class ToggleSwitch(QCheckBox):
    """
    A custom, theme-aware toggle switch widget.
    Inherits from QCheckBox so it can be used anywhere a checkbox is expected.
    """
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setFixedSize(50, 28)
        self.setCursor(Qt.CursorShape.PointingHandCursor)

        # Animation for the knob position
        self._knob_position = 0
        self._padding = 3
        self.animation = QPropertyAnimation(self, b"knob_position", self)
        self.animation.setEasingCurve(QEasingCurve.Type.InOutCubic)
        self.animation.setDuration(150)

        # FIX: use 'toggled' signal and set initial position without animating
        self.toggled.connect(self.animate)
        radius = (self.height() - 2 * self._padding) // 2
        max_pos = max(0, self.width() - 2 * (radius + self._padding))
        self._knob_position = max_pos if self.isChecked() else 0

    @pyqtProperty(int)
    def knob_position(self):
        return self._knob_position

    @knob_position.setter
    def knob_position(self, value):
        self._knob_position = int(value)
        self.update()

    def sizeHint(self):
        return QSize(50, 28)

    def animate(self, checked: bool):
        """Animate the knob to the new position when toggled."""
        radius = (self.height() - 2 * self._padding) // 2
        max_pos = max(0, self.width() - 2 * (radius + self._padding))
        self.animation.stop()
        self.animation.setStartValue(self.knob_position)
        self.animation.setEndValue(max_pos if checked else 0)
        self.animation.start()

    def mousePressEvent(self, event):
        """Override to toggle immediately on any click within the widget bounds."""
        if event.button() == Qt.MouseButton.LeftButton:
            self.toggle()
            event.accept()
        else:
            super().mousePressEvent(event)

    def mouseReleaseEvent(self, event):
        """Override to prevent double-toggling from default behavior."""
        event.accept()

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)

        # Track
        radius = (self.height() - 2 * self._padding) // 2
        track_rect = QRectF(self._padding, self._padding, self.width() - 2 * self._padding, 2 * radius)
        on_color = QColor(76, 175, 80)  # green
        off_color = QColor(150, 150, 150)
        painter.setPen(Qt.PenStyle.NoPen)
        painter.setBrush(on_color if self.isChecked() else off_color)
        painter.drawRoundedRect(track_rect, radius, radius)

        # Knob
        max_pos = max(0, self.width() - 2 * (radius + self._padding))
        knob_x = self._knob_position + self._padding + radius
        knob_center = QPoint(int(knob_x), int(self._padding + radius))
        painter.setBrush(QColor(255, 255, 255))
        painter.drawEllipse(knob_center, radius, radius)

class AvailableRxNumbersDialog(QDialog):
    """Dialog to display deleted RX numbers (available for reuse), with optional selection mode."""
    def __init__(self, parent=None, select_mode: bool = False):
        super().__init__(parent)
        self.parent = parent
        self.select_mode = select_mode
        self.setWindowTitle("Available RX Numbers")
        self.setWindowFlags(self.windowFlags() | Qt.WindowType.WindowMinMaxButtonsHint)
        self.resize(520, 420)
        self._setup_ui()
        self._load_data()

    def _setup_ui(self):
        layout = QVBoxLayout(self)
        header = QLabel("These RX numbers are available for reuse (deleted or auto-detected gaps).")
        layout.addWidget(header)

        self.table = QTableWidget()
        self.table.setColumnCount(3)
        self.table.setHorizontalHeaderLabels(["RX #", "Deleted On", "Note"])
        self.table.horizontalHeader().setSectionResizeMode(0, QHeaderView.ResizeMode.ResizeToContents)
        self.table.horizontalHeader().setSectionResizeMode(1, QHeaderView.ResizeMode.ResizeToContents)
        self.table.horizontalHeader().setSectionResizeMode(2, QHeaderView.ResizeMode.Stretch)
        layout.addWidget(self.table)

        btns = QHBoxLayout()
        export_btn = QPushButton("Export CSV")
        export_btn.clicked.connect(self._export_csv)
        btns.addWidget(export_btn)

        btns.addStretch(1)

        if self.select_mode:
            use_btn = QPushButton("Use Selected")
            use_btn.clicked.connect(lambda: self.accept() if self.get_selected_rx_no() else None)
            btns.addWidget(use_btn)

            # Allow manual entry when the list is empty or when you know the number
            manual_btn = QPushButton("Manual Entry…")
            def _manual_entry():
                try:
                    from PyQt6.QtWidgets import QInputDialog
                    rx_val, ok = QInputDialog.getInt(self, "Enter RX #", "RX Number:", min=1, value=0)
                    if not ok:
                        return
                    # Validate via parent if available
                    if hasattr(self.parent, 'is_rx_available_for_reuse'):
                        if not self.parent.is_rx_available_for_reuse(rx_val):
                            QMessageBox.warning(self, "RX Not Available", f"RX #{rx_val} is already used or reserved.")
                            return
                    # Stash and accept
                    self._manual_rx = int(rx_val)
                    self.accept()
                except Exception as e:
                    QMessageBox.critical(self, "Manual Entry", f"Failed: {e}")
            manual_btn.clicked.connect(_manual_entry)
            btns.addWidget(manual_btn)

        close_btn = QPushButton("Close")
        close_btn.clicked.connect(self.reject)
        btns.addWidget(close_btn)

        layout.addLayout(btns)

    def _load_data(self):
        rows = []
        try:
            if hasattr(self.parent, 'get_deleted_rx_numbers'):
                rows = self.parent.get_deleted_rx_numbers()
        except Exception:
            rows = []
        self.table.setRowCount(len(rows))
        for i, (rx_no, created_at, note) in enumerate(rows):
            self.table.setItem(i, 0, QTableWidgetItem(str(rx_no)))
            self.table.setItem(i, 1, QTableWidgetItem(str(created_at or '')))
            self.table.setItem(i, 2, QTableWidgetItem(str(note or '')))

    def get_selected_rx_no(self) -> int | None:
        # If manual entry was used, return that first
        if hasattr(self, '_manual_rx') and self._manual_rx:
            try:
                return int(self._manual_rx)
            except Exception:
                pass
        row = self.table.currentRow()
        if row < 0:
            return None
        item = self.table.item(row, 0)
        if not item:
            return None
        try:
            return int(item.text())
        except Exception:
            return None

    def _export_csv(self):
        try:
            path, _ = QFileDialog.getSaveFileName(self, "Export Available RX Numbers", "available_rx_numbers.csv", "CSV Files (*.csv)")
            if not path:
                return
            headers = ["rx_no", "deleted_on", "note"]
            with open(path, "w", newline="", encoding="utf-8") as fp:
                w = csv.writer(fp)
                w.writerow(headers)
                for r in range(self.table.rowCount()):
                    w.writerow([
                        self.table.item(r, 0).text() if self.table.item(r, 0) else "",
                        self.table.item(r, 1).text() if self.table.item(r, 1) else "",
                        self.table.item(r, 2).text() if self.table.item(r, 2) else "",
                    ])
            QMessageBox.information(self, "Export", f"Exported {self.table.rowCount()} RX numbers to:\n{path}")
        except Exception as e:
            QMessageBox.critical(self, "Export", f"Failed to export: {e}")

    

