class DeletedOrdersLogDialog(QDialog):
    """Dialog to display all deleted orders with full details."""
    def __init__(self, parent=None):
        super().__init__(parent)
        self.parent = parent
        self.setWindowTitle("Deleted Orders Log")
        self.setWindowFlags(self.windowFlags() | Qt.WindowType.WindowMinMaxButtonsHint)
        self.resize(1200, 600)
        self._setup_ui()
        self._load_data()

    def _setup_ui(self):
        layout = QVBoxLayout(self)
        
        header = QLabel("Complete log of all deleted orders (for audit trail and recovery)")
        header.setStyleSheet("font-weight: bold; font-size: 12pt; padding: 10px;")
        layout.addWidget(header)

        # Main table for deleted orders
        self.table = QTableWidget()
        self.table.setColumnCount(12)
        self.table.setHorizontalHeaderLabels([
            "Order ID", "Rx Date", "Order Date", "Patient Name", "DOB",
            "Prescriber", "Insurance", "Status", "Deleted Date", "Deleted By", 
            "Items", "View Details"
        ])
        self.table.horizontalHeader().setSectionResizeMode(QHeaderView.ResizeMode.ResizeToContents)
        self.table.horizontalHeader().setSectionResizeMode(3, QHeaderView.ResizeMode.Stretch)
        self.table.setSelectionBehavior(QTableWidget.SelectionBehavior.SelectRows)
        self.table.setEditTriggers(QTableWidget.EditTrigger.NoEditTriggers)
        layout.addWidget(self.table)

        # Buttons
        btns = QHBoxLayout()
        
        export_btn = QPushButton("📄 Export CSV")
        export_btn.clicked.connect(self._export_csv)
        btns.addWidget(export_btn)
        
        btns.addStretch(1)
        
        close_btn = QPushButton("Close")
        close_btn.clicked.connect(self.reject)
        btns.addWidget(close_btn)
        
        layout.addLayout(btns)

    def _load_data(self):
        """Load deleted orders from database."""
        rows = []
        try:
            if not hasattr(self.parent, 'orders_db_path'):
                return
            
            conn = sqlite3.connect(self.parent.orders_db_path)
            cursor = conn.cursor()
            
            cursor.execute("""
                SELECT id, original_order_id, rx_date, order_date, 
                       patient_last_name, patient_first_name, patient_dob,
                       prescriber_name, primary_insurance, order_status,
                       deleted_date, deleted_by
                FROM deleted_orders
                ORDER BY deleted_date DESC
            """)
            rows = cursor.fetchall()
            conn.close()
            
        except Exception as e:
            print(f"Error loading deleted orders: {e}")
            QMessageBox.warning(self, "Error", f"Failed to load deleted orders: {e}")
            return
        
        self.table.setRowCount(len(rows))
        for i, row in enumerate(rows):
            (deleted_id, orig_order_id, rx_date, order_date, last_name, first_name,
             dob, prescriber, insurance, status, deleted_date, deleted_by) = row
            
            # Order ID
            self.table.setItem(i, 0, QTableWidgetItem(f"ORD-{orig_order_id:03d}"))
            
            # Dates
            self.table.setItem(i, 1, QTableWidgetItem(str(rx_date or '')))
            self.table.setItem(i, 2, QTableWidgetItem(str(order_date or '')))
            
            # Patient name
            patient_name = f"{last_name or ''}, {first_name or ''}".strip(', ')
            patient_item = QTableWidgetItem(patient_name)
            font = patient_item.font()
            font.setBold(True)
            patient_item.setFont(font)
            self.table.setItem(i, 3, patient_item)
            self.table.setItem(i, 4, QTableWidgetItem(str(dob or '')))
            
            # Prescriber and insurance
            self.table.setItem(i, 5, QTableWidgetItem(str(prescriber or '')))
            self.table.setItem(i, 6, QTableWidgetItem(str(insurance or '')))
            self.table.setItem(i, 7, QTableWidgetItem(str(status or '')))
            
            # Deletion info
            self.table.setItem(i, 8, QTableWidgetItem(str(deleted_date or '')))
            self.table.setItem(i, 9, QTableWidgetItem(str(deleted_by or 'Unknown')))
            
            # Count items for this deleted order
            try:
                conn = sqlite3.connect(self.parent.orders_db_path)
                cursor = conn.cursor()
                cursor.execute("SELECT COUNT(*) FROM deleted_order_items WHERE deleted_order_id = ?", (deleted_id,))
                item_count = cursor.fetchone()[0]
                conn.close()
                self.table.setItem(i, 10, QTableWidgetItem(str(item_count)))
            except:
                self.table.setItem(i, 10, QTableWidgetItem("0"))
            
            # View Details button
            details_btn = QPushButton("📋 View")
            details_btn.setProperty('deleted_order_id', deleted_id)
            details_btn.clicked.connect(lambda checked, did=deleted_id: self._show_order_details(did))
            self.table.setCellWidget(i, 11, details_btn)

    def _show_order_details(self, deleted_order_id):
        """Show detailed view of a deleted order including all items."""
        try:
            conn = sqlite3.connect(self.parent.orders_db_path)
            cursor = conn.cursor()
            
            # Get order header
            cursor.execute("""
                SELECT original_order_id, rx_date, order_date, 
                       patient_last_name, patient_first_name, patient_dob,
                       patient_address, patient_phone,
                       prescriber_name, prescriber_npi,
                       primary_insurance, primary_insurance_id,
                       order_status, notes, doctor_directions,
                       deleted_date, deleted_by
                FROM deleted_orders WHERE id = ?
            """, (deleted_order_id,))
            order = cursor.fetchone()
            
            if not order:
                QMessageBox.warning(self, "Not Found", "Deleted order not found.")
                conn.close()
                return
            
            # Get order items
            cursor.execute("""
                SELECT rx_no, hcpcs_code, description, item_number,
                       refills, day_supply, qty, cost_ea, total, pa_number, directions
                FROM deleted_order_items WHERE deleted_order_id = ?
            """, (deleted_order_id,))
            items = cursor.fetchall()
            conn.close()
            
            # Build detail message
            (orig_id, rx_date, order_date, last_name, first_name, dob, address, phone,
             prescriber, npi, insurance, ins_id, status, notes, directions,
             deleted_date, deleted_by) = order
            
            details = f"""DELETED ORDER DETAILS
            
Order ID: ORD-{orig_id:03d}
Rx Date: {rx_date or 'N/A'}
Order Date: {order_date or 'N/A'}
Status: {status or 'N/A'}

PATIENT INFORMATION:
Name: {last_name or ''}, {first_name or ''}
DOB: {dob or 'N/A'}
Address: {address or 'N/A'}
Phone: {phone or 'N/A'}

PRESCRIBER:
Name: {prescriber or 'N/A'}
NPI: {npi or 'N/A'}

INSURANCE:
Primary: {insurance or 'N/A'}
Insurance ID: {ins_id or 'N/A'}

DOCTOR'S DIRECTIONS:
{directions or 'None'}

NOTES:
{notes or 'None'}

ORDER ITEMS ({len(items)} items):
"""
            for idx, item in enumerate(items, 1):
                rx_no, hcpcs, desc, item_num, refills, day_supply, qty, cost_ea, total, pa, item_dir = item
                details += f"\n{idx}. RX #{rx_no or 'N/A'} - {desc or 'N/A'}"
                details += f"\n   HCPCS: {hcpcs or 'N/A'} | Item#: {item_num or 'N/A'}"
                details += f"\n   Refills: {refills or '0'} | Day Supply: {day_supply or 'N/A'}"
                details += f"\n   Qty: {qty or 'N/A'} | Cost: ${cost_ea or '0.00'} | Total: ${total or '0.00'}"
                if pa:
                    details += f"\n   PA#: {pa}"
                if item_dir:
                    details += f"\n   Directions: {item_dir}"
                details += "\n"
            
            details += f"""
DELETION INFORMATION:
Deleted Date: {deleted_date or 'N/A'}
Deleted By: {deleted_by or 'Unknown'}
"""
            
            # Show in dialog
            msg = QMessageBox(self)
            msg.setWindowTitle(f"Deleted Order ORD-{orig_id:03d}")
            msg.setText(details)
            msg.setIcon(QMessageBox.Icon.Information)
            msg.setStandardButtons(QMessageBox.StandardButton.Ok)
            msg.setTextInteractionFlags(Qt.TextInteractionFlag.TextSelectableByMouse)
            msg.exec()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load order details: {e}")

    def _export_csv(self):
        """Export deleted orders to CSV."""
        try:
            path, _ = QFileDialog.getSaveFileName(self, "Export Deleted Orders", "deleted_orders.csv", "CSV Files (*.csv)")
            if not path:
                return
            
            conn = sqlite3.connect(self.parent.orders_db_path)
            cursor = conn.cursor()
            
            # Get all deleted orders with items
            cursor.execute("""
                SELECT d.original_order_id, d.rx_date, d.order_date,
                       d.patient_last_name, d.patient_first_name, d.patient_dob,
                       d.prescriber_name, d.primary_insurance, d.order_status,
                       d.deleted_date, d.deleted_by, d.notes,
                       GROUP_CONCAT(i.description, ' | ') as items
                FROM deleted_orders d
                LEFT JOIN deleted_order_items i ON d.id = i.deleted_order_id
                GROUP BY d.id
                ORDER BY d.deleted_date DESC
            """)
            rows = cursor.fetchall()
            conn.close()
            
            headers = ["Order_ID", "Rx_Date", "Order_Date", "Patient_Last", "Patient_First", 
                      "DOB", "Prescriber", "Insurance", "Status", "Deleted_Date", "Deleted_By", 
                      "Notes", "Items"]
            
            with open(path, "w", newline="", encoding="utf-8") as fp:
                w = csv.writer(fp)
                w.writerow(headers)
                for row in rows:
                    w.writerow([str(r or '') for r in row])
            
            QMessageBox.information(self, "Export", f"Exported {len(rows)} deleted orders to:\n{path}")
            
        except Exception as e:
            QMessageBox.critical(self, "Export", f"Failed to export: {e}")


class BackupWorker(QObject):
    """Worker object to handle backup and restore in a thread."""
    progress = pyqtSignal(int)
    finished = pyqtSignal(str)
    error = pyqtSignal(str)

    def __init__(self, mode: str, source_path: str = None, backup_path: str = None):
        super().__init__()
        self.mode = mode
        self.source_path = source_path
        self.backup_path = backup_path

    def run(self):
        try:
            if self.mode == "backup":
                path = self.create_backup()
                self.finished.emit(path)
            elif self.mode == "restore":
                self.restore_backup()
            else:
                self.error.emit(f"[unknown] Unknown mode: {self.mode}")
        except Exception as e:
            # Include the mode in the error for clearer UI messaging
            try:
                self.error.emit(f"[{self.mode}] {e}")
            except Exception:
                self.error.emit(str(e))

    def create_backup(self) -> str:
        """Create a backup zip that includes settings.json and all known DBs.

        Databases are discovered from both the current source_path (fax folder)
        and the centralized settings['db_folder'] if available. The largest
        existing copy is included for each DB name.
        """
        if not self.source_path:
            raise ValueError("Source path not set for backup")
        os.makedirs(BACKUP_FOLDER, exist_ok=True)
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_path = os.path.join(BACKUP_FOLDER, f"dmesolutions_backup_{timestamp}.zip")

        # Load db_folder from settings if present
        db_folder = None
        try:
            if os.path.exists(SETTINGS_FILE):
                with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                    s = json.load(f)
                    db_folder = s.get('db_folder')
        except Exception:
            db_folder = None

        # Build search paths
        search_paths = []
        try:
            app_root = os.path.dirname(os.path.abspath(__file__))
            search_paths.append(app_root)
        except Exception:
            pass
        if self.source_path:
            search_paths.append(self.source_path)
        if db_folder and isinstance(db_folder, str) and db_folder.strip():
            search_paths.append(db_folder)

        # DB names to include (support legacy insurance.db and current insurance_names.db)
        db_names = [
            "patients.db",
            "orders.db",
            "prescribers.db",
            "inventory.db",
            "billing.db",
            "suppliers.db",
            "insurance_names.db",
            "insurance.db",
            "document_data.db",
        ]

        def find_best(existing_name: str) -> str | None:
            candidates = []
            for base in search_paths:
                try:
                    p = os.path.join(base, existing_name)
                    if os.path.exists(p):
                        candidates.append((p, os.path.getsize(p)))
                except Exception:
                    pass
            if not candidates:
                return None
            candidates.sort(key=lambda t: t[1], reverse=True)
            return candidates[0][0]

        self.progress.emit(5)
        with zipfile.ZipFile(backup_path, 'w', compression=zipfile.ZIP_DEFLATED) as zipf:
            # Include settings file if present
            if os.path.exists(SETTINGS_FILE):
                zipf.write(SETTINGS_FILE, SETTINGS_FILE)
            self.progress.emit(10)

            # Include databases under a subfolder
            progress_step = 85 // max(len(db_names), 1)
            current_progress = 10
            included = set()
            for name in db_names:
                # Avoid including both insurance_names.db and insurance.db if they are the same file
                best = find_best(name)
                if not best:
                    current_progress += progress_step
                    self.progress.emit(min(current_progress, 95))
                    continue
                # Use the base filename as archive name to normalize
                arcname = f"databases/{os.path.basename(best)}"
                # Prevent duplicate archive entries if both names resolve to the same path
                if arcname.lower() in included:
                    current_progress += progress_step
                    self.progress.emit(min(current_progress, 95))
                    continue
                zipf.write(best, arcname)
                included.add(arcname.lower())
                current_progress += progress_step
                self.progress.emit(min(current_progress, 95))

            # Include Fee Schedule Excel if configured/found
            try:
                fee_path = None
                try:
                    if os.path.exists(SETTINGS_FILE):
                        with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                            s = json.load(f)
                            fee_path = s.get('fee_schedule_path')
                except Exception:
                    fee_path = None
                # If none explicitly set, search common locations for a likely match
                if not fee_path:
                    pats = ["MEDICAID_FEE_SCHED_*.xlsx", "DME_Fee_Schedule*.xlsx"]
                    bases = list(search_paths)
                    # De-dup
                    seen = set()
                    for b in bases:
                        if not b or b in seen:
                            continue
                        seen.add(b)
                        for pat in pats:
                            for p in glob.glob(os.path.join(b, pat)):
                                fee_path = p
                                break
                        if fee_path:
                            break
                if fee_path and os.path.exists(fee_path):
                    arcname = f"extras/fee_schedule/{os.path.basename(fee_path)}"
                    zipf.write(fee_path, arcname)
            except Exception:
                pass

        self.progress.emit(100)
        return backup_path

    def restore_backup(self):
        """Restore settings and databases.

        Databases are restored into settings['db_folder'] when available; otherwise
        fall back to source_path. This makes restores consistent with centralized DB usage.
        """
        if not self.backup_path:
            raise ValueError("Backup path not set for restore")
        with zipfile.ZipFile(self.backup_path, 'r') as zipf:
            # Extract to a user-writable temporary location first
            try:
                import tempfile
                # Prefer system temp; fall back to BACKUP_FOLDER
                base_tmp = tempfile.gettempdir()
                if not os.access(base_tmp, os.W_OK):
                    base_tmp = BACKUP_FOLDER
                temp_dir = tempfile.mkdtemp(prefix="DmeSolutionsV1_restore_", dir=base_tmp)
            except Exception:
                # Last resort: BACKUP_FOLDER/temp_restore_<timestamp>
                try:
                    os.makedirs(BACKUP_FOLDER, exist_ok=True)
                except Exception:
                    pass
                try:
                    import time as _time
                    suffix = int(_time.time())
                except Exception:
                    suffix = 0
                temp_dir = os.path.join(BACKUP_FOLDER, f"temp_restore_{suffix}")
                os.makedirs(temp_dir, exist_ok=True)
            zipf.extractall(temp_dir)
            self.progress.emit(30)

            # Move settings file to correct location first
            if os.path.exists(os.path.join(temp_dir, SETTINGS_FILE)):
                shutil.copy2(os.path.join(temp_dir, SETTINGS_FILE), SETTINGS_FILE)
            self.progress.emit(40)

            # Determine destination folder for DBs
            dest_db_folder = None
            try:
                if os.path.exists(SETTINGS_FILE):
                    with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                        s = json.load(f)
                        dest_db_folder = s.get('db_folder')
            except Exception:
                dest_db_folder = None
            if not dest_db_folder:
                try:
                    dest_db_folder = _default_db_folder()
                except Exception:
                    dest_db_folder = None
            # Fallback to source_path
            if not dest_db_folder:
                dest_db_folder = self.source_path
            try:
                if dest_db_folder:
                    os.makedirs(dest_db_folder, exist_ok=True)
            except Exception:
                pass

            # Restore database files from databases folder
            databases_dir = os.path.join(temp_dir, "databases")
            if os.path.exists(databases_dir) and dest_db_folder:
                db_files = [f for f in os.listdir(databases_dir) if f.endswith('.db')]
                progress_step = 50 // max(len(db_files), 1)
                current_progress = 45

                for db_file in db_files:
                    src = os.path.join(databases_dir, db_file)
                    # Preserve filename, restore into dest_db_folder
                    dst = os.path.join(dest_db_folder, db_file)
                    shutil.copy2(src, dst)
                    current_progress += progress_step
                    self.progress.emit(min(current_progress, 95))

            # Restore Fee Schedule Excel if present
            try:
                extras_dir = os.path.join(temp_dir, "extras", "fee_schedule")
                if os.path.exists(extras_dir) and dest_db_folder:
                    xlsx_files = [f for f in os.listdir(extras_dir) if f.lower().endswith('.xlsx')]
                    if xlsx_files:
                        # Choose the newest file
                        xlsx_files.sort(key=lambda f: os.path.getmtime(os.path.join(extras_dir, f)), reverse=True)
                        src = os.path.join(extras_dir, xlsx_files[0])
                        dst = os.path.join(dest_db_folder, os.path.basename(src))
                        shutil.copy2(src, dst)
                        # Update settings with restored path
                        try:
                            if os.path.exists(SETTINGS_FILE):
                                with open(SETTINGS_FILE, 'r', encoding='utf-8') as f:
                                    s = json.load(f)
                            else:
                                s = {}
                            s['fee_schedule_path'] = dst
                            with open(SETTINGS_FILE, 'w', encoding='utf-8') as f:
                                json.dump(s, f, indent=2)
                        except Exception:
                            pass
            except Exception:
                pass

            # Clean up temp directory
            try:
                shutil.rmtree(temp_dir, ignore_errors=True)
            except Exception:
                pass
            self.progress.emit(100)
        self.finished.emit(f"Backup restored successfully\nTemp path used: {temp_dir}")

class AutoBackupScheduler(QThread):
    """Thread to handle automatic backup scheduling."""
    backup_triggered = pyqtSignal()
    
    def __init__(self, frequency="Daily"):
        super().__init__()
        self.frequency = frequency
        self.running = True
        
    def run(self):
        """Main scheduler loop."""
        while self.running:
            current_time = QDateTime.currentDateTime()
            
            if self.frequency == "Daily":
                # Check if it's 12:00 AM (midnight)
                if current_time.time().hour() == 0 and current_time.time().minute() == 0:
                    self.backup_triggered.emit()
                    # Sleep for 61 seconds to avoid triggering multiple times in the same minute
                    self.msleep(61000)
                else:
                    # Check every minute
                    self.msleep(60000)
            elif self.frequency == "Weekly":
                # Backup every Sunday at midnight
                if current_time.date().dayOfWeek() == 7 and current_time.time().hour() == 0 and current_time.time().minute() == 0:
                    self.backup_triggered.emit()
                    self.msleep(61000)
                else:
                    self.msleep(60000)
            elif self.frequency == "Monthly":
                # Backup on the 1st of each month at midnight
                if current_time.date().day() == 1 and current_time.time().hour() == 0 and current_time.time().minute() == 0:
                    self.backup_triggered.emit()
                    self.msleep(61000)
                else:
                    self.msleep(60000)
    
    def stop(self):
        """Stop the scheduler."""
        self.running = False
        self.quit()
        self.wait()


class WhiteCheckboxDelegate(QStyledItemDelegate):
    """Custom delegate to render high-contrast checkbox cells in tables.

    Draws a clean checkbox (white box with blue fill + checkmark when checked),
    centered in the cell.  Handles clicks/keys to toggle.
    """

    def __init__(self, parent=None, target_columns=None, is_dark_theme=True):
        super().__init__(parent)
        self.target_columns = target_columns  # Set of column indices to apply to, or None for all
        self.is_dark_theme = is_dark_theme

    def set_theme(self, is_dark_theme: bool):
        self.is_dark_theme = bool(is_dark_theme)
        try:
            view = self.parent()
            if hasattr(view, 'viewport'):
                view.viewport().update()
        except Exception:
            pass

    def paint(self, painter, option, index):
        # Only apply to target columns if specified
        if self.target_columns is not None and index.column() not in self.target_columns:
            super().paint(painter, option, index)
            return

        if index.data(Qt.ItemDataRole.CheckStateRole) is None:
            super().paint(painter, option, index)
            return

        painter.save()
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)

        from PyQt6.QtGui import QColor, QPen

        checked = index.data(Qt.ItemDataRole.CheckStateRole) == Qt.CheckState.Checked

        # Checkbox geometry — 18×18 box centered in the cell
        box_size = 18
        rect = option.rect
        x = rect.x() + (rect.width() - box_size) // 2
        y = rect.y() + (rect.height() - box_size) // 2
        box_rect = QRectF(x, y, box_size, box_size)

        if checked:
            # Filled blue box
            painter.setPen(QPen(QColor('#0078D4'), 2))
            painter.setBrush(QColor('#0078D4'))
            painter.drawRoundedRect(box_rect, 3, 3)
            # White checkmark
            painter.setPen(QPen(QColor('#FFFFFF'), 2.5, Qt.PenStyle.SolidLine, Qt.PenCapStyle.RoundCap, Qt.PenJoinStyle.RoundJoin))
            painter.setBrush(Qt.BrushStyle.NoBrush)
            cx, cy = x + 4, y + box_size / 2
            from PyQt6.QtGui import QPainterPath
            path = QPainterPath()
            path.moveTo(x + 4, y + box_size * 0.5)
            path.lineTo(x + box_size * 0.38, y + box_size * 0.72)
            path.lineTo(x + box_size - 4, y + box_size * 0.28)
            painter.drawPath(path)
        else:
            # Empty white box with border
            border_color = QColor('#555555') if self.is_dark_theme else QColor('#999999')
            painter.setPen(QPen(border_color, 2))
            painter.setBrush(QColor('#FFFFFF'))
            painter.drawRoundedRect(box_rect, 3, 3)

        painter.restore()

    def editorEvent(self, event, model, option, index):
        """Explicitly handle clicks/spacebar to toggle checkboxes."""
        # Respect target columns if provided
        if self.target_columns is not None and index.column() not in self.target_columns:
            return super().editorEvent(event, model, option, index)

        # Only handle items that actually have a checkbox
        if index.data(Qt.ItemDataRole.CheckStateRole) is None:
            return super().editorEvent(event, model, option, index)

        from PyQt6.QtCore import QEvent
        etype = event.type()

        is_toggle = False
        if etype in (QEvent.Type.MouseButtonRelease, QEvent.Type.MouseButtonDblClick):
            is_toggle = True
        elif etype == QEvent.Type.KeyPress:
            key = event.key()
            if key in (Qt.Key.Key_Space, Qt.Key.Key_Return, Qt.Key.Key_Enter):
                is_toggle = True

        if is_toggle:
            current = index.data(Qt.ItemDataRole.CheckStateRole)
            new_state = Qt.CheckState.Checked if current != Qt.CheckState.Checked else Qt.CheckState.Unchecked
            changed = model.setData(index, new_state, Qt.ItemDataRole.CheckStateRole)
            return bool(changed)

        return super().editorEvent(event, model, option, index)


class YesNoDelegate(QStyledItemDelegate):
    """Delegate that shows a Yes/No combo for a cell and writes back the text.

    Useful for boolean fields when we prefer explicit words instead of a checkbox.
    """
    def createEditor(self, parent, option, index):
        cb = QComboBox(parent)
        cb.addItems(["No", "Yes"])
        return cb

    def setEditorData(self, editor, index):
        val = index.data(Qt.ItemDataRole.DisplayRole) or "No"
        idx = 1 if str(val).strip().lower() in ("yes", "1", "true") else 0
        editor.setCurrentIndex(idx)

    def setModelData(self, editor, model, index):
        text = "Yes" if editor.currentIndex() == 1 else "No"
        model.setData(index, text, Qt.ItemDataRole.DisplayRole)


class ColorPreservingDelegate(QStyledItemDelegate):
    """Delegate that paints text with the item's ForegroundRole color,
    ignoring the QSS stylesheet color so programmatic setForeground() works."""

    def paint(self, painter, option, index):
        # Let the base draw the background / selection highlight
        self.initStyleOption(option, index)
        style = option.widget.style() if option.widget else QApplication.style()

        # Draw background only (no text yet)
        painter.save()
        style.drawPrimitive(style.PrimitiveElement.PE_PanelItemViewItem, option, painter, option.widget)

        # Determine text color: honour ForegroundRole if set, else fall back to palette
        fg = index.data(Qt.ItemDataRole.ForegroundRole)
        if fg and isinstance(fg, QBrush):
            painter.setPen(fg.color())
        elif fg and isinstance(fg, QColor):
            painter.setPen(fg)
        elif option.state & style.StateFlag.State_Selected:
            painter.setPen(option.palette.color(QPalette.ColorRole.HighlightedText))
        else:
            painter.setPen(option.palette.color(QPalette.ColorRole.Text))

        # Honour the item's font (bold / italic)
        font_data = index.data(Qt.ItemDataRole.FontRole)
        if font_data and isinstance(font_data, QFont):
            painter.setFont(font_data)
        else:
            painter.setFont(option.font)

        text = index.data(Qt.ItemDataRole.DisplayRole) or ""
        text_rect = option.rect.adjusted(10, 0, -4, 0)  # match padding
        painter.drawText(text_rect, Qt.AlignmentFlag.AlignCenter | Qt.AlignmentFlag.AlignVCenter, str(text))
        painter.restore()

class QuickDeliveryTicketDialog(QDialog):
    """Simple, fillable Delivery Ticket generator without creating an order.

    Allows entry of patient info and line items, then generates a PDF to sign.
    """
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("Quick Delivery Ticket")
        self.setWindowFlags(self.windowFlags() | Qt.WindowType.WindowMinMaxButtonsHint)
        self.setModal(False)  # Non-modal so user can work on main window
        self.resize(900, 700)
        self.parent = parent
        self._inventory_index = {}  # Store inventory items
        self._build_ui()
        self.load_inventory()  # Load inventory after UI is built

    def _build_ui(self):
        from PyQt6.QtWidgets import QDateEdit
        layout = QVBoxLayout(self)

        # Header
        header = QLabel("Fillable Delivery Ticket (no order)")
        header.setStyleSheet("font-size:16px; font-weight:600;")
        layout.addWidget(header)

        # Patient info grid
        grid = QGridLayout()
        r = 0
        grid.addWidget(QLabel("Date:"), r, 0)
        self.ticket_date = QDateEdit()
        self.ticket_date.setDisplayFormat("MM/dd/yyyy")
        self.ticket_date.setCalendarPopup(True)
        self.ticket_date.setDate(QDate.currentDate())
        grid.addWidget(self.ticket_date, r, 1)

        grid.addWidget(QLabel("Patient Last Name:"), r, 2)
        self.pt_last = QLineEdit(); grid.addWidget(self.pt_last, r, 3)
        r += 1

        grid.addWidget(QLabel("Patient First Name:"), r, 0)
        self.pt_first = QLineEdit(); grid.addWidget(self.pt_first, r, 1)

        grid.addWidget(QLabel("DOB:"), r, 2)
        self.pt_dob = QLineEdit(); self.pt_dob.setPlaceholderText("MM/DD/YYYY")
        grid.addWidget(self.pt_dob, r, 3)
        r += 1

        grid.addWidget(QLabel("Phone:"), r, 0)
        self.pt_phone = QLineEdit(); grid.addWidget(self.pt_phone, r, 1)

        grid.addWidget(QLabel("Address:"), r, 2)
        self.pt_address = QLineEdit(); grid.addWidget(self.pt_address, r, 3)
        r += 1

        # Prescriber info
        grid.addWidget(QLabel("Prescriber:"), r, 0)
        self.pr_name = QLineEdit(); grid.addWidget(self.pr_name, r, 1)
        grid.addWidget(QLabel("Prescriber Phone:"), r, 2)
        self.pr_phone = QLineEdit(); grid.addWidget(self.pr_phone, r, 3)
        r += 1
        layout.addLayout(grid)

        # Items
        items_box = QGroupBox("Items")
        items_layout = QVBoxLayout(items_box)
        
        # Add inventory selection controls
        inv_controls = QHBoxLayout()
        inv_controls.addWidget(QLabel("Select Item:"))
        self.item_combo = QComboBox()
        self.item_combo.setEditable(True)
        self.item_combo.setInsertPolicy(QComboBox.InsertPolicy.NoInsert)
        self.item_combo.setMinimumWidth(400)
        inv_controls.addWidget(self.item_combo, 1)
        
        add_from_inv_btn = QPushButton("➕ Add Item")
        add_from_inv_btn.setToolTip("Add selected inventory item to table")
        add_from_inv_btn.clicked.connect(self.add_item_from_inventory)
        inv_controls.addWidget(add_from_inv_btn)
        
        add_to_inv_btn = QPushButton("📦 Add to Inventory")
        add_to_inv_btn.setToolTip("Add new item to inventory database")
        add_to_inv_btn.clicked.connect(self.add_to_inventory)
        inv_controls.addWidget(add_to_inv_btn)
        
        items_layout.addLayout(inv_controls)
        
        self.ticket_items = QTableWidget(0, 4)
        self.ticket_items.setHorizontalHeaderLabels(["HCPCS", "Description", "Qty", "Directions"])
        hdr = self.ticket_items.horizontalHeader()
        hdr.setSectionResizeMode(0, QHeaderView.ResizeMode.ResizeToContents)
        hdr.setSectionResizeMode(1, QHeaderView.ResizeMode.Stretch)
        hdr.setSectionResizeMode(2, QHeaderView.ResizeMode.ResizeToContents)
        hdr.setSectionResizeMode(3, QHeaderView.ResizeMode.Stretch)
        items_layout.addWidget(self.ticket_items)
        row_btns = QHBoxLayout()
        add_row = QPushButton("➕ Add Empty Row"); add_row.clicked.connect(self.add_ticket_row)
        del_row = QPushButton("🗑️ Remove Row"); del_row.clicked.connect(self.del_ticket_row)
        row_btns.addWidget(add_row); row_btns.addWidget(del_row); row_btns.addStretch()
        items_layout.addLayout(row_btns)
        layout.addWidget(items_box)

        # Notes + signature hint
        self.ticket_notes = QTextEdit(); self.ticket_notes.setPlaceholderText("Notes / special instructions…")
        layout.addWidget(self.ticket_notes)

        # Actions
        actions = QHBoxLayout()
        actions.addStretch()
        self.btn_cancel = QPushButton("Cancel"); self.btn_cancel.clicked.connect(self.reject)
        self.btn_save = QPushButton("🖨️ Generate PDF…"); self.btn_save.setDefault(True)
        self.btn_save.clicked.connect(self.generate_ticket_pdf)
        actions.addWidget(self.btn_cancel); actions.addWidget(self.btn_save)
        layout.addLayout(actions)

        # Start with one row
        self.add_ticket_row()

    def add_ticket_row(self):
        r = self.ticket_items.rowCount()
        self.ticket_items.insertRow(r)
        for c in range(4):
            self.ticket_items.setItem(r, c, QTableWidgetItem(""))

    def del_ticket_row(self):
        r = self.ticket_items.currentRow()
        if r >= 0:
            self.ticket_items.removeRow(r)

    def load_inventory(self):
        """Load inventory items into dropdown."""
        try:
            self.item_combo.clear()
            self._inventory_index.clear()
            
            if not hasattr(self.parent, 'inventory_database_file') or not self.parent.inventory_database_file:
                return
                
            from dmelogic.db.inventory import fetch_all_inventory
            rows = fetch_all_inventory()
            
            for row in rows:
                try:
                    item_id = row['item_id']
                    item_number = row['item_number'] if row['item_number'] else ''
                    hcpcs = row['hcpcs_code'] if row['hcpcs_code'] else ''
                    description = row['description'] if row['description'] else ''
                    price = row['retail_price'] if row['retail_price'] else 0
                except (KeyError, IndexError):
                    continue
                    
                # Display format: #ITEM_NUMBER | HCPCS | Description (or item_id if no item_number)
                display_num = item_number if item_number else str(item_id)
                label = f"#{display_num} | {hcpcs} | {description}"
                
                self.item_combo.addItem(label)
                self._inventory_index[label] = {
                    'id': item_id,
                    'item_number': item_number,
                    'hcpcs': hcpcs,
                    'description': description,
                    'cost': price
                }
            
            self.item_combo.setCurrentIndex(-1)  # Clear selection
        except Exception as e:
            print(f"QuickDeliveryTicket: load_inventory failed: {e}")

    def add_item_from_inventory(self):
        """Add selected inventory item to the items table."""
        try:
            label = self.item_combo.currentText()
            rec = self._inventory_index.get(label)
            if not rec:
                QMessageBox.warning(self, "No Item Selected", "Please select an item from the dropdown.")
                return
            
            r = self.ticket_items.rowCount()
            self.ticket_items.insertRow(r)
            
            # Populate HCPCS, Description, default Qty=1
            self.ticket_items.setItem(r, 0, QTableWidgetItem(rec.get('hcpcs') or ''))
            self.ticket_items.setItem(r, 1, QTableWidgetItem(rec.get('description') or ''))
            self.ticket_items.setItem(r, 2, QTableWidgetItem("1"))
            self.ticket_items.setItem(r, 3, QTableWidgetItem(""))  # Directions empty
            
            # Clear selection for next item
            self.item_combo.setCurrentIndex(-1)
        except Exception as e:
            QMessageBox.warning(self, "Add Item", f"Failed to add item: {e}")

    def add_to_inventory(self):
        """Open add inventory dialog."""
        try:
            if not hasattr(self.parent, 'add_inventory_item'):
                QMessageBox.warning(self, "Feature Unavailable", "Inventory management is not available.")
                return
            
            # Call parent's add inventory method
            self.parent.add_inventory_item()
            
            # Reload inventory after adding
            self.load_inventory()
        except Exception as e:
            QMessageBox.warning(self, "Add to Inventory", f"Failed: {e}")

    def _default_ticket_dir(self) -> str:
        try:
            # Use Downloads folder
            from pathlib import Path
            downloads = str(Path.home() / "Downloads")
            if os.path.exists(downloads):
                return downloads
            # Fallback to user home if Downloads doesn't exist
            return str(Path.home())
        except Exception:
            return os.getcwd()

    def generate_ticket_pdf(self):
        try:
            # Build filename
            from datetime import datetime
            ts = datetime.now().strftime('%Y%m%d_%H%M%S')
            lname = (self.pt_last.text() or '').strip().replace(' ', '_') or 'PATIENT'
            fname = (self.pt_first.text() or '').strip().replace(' ', '_') or ''
            base_name = f"Delivery_Ticket_{lname}_{fname}_{ts}.pdf" if fname else f"Delivery_Ticket_{lname}_{ts}.pdf"

            # Ask save location (default to Tickets under db_folder)
            default_dir = self._default_ticket_dir()
            out_path, _ = QFileDialog.getSaveFileName(self, 'Save Delivery Ticket', os.path.join(default_dir, base_name), 'PDF Files (*.pdf)')
            if not out_path:
                return

            # Generate with reportlab
            from reportlab.lib.pagesizes import letter
            from reportlab.pdfgen import canvas
            from reportlab.lib.units import inch
            c = canvas.Canvas(out_path, pagesize=letter)
            width, height = letter

            # Header
            c.setFont('Helvetica-Bold', 16)
            c.drawString(1*inch, height-1*inch, 'DELIVERY TICKET')
            c.setFont('Helvetica', 10)
            c.drawString(1*inch, height-1.25*inch, f"Date: {self.ticket_date.date().toString('MM/dd/yyyy')}")

            # Patient + Prescriber block
            y = height-1.6*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Patient:'); c.setFont('Helvetica', 10)
            c.drawString(1.7*inch, y, f"{self.pt_last.text().strip()}, {self.pt_first.text().strip()}")
            y -= 0.18*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'DOB:'); c.setFont('Helvetica', 10)
            c.drawString(1.7*inch, y, self.pt_dob.text().strip())
            y -= 0.18*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Phone:'); c.setFont('Helvetica', 10)
            c.drawString(1.7*inch, y, self.pt_phone.text().strip())
            y -= 0.18*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Address:'); c.setFont('Helvetica', 10)
            c.drawString(1.7*inch, y, self.pt_address.text().strip())
            y -= 0.18*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Prescriber:'); c.setFont('Helvetica', 10)
            c.drawString(1.7*inch, y, (self.pr_name.text() or '').strip())
            y -= 0.18*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Prescriber Phone:'); c.setFont('Helvetica', 10)
            c.drawString(2.4*inch, y, (self.pr_phone.text() or '').strip())

            # Table header
            y -= 0.35*inch
            c.setFont('Helvetica-Bold', 10)
            # Column headers with proper spacing
            c.drawString(1*inch, y, 'HCPCS')
            c.drawString(2*inch, y, 'Description')
            c.drawString(6.5*inch, y, 'Qty')
            y -= 0.05*inch
            c.line(1*inch, y, 7.5*inch, y)
            y -= 0.15*inch

            # Rows
            c.setFont('Helvetica', 10)
            for r in range(self.ticket_items.rowCount()):
                vals = [self.ticket_items.item(r, i).text() if self.ticket_items.item(r, i) else '' for i in range(4)]
                hcpcs, desc, qty, directions = vals

                # First line: HCPCS, Description, Qty with proper spacing
                c.drawString(1*inch, y, (hcpcs or '')[:15])
                c.drawString(2*inch, y, (desc or '')[:65])
                c.drawString(6.5*inch, y, (qty or '')[:5])

                # Second line: Directions placed beneath description
                y -= 0.18*inch
                if directions:
                    c.setFont('Helvetica-Oblique', 10)
                    c.drawString(2*inch, y, f"Directions: {(directions or '')[:100]}")
                    c.setFont('Helvetica', 10)

                # Row spacing
                y -= 0.24*inch
                if y < 1.95*inch:
                    # New page if needed (leave space for signatures)
                    c.showPage()
                    width, height = letter
                    y = height-1*inch

            # Notes
            if y < 2.4*inch:
                c.showPage(); y = height-1*inch
            c.setFont('Helvetica-Bold', 10); c.drawString(1*inch, y, 'Notes:')
            y -= 0.18*inch
            c.setFont('Helvetica', 10)
            for line in (self.ticket_notes.toPlainText() or '').splitlines():
                c.drawString(1*inch, y, line[:90])
                y -= 0.18*inch
                if y < 2.2*inch:
                    c.showPage(); y = height-1*inch

            # Signatures
            y = 1.8*inch
            # Signature lines
            c.line(1*inch, y, 4*inch, y)
            c.drawString(1*inch, y-0.18*inch, 'Patient/Recipient Signature')
            c.line(4.5*inch, y, 7.5*inch, y)
            c.drawString(4.5*inch, y-0.18*inch, 'Delivered By (Signature)')

            # Print name and date areas beneath each signature
            c.setFont('Helvetica', 10)
            left_y = y - 0.38*inch
            c.drawString(1*inch, left_y, 'Print Name:')
            c.line(1.8*inch, left_y, 4*inch, left_y)
            c.drawString(1*inch, left_y - 0.25*inch, 'Date:')
            c.line(1.4*inch, left_y - 0.25*inch, 3*inch, left_y - 0.25*inch)

            right_y = y - 0.38*inch
            c.drawString(4.5*inch, right_y, 'Print Name:')
            c.line(5.4*inch, right_y, 7.5*inch, right_y)
            c.drawString(4.5*inch, right_y - 0.25*inch, 'Date:')
            c.line(4.9*inch, right_y - 0.25*inch, 6.5*inch, right_y - 0.25*inch)

            c.save()

            try:
                os.startfile(out_path)
            except Exception:
                pass
            QMessageBox.information(self, 'Delivery Ticket', f'Saved to:\n{out_path}')
            self.accept()
        except Exception as e:
            QMessageBox.critical(self, 'Delivery Ticket', f'Failed to generate: {e}')


# ============================================================================
# ICD-10 CODE SEARCH DIALOG
# ============================================================================
class ICD10SearchDialog(QDialog):
    """Dialog for searching ICD-10 codes using NIH ClinicalTables API"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("🔍 ICD-10 Code Search")
        self.setWindowFlags(self.windowFlags() | Qt.WindowType.WindowMinMaxButtonsHint)
        self.resize(800, 600)
        self.selected_code = None
        self.selected_description = None
        
        layout = QVBoxLayout(self)
        
        # Search input
        search_layout = QHBoxLayout()
        search_layout.addWidget(QLabel("Search:"))
        self.search_input = QLineEdit()
        self.search_input.setPlaceholderText("Enter diagnosis, symptom, or condition...")
        self.search_input.returnPressed.connect(self.perform_search)
        search_layout.addWidget(self.search_input)
        
        self.search_btn = QPushButton("🔍 Search")
        self.search_btn.clicked.connect(self.perform_search)
        search_layout.addWidget(self.search_btn)
        layout.addLayout(search_layout)
        
        # Results table
        self.results_table = QTableWidget()
        self.results_table.setColumnCount(2)
        self.results_table.setHorizontalHeaderLabels(["Code", "Description"])
        self.results_table.horizontalHeader().setStretchLastSection(True)
        self.results_table.setColumnWidth(0, 100)
        self.results_table.setSelectionBehavior(QTableWidget.SelectionBehavior.SelectRows)
        self.results_table.setEditTriggers(QTableWidget.EditTrigger.NoEditTriggers)
        self.results_table.doubleClicked.connect(self.on_double_click)
        layout.addWidget(self.results_table)
        
        # Status label
        self.status_label = QLabel("Enter search terms and click Search")
        self.status_label.setStyleSheet("color: #666; font-style: italic;")
        layout.addWidget(self.status_label)
        
        # Buttons
        button_layout = QHBoxLayout()
        button_layout.addStretch()
        
        self.select_btn = QPushButton("✓ Select Code")
        self.select_btn.clicked.connect(self.on_select)
        self.select_btn.setEnabled(False)
        button_layout.addWidget(self.select_btn)
        
        cancel_btn = QPushButton("Cancel")
        cancel_btn.clicked.connect(self.reject)
        button_layout.addWidget(cancel_btn)
        
        layout.addLayout(button_layout)
        
        # Enable select button when row is selected
        self.results_table.itemSelectionChanged.connect(self.on_selection_changed)
        
        # Focus search input
        self.search_input.setFocus()
    
    def on_selection_changed(self):
        """Enable select button when a row is selected"""
        self.select_btn.setEnabled(len(self.results_table.selectedItems()) > 0)
    
    def perform_search(self):
        """Query NIH ClinicalTables API for ICD-10 codes"""
        search_term = self.search_input.text().strip()
        
        if not search_term:
            self.status_label.setText("Please enter a search term")
            self.status_label.setStyleSheet("color: #dc3545;")
            return
        
        # Check if urllib is available
        if urllib is None:
            self.status_label.setText("Error: urllib not available")
            self.status_label.setStyleSheet("color: #dc3545;")
            return
        
        self.status_label.setText("Searching...")
        self.status_label.setStyleSheet("color: #007bff;")
        self.search_btn.setEnabled(False)
        self.results_table.setRowCount(0)
        
        try:
            # Build API URL
            base_url = "https://clinicaltables.nlm.nih.gov/api/icd10cm/v3/search"
            params = {
                'sf': 'code,name',
                'terms': search_term,
                'maxList': 100
            }
            url = f"{base_url}?{urllib.parse.urlencode(params)}"
            
            # Make request
            with urllib.request.urlopen(url, timeout=10) as response:
                data = json.loads(response.read().decode('utf-8'))
            
            # Parse response: [count, [codes], null, [descriptions]]
            # Example: [1, ["J45.909"], null, ["Unspecified asthma, uncomplicated"]]
            if not data or not isinstance(data, list) or len(data) < 4:
                self.status_label.setText("Invalid response from server")
                self.status_label.setStyleSheet("color: #dc3545;")
                return
            
            count = data[0]
            codes = data[1] if data[1] and isinstance(data[1], list) else []
            descriptions = data[3] if data[3] and isinstance(data[3], list) else []
            
            if count == 0 or not codes:
                self.status_label.setText(f"No results found for '{search_term}'")
                self.status_label.setStyleSheet("color: #666;")
                return
            
            # Populate table - ensure we convert items to strings
            self.results_table.setRowCount(len(codes))
            for i in range(len(codes)):
                # Get code and description, ensuring they're strings
                code = str(codes[i]) if i < len(codes) else ""
                desc = str(descriptions[i]) if i < len(descriptions) else ""
                
                code_item = QTableWidgetItem(code)
                desc_item = QTableWidgetItem(desc)
                self.results_table.setItem(i, 0, code_item)
                self.results_table.setItem(i, 1, desc_item)
            
            self.status_label.setText(f"Found {count} result{'s' if count != 1 else ''}")
            self.status_label.setStyleSheet("color: #28a745;")
            
        except urllib.error.URLError as e:
            self.status_label.setText(f"Network error: {str(e)}")
            self.status_label.setStyleSheet("color: #dc3545;")
        except Exception as e:
            self.status_label.setText(f"Error: {str(e)}")
            self.status_label.setStyleSheet("color: #dc3545;")
        finally:
            self.search_btn.setEnabled(True)
    
    def on_double_click(self):
        """Handle double-click on a result row"""
        self.on_select()
    
    def on_select(self):
        """Select the currently highlighted code"""
        selected_rows = self.results_table.selectedItems()
        if not selected_rows:
            return
        
        row = self.results_table.currentRow()
        if row >= 0:
            code_item = self.results_table.item(row, 0)
            desc_item = self.results_table.item(row, 1)
            
            if code_item and desc_item:
                self.selected_code = code_item.text()
                self.selected_description = desc_item.text()
                self.accept()


