class NewOrderDialog(QDialog):
    def __init__(self, parent=None, order_data=None, order_items=None, order_id=None):
        super().__init__(parent)
        self.setWindowTitle("DME Order Management - New Order")
        # Non-modal; we will open with .show()
        self.setModal(False)
        
        # Enable window controls: minimize, maximize, resize
        self.setWindowFlags(
            Qt.WindowType.Window |
            Qt.WindowType.WindowMinimizeButtonHint |
            Qt.WindowType.WindowMaximizeButtonHint |
            Qt.WindowType.WindowCloseButtonHint
        )
        
        # Guard flag to prevent recursive cellChanged loops when we update cells programmatically
        self._updating_totals = False
        # Track attached files (stored as list of absolute paths)
        self._attached_rx_files = []
        self._attached_signed_tickets = []
        # Store all inventory items for filtering
        self._all_inventory_items = []
        self._inventory_index = {}
        
        # Track recent patients (last 4 selected)
        self._recent_patients = []
        
        # Auto-save draft functionality
        self._draft_file = os.path.join(os.environ.get('TEMP', '.'), 'dmelogic_order_draft.json')
        self._auto_save_timer = None

        # Make dialog wider to fit long columns/ICD row
        screen = QApplication.primaryScreen().geometry()
        dialog_width = int(screen.width() * 0.8)   # 80% of screen width
        dialog_height = int(screen.height() * 0.8) # 80% of screen height
        self.resize(dialog_width, dialog_height)
        
        self.parent = parent
        self.current_order_id = order_id
        self.existing_order_data = order_data
        self.existing_order_items = order_items or []
        self.setup_ui()
        self.load_patients()
        self.load_prescribers()
        self.load_clinics()
        self.load_inventory()
        
        # Start auto-save timer for new orders
        if not order_id:
            self._start_auto_save()
            # Restore pending draft if available (set by _check_for_draft)
            if hasattr(self, '_pending_draft') and self._pending_draft:
                # Use single-shot timer to restore after event loop processes
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(100, lambda: self._restore_draft(self._pending_draft))
        
        # If editing existing order, populate fields and update order number
        if self.existing_order_data:
            self.populate_existing_order()
            # Update order number display for existing orders
            if self.current_order_id:
                try:
                    order_num = self.parent.format_order_number(self.current_order_id) if hasattr(self.parent, 'format_order_number') else f"ORD-{str(self.current_order_id).zfill(3)}"
                except Exception:
                    order_num = f"ORD-{str(self.current_order_id).zfill(3)}"
                self.order_number_label.setText(f"Order #: {order_num}")
                self.setWindowTitle(f"Edit Order {order_num}")
                
                # Check if this order is already refill_completed - disable the Process Refill button
                self._check_and_disable_refill_button()
        else:
            # Check for and offer to restore draft for NEW orders only
            self._check_for_draft()
            
            # Preview the next order number so the header matches expectations
            try:
                next_id = self._predict_next_order_id()
                if next_id:
                    preview = self.parent.format_order_number(next_id) if hasattr(self.parent, 'format_order_number') else f"ORD-{str(next_id).zfill(3)}"
                    self.order_number_label.setText(f"Order #: {preview}")
            except Exception:
                pass
    
    def update_window_title(self, patient_last=None, patient_first=None):
        """
        Build a descriptive window title using:
        - mode (New/Edit)
        - order number (if known)
        - patient name (LAST, FIRST if known)
        """
        try:
            # Determine base mode: editing vs creating
            is_edit = bool(self.current_order_id)

            # Order number (ORD-xxx) if we have an ID
            order_part = ""
            if self.current_order_id:
                try:
                    if hasattr(self.parent, "format_order_number"):
                        order_part = self.parent.format_order_number(self.current_order_id)
                    else:
                        order_part = f"ORD-{int(self.current_order_id):03d}"
                except Exception:
                    order_part = f"ORD-{self.current_order_id}"

            # Patient name BEST-EFFORT
            name_part = ""
            last = (patient_last or "").strip()
            first = (patient_first or "").strip()
            if last or first:
                if last and first:
                    name_part = f"{last.upper()}, {first.upper()}"
                else:
                    name_part = (last or first).upper()

            # Assemble pieces
            pieces = []
            if order_part:
                pieces.append(order_part)
            if name_part:
                pieces.append(name_part)

            suffix = " — ".join(pieces) if pieces else ""

            if is_edit:
                title = "Edit DME Order"
            else:
                title = "New DME Order"

            if suffix:
                title = f"{title} — {suffix}"

            self.setWindowTitle(title)
        except Exception:
            # Fail quietly; title is cosmetic
            pass
    
    def _check_for_draft(self):
        """Check for and offer to restore a saved draft."""
        try:
            if os.path.exists(self._draft_file):
                import json
                with open(self._draft_file, 'r') as f:
                    draft = json.load(f)
                
                # Check if draft is recent (within last 24 hours)
                from datetime import datetime
                draft_time = draft.get('saved_at', '')
                if draft_time:
                    try:
                        saved = datetime.fromisoformat(draft_time)
                        age_hours = (datetime.now() - saved).total_seconds() / 3600
                        if age_hours > 24:
                            # Draft too old, delete it
                            os.remove(self._draft_file)
                            return
                    except Exception:
                        pass
                
                # Ask user if they want to restore
                patient_name = draft.get('patient', 'Unknown')
                reply = QMessageBox.question(
                    self,
                    "Restore Draft?",
                    f"A saved draft was found for patient: {patient_name}\n\nWould you like to restore it?",
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.Yes
                )
                
                if reply == QMessageBox.StandardButton.Yes:
                    # Restore will happen after UI is set up
                    self._pending_draft = draft
                else:
                    # Delete the draft
                    os.remove(self._draft_file)
        except Exception as e:
            print(f"⚠️ Error checking for draft: {e}")
    
    def _restore_draft(self, draft: dict):
        """Restore form fields from a saved draft."""
        try:
            # Patient
            if draft.get('patient'):
                idx = self.patient_combo.findText(draft['patient'])
                if idx >= 0:
                    self.patient_combo.setCurrentIndex(idx)
            
            # Prescriber
            if draft.get('prescriber'):
                idx = self.prescriber_combo.findText(draft['prescriber'])
                if idx >= 0:
                    self.prescriber_combo.setCurrentIndex(idx)
            
            # Clinic
            if draft.get('clinic') and hasattr(self, 'clinic_combo'):
                idx = self.clinic_combo.findText(draft['clinic'])
                if idx >= 0:
                    self.clinic_combo.setCurrentIndex(idx)
            
            # RX Date
            if draft.get('rx_date') and hasattr(self, 'rx_date_edit'):
                try:
                    from PyQt6.QtCore import QDate
                    date = QDate.fromString(draft['rx_date'], "yyyy-MM-dd")
                    if date.isValid():
                        self.rx_date_edit.setDate(date)
                except Exception:
                    pass
            
            # Order Date
            if draft.get('order_date') and hasattr(self, 'order_date_edit'):
                try:
                    from PyQt6.QtCore import QDate
                    date = QDate.fromString(draft['order_date'], "yyyy-MM-dd")
                    if date.isValid():
                        self.order_date_edit.setDate(date)
                except Exception:
                    pass
            
            # ICD codes
            icd_codes = draft.get('icd_codes', [])
            if hasattr(self, 'icd_inputs') and icd_codes:
                for i, code in enumerate(icd_codes[:5]):
                    if i < len(self.icd_inputs):
                        self.icd_inputs[i].setText(code)
            
            # Notes
            if draft.get('notes') and hasattr(self, 'notes_edit'):
                self.notes_edit.setPlainText(draft['notes'])
            
            # Doctor directions
            if draft.get('doctor_directions') and hasattr(self, 'doctor_directions_edit'):
                self.doctor_directions_edit.setPlainText(draft['doctor_directions'])
            
            print("✅ Draft restored successfully")
        except Exception as e:
            print(f"⚠️ Error restoring draft: {e}")
    
    def _save_draft(self):
        """Save current form state as a draft."""
        try:
            import json
            from datetime import datetime
            
            # Only save for new orders, not edits
            if self.current_order_id:
                return
            
            draft = {
                'saved_at': datetime.now().isoformat(),
                'patient': self.patient_combo.currentText() if hasattr(self, 'patient_combo') else '',
                'prescriber': self.prescriber_combo.currentText() if hasattr(self, 'prescriber_combo') else '',
                'clinic': self.clinic_combo.currentText() if hasattr(self, 'clinic_combo') else '',
                'rx_date': self.rx_date_edit.date().toString("yyyy-MM-dd") if hasattr(self, 'rx_date_edit') else '',
                'order_date': self.order_date_edit.date().toString("yyyy-MM-dd") if hasattr(self, 'order_date_edit') else '',
                'icd_codes': [inp.text() for inp in getattr(self, 'icd_inputs', [])][:5],
                'notes': self.notes_edit.toPlainText() if hasattr(self, 'notes_edit') else '',
                'doctor_directions': self.doctor_directions_edit.toPlainText() if hasattr(self, 'doctor_directions_edit') else '',
            }
            
            # Only save if there's actual content
            has_content = (
                draft['patient'] or 
                draft['prescriber'] or 
                any(draft['icd_codes']) or 
                draft['notes'] or 
                draft['doctor_directions']
            )
            
            if has_content:
                with open(self._draft_file, 'w') as f:
                    json.dump(draft, f)
                print("💾 Draft saved")
        except Exception as e:
            print(f"⚠️ Error saving draft: {e}")
    
    def _start_auto_save(self):
        """Start auto-save timer (saves every 30 seconds)."""
        try:
            from PyQt6.QtCore import QTimer
            self._auto_save_timer = QTimer(self)
            self._auto_save_timer.timeout.connect(self._save_draft)
            self._auto_save_timer.start(30000)  # 30 seconds
        except Exception as e:
            print(f"⚠️ Error starting auto-save: {e}")
    
    def _clear_draft(self):
        """Remove the draft file after successful save."""
        try:
            if os.path.exists(self._draft_file):
                os.remove(self._draft_file)
                print("🗑️ Draft cleared")
        except Exception as e:
            print(f"⚠️ Error clearing draft: {e}")
    
    def closeEvent(self, event):
        """Handle dialog close - save draft if there's unsaved work."""
        try:
            # Stop auto-save timer
            if self._auto_save_timer:
                self._auto_save_timer.stop()
            
            # Save draft before closing (for new orders only)
            if not self.current_order_id:
                self._save_draft()
        except Exception:
            pass
        super().closeEvent(event)
    
    def make_section_header(self, title: str):
        """Helper to create a modern section header"""
        header = QFrame()
        header.setObjectName("SectionHeader")
        header.setFrameShape(QFrame.Shape.NoFrame)
        layout = QHBoxLayout(header)
        layout.setContentsMargins(0, 0, 0, 0)
        label = QLabel(title)
        label.setObjectName("SectionTitle")
        layout.addWidget(label)
        layout.addStretch()
        return header
    
