    def copy_npi_to_clipboard(self):
        """Copy prescriber NPI number to the clipboard."""
        prescriber_text = self.prescriber_summary_label.text()
        if "NPI:" in prescriber_text and "[No prescriber selected]" not in prescriber_text:
            # Extract NPI number from text like "ANSARI, ASIF • NPI: 1194916197"
            npi_part = prescriber_text.split("NPI:")[-1].strip()
            # Remove any trailing text after the NPI number
            npi_number = npi_part.split()[0] if npi_part else ""
            if npi_number:
                clipboard = QApplication.clipboard()
                clipboard.setText(npi_number)
                QMessageBox.information(
                    self,
                    "Copied",
                    f"NPI copied to clipboard:\n\n{npi_number}"
                )
            else:
                QMessageBox.warning(
                    self,
                    "No NPI",
                    "Could not extract NPI number."
                )
        else:
            QMessageBox.warning(
                self,
                "No Prescriber",
                "No prescriber selected. Please select a prescriber first."
            )
    
