    def clear_paid_date_field(self):
        """Clear the Paid Date in the Edit/New Order dialog.
        Uses the field's minimum date (blank display via SpecialValueText).
        If the order is marked as Paid, offer to uncheck it before clearing.
        """
        try:
            # If Paid is checked, confirm unchecking to clear date
            if hasattr(self, 'paid_checkbox') and self.paid_checkbox.isChecked():
                reply = QMessageBox.question(
                    self,
                    "Cannot Clear Date",
                    (
                        "This order is marked as Paid. A Paid Date is required.\n\n"
                        "Do you want to uncheck Paid and clear the date?"
                    ),
                    QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                    QMessageBox.StandardButton.No,
                )
                if reply != QMessageBox.StandardButton.Yes:
                    return
                try:
                    self.paid_checkbox.blockSignals(True)
                    self.paid_checkbox.setChecked(False)
                finally:
                    try:
                        self.paid_checkbox.blockSignals(False)
                    except Exception:
                        pass
            self.paid_date_edit.setDate(QDate(2000, 1, 1))
        except Exception:
            # If the widget isn't available yet, ignore gracefully
            pass

