    def update_backup_status_display(self):
        """Update the last backup status labels."""
        try:
            from dmelogic.backup import get_latest_backup_info
            from datetime import datetime
            
            # Daily backup status
            daily_info = get_latest_backup_info("daily")
            if daily_info:
                try:
                    created = datetime.fromisoformat(daily_info["created_at"])
                    time_str = created.strftime("%Y-%m-%d %H:%M")
                    self.last_daily_label.setText(f"{time_str} ✅")
                    self.last_daily_label.setStyleSheet("color: #22C55E;")
                except Exception:
                    self.last_daily_label.setText(daily_info["filename"])
            else:
                self.last_daily_label.setText("No daily backups found")
                self.last_daily_label.setStyleSheet("color: #888888;")
            
            # Weekly backup status
            weekly_info = get_latest_backup_info("weekly")
            if weekly_info:
                try:
                    created = datetime.fromisoformat(weekly_info["created_at"])
                    time_str = created.strftime("%Y-%m-%d %H:%M")
                    self.last_weekly_label.setText(f"{time_str} ✅")
                    self.last_weekly_label.setStyleSheet("color: #22C55E;")
                except Exception:
                    self.last_weekly_label.setText(weekly_info["filename"])
            else:
                self.last_weekly_label.setText("No weekly backups found")
                self.last_weekly_label.setStyleSheet("color: #888888;")
                
        except Exception as e:
            self.last_daily_label.setText("Status unavailable")
            self.last_weekly_label.setText("Status unavailable")
    
    def verify_last_backup(self):
        """Verify the integrity of the most recent backup."""
        try:
            from dmelogic.backup import get_latest_backup_info, verify_backup
            
            # Find the most recent backup (daily or weekly)
            daily_info = get_latest_backup_info("daily")
            weekly_info = get_latest_backup_info("weekly")
            
            latest = None
            if daily_info and weekly_info:
                # Pick the more recent one
                from datetime import datetime
                daily_time = datetime.fromisoformat(daily_info["created_at"])
                weekly_time = datetime.fromisoformat(weekly_info["created_at"])
                latest = daily_info if daily_time > weekly_time else weekly_info
            elif daily_info:
                latest = daily_info
            elif weekly_info:
                latest = weekly_info
            
            if not latest:
                QMessageBox.warning(self, "Verify Backup", "No backups found to verify.")
                return
            
            # Run verification
            QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)
            try:
                result = verify_backup(latest["path"])
            finally:
                QApplication.restoreOverrideCursor()
            
            # Build report
            report_lines = [
                f"Backup: {latest['filename']}",
                f"Type: {latest['backup_type'].capitalize()}",
                f"Created: {latest['created_at'][:19]}",
                "",
            ]
            
            if result["valid"]:
                report_lines.append("✅ Verification PASSED")
                report_lines.append("")
                report_lines.append(f"Databases verified: {len(result['databases'])}")
                for db in result["databases"]:
                    status = "✓" if db["integrity_ok"] and db["checksum_ok"] else "✗"
                    report_lines.append(f"  {status} {db['name']}")
            else:
                report_lines.append("❌ Verification FAILED")
                report_lines.append("")
                for err in result["errors"]:
                    report_lines.append(f"  • {err}")
            
            if result["warnings"]:
                report_lines.append("")
                report_lines.append("Warnings:")
                for warn in result["warnings"]:
                    report_lines.append(f"  • {warn}")
            
            QMessageBox.information(self, "Backup Verification", "\n".join(report_lines))
            
        except Exception as e:
            QMessageBox.critical(self, "Verify Backup", f"Verification failed:\n{e}")
    
    def create_backup(self):
        """Create a manual backup using the new backup system."""
        from dmelogic.backup import BackupWorker as DmeBackupWorker
        
        self.progress_bar.setVisible(True)
        self.progress_bar.setValue(0)
        self.create_backup_btn.setEnabled(False)
        
        # Get data folder path from parent app
        data_folder = self.parent_app.folder_path
        
        # Use the enhanced BackupWorker from dmelogic.backup
        self.backup_worker = DmeBackupWorker(
            mode="backup",
            source_path=data_folder,
            backup_type="manual",
            auto_discover=True,
        )
        self.backup_thread = QThread()
        self.backup_worker.moveToThread(self.backup_thread)
        self.backup_worker.progress.connect(self.progress_bar.setValue)
        self.backup_worker.finished.connect(self.backup_finished)
        self.backup_worker.error.connect(self.backup_error)
        self.backup_thread.started.connect(self.backup_worker.run)
        self.backup_thread.start()
    
    def restore_backup(self):
        """Restore from a backup file using the new backup system."""
        from dmelogic.backup import BackupWorker as DmeBackupWorker
        
        backup_file, _ = QFileDialog.getOpenFileName(
            self, "Select Backup File", BACKUP_FOLDER, "Backup Files (*.zip)"
        )
        
        if backup_file:
            reply = QMessageBox.question(
                self, "Restore Backup",
                "This will overwrite current settings and data.\n\n"
                "A safety backup will be created before restoring.\n"
                "Are you sure you want to continue?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
            )
            
            if reply == QMessageBox.StandardButton.Yes:
                self.progress_bar.setVisible(True)
                self.progress_bar.setValue(0)
                self.restore_backup_btn.setEnabled(False)
                
                # Get data folder path from parent app
                data_folder = self.parent_app.folder_path
                
                # Use the enhanced BackupWorker from dmelogic.backup
                self.backup_worker = DmeBackupWorker(
                    mode="restore",
                    source_path=data_folder,
                    backup_path=backup_file,
                )
                self.backup_thread = QThread()
                self.backup_worker.moveToThread(self.backup_thread)
                self.backup_worker.progress.connect(self.progress_bar.setValue)
                self.backup_worker.finished.connect(self.restore_finished)
                self.backup_worker.error.connect(self.restore_error)
                self.backup_thread.started.connect(self.backup_worker.run)
                self.backup_thread.start()
    
    def view_backups(self):
        """Open backup folder in file explorer."""
        backup_path = os.path.abspath(BACKUP_FOLDER)
        if not os.path.exists(backup_path):
            os.makedirs(backup_path, exist_ok=True)
        
        try:
            os.startfile(backup_path)
        except:
            QMessageBox.information(self, "Backup Location", f"Backup folder: {backup_path}")
    
    def backup_finished(self, backup_path):
        """Handle backup completion."""
        self.progress_bar.setVisible(False)
        self.create_backup_btn.setEnabled(True)
        QMessageBox.information(self, "Backup Complete", f"Backup created successfully:\n{backup_path}")
        # Refresh the backup status display
        self.update_backup_status_display()
    
    def restore_finished(self, message):
        """Handle restore completion."""
        self.progress_bar.setVisible(False)
        self.restore_backup_btn.setEnabled(True)
        QMessageBox.information(self, "Restore Complete", 
                              f"{message}\n\nPlease restart the application to apply restored settings.")
    
    def backup_error(self, error_message):
        """Handle backup/restore errors."""
        self.progress_bar.setVisible(False)
        self.create_backup_btn.setEnabled(True)
        self.restore_backup_btn.setEnabled(True)
        # If the worker tagged the message with a mode, route appropriately
        if isinstance(error_message, str) and error_message.startswith("[restore]"):
            return self.restore_error(error_message)
        QMessageBox.critical(self, "Backup Error", f"Error during backup operation:\n{error_message}")

    def restore_error(self, error_message):
        """Handle restore-specific errors with clearer messaging."""
        self.progress_bar.setVisible(False)
        self.create_backup_btn.setEnabled(True)
        self.restore_backup_btn.setEnabled(True)
        QMessageBox.critical(self, "Restore Error", f"Error during restore operation:\n{error_message}")
    
    def load_current_settings(self):
        """Load current settings into the dialog."""
        # General settings
        self.autosave_enabled.setChecked(self.settings.get('autosave_enabled', True))
        self.autosave_delay.setValue(self.settings.get('autosave_delay', 2))
        self.remember_last_folder.setChecked(self.settings.get('remember_last_folder', True))
        self.max_quick_folders.setValue(self.settings.get('max_quick_folders', 5))
        self.show_welcome.setChecked(self.settings.get('show_welcome', True))
        self.restore_window_state.setChecked(self.settings.get('restore_window_state', True))
        
        # Appearance settings
        self.theme_combo.setCurrentText(self.settings.get('theme', 'Light'))
        self.accent_color = self.settings.get('accent_color', '#0078D4')
        self.accent_color_btn.setStyleSheet(f"background-color: {self.accent_color};")
        self.font_family.setCurrentText(self.settings.get('font_family', 'System Default'))
        self.font_size.setValue(self.settings.get('font_size', 11))
        self.ui_scale.setValue(self.settings.get('ui_scale', 100))
        
        # PDF Viewer settings
        self.default_zoom.setValue(self.settings.get('default_zoom', 100))
        self.zoom_step.setValue(self.settings.get('zoom_step', 20))
        self.smooth_zoom.setChecked(self.settings.get('smooth_zoom', True))
        self.high_quality_render.setChecked(self.settings.get('high_quality_render', False))
        self.preload_pages.setChecked(self.settings.get('preload_pages', True))
        self.remember_zoom.setChecked(self.settings.get('remember_zoom', True))
        self.mouse_wheel_zoom.setChecked(self.settings.get('mouse_wheel_zoom', True))
        self.page_turn_animation.setChecked(self.settings.get('page_turn_animation', False))
        
        # Scanner settings
        self.scanner_mode_combo.setCurrentText(self.settings.get('scanner_mode', 'Auto'))
        scanner_id = self.settings.get('scanner_device_id', '')
        if scanner_id:
            idx = self.scanner_combo.findData(scanner_id)
            if idx >= 0:
                self.scanner_combo.setCurrentIndex(idx)
        self.scan_format_combo.setCurrentText(self.settings.get('scan_format', 'PDF'))
        self.scan_folder_edit.setText(self.settings.get('scan_folder', ''))
        self.scanner_app_edit.setText(self.settings.get('scanner_app_path', ''))
        self.scanner_output_folder_edit.setText(self.settings.get('scanner_output_folder', ''))

        # Backup settings (with new defaults: enabled by default)
        self.auto_backup_enabled.setChecked(self.settings.get('auto_backup_enabled', True))
        self.daily_backup_enabled.setChecked(self.settings.get('daily_backup_enabled', True))
        self.weekly_backup_enabled.setChecked(self.settings.get('weekly_backup_enabled', True))
        backup_location = self.settings.get('backup_location', os.path.abspath(BACKUP_FOLDER))
        self.backup_location.setText(backup_location)

        # Azure OCR settings
        self.azure_endpoint.setText(self.settings.get('azure_di_endpoint', ''))
        self.azure_key.setText(self.settings.get('azure_di_key', ''))

        # OpenAI AI Parser settings
        self.openai_key.setText(self.settings.get('openai_api_key', ''))
        self.openai_model.setCurrentText(self.settings.get('openai_model', 'gpt-4o-mini'))
    
    def apply_settings(self):
        """Apply settings without closing dialog."""
        self.save_settings()
        self.parent_app.apply_settings(self.settings)
        # Reconfigure Azure OCR singleton immediately
        try:
            azure_endpoint = self.settings.get('azure_di_endpoint', '')
            azure_key = self.settings.get('azure_di_key', '')
            if azure_endpoint and azure_key:
                from dmelogic.services.azure_ocr import configure_azure_ocr
                configure_azure_ocr(azure_endpoint, azure_key)
        except Exception:
            pass
        # Reconfigure OpenAI AI Parser singleton immediately
        try:
            openai_key = self.settings.get('openai_api_key', '')
            openai_model = self.settings.get('openai_model', 'gpt-4o-mini')
            if openai_key:
                from dmelogic.services.ai_rx_parser import configure_openai
                configure_openai(openai_key, openai_model)
        except Exception:
            pass
    
    def save_settings(self):
        """Save settings from dialog controls."""
        # General settings
        self.settings['autosave_enabled'] = self.autosave_enabled.isChecked()
        self.settings['autosave_delay'] = self.autosave_delay.value()
        self.settings['remember_last_folder'] = self.remember_last_folder.isChecked()
        self.settings['max_quick_folders'] = self.max_quick_folders.value()
        self.settings['show_welcome'] = self.show_welcome.isChecked()
        self.settings['restore_window_state'] = self.restore_window_state.isChecked()
        
        # Appearance settings
        self.settings['theme'] = self.theme_combo.currentText()
        self.settings['accent_color'] = self.accent_color
        self.settings['font_family'] = self.font_family.currentText()
        self.settings['font_size'] = self.font_size.value()
        self.settings['ui_scale'] = self.ui_scale.value()
        
        # PDF Viewer settings
        self.settings['default_zoom'] = self.default_zoom.value()
        self.settings['zoom_step'] = self.zoom_step.value()
        self.settings['smooth_zoom'] = self.smooth_zoom.isChecked()
        self.settings['high_quality_render'] = self.high_quality_render.isChecked()
        self.settings['preload_pages'] = self.preload_pages.isChecked()
        self.settings['remember_zoom'] = self.remember_zoom.isChecked()
        self.settings['mouse_wheel_zoom'] = self.mouse_wheel_zoom.isChecked()
        self.settings['page_turn_animation'] = self.page_turn_animation.isChecked()
        
        # Scanner settings
        self.settings['scanner_mode'] = self.scanner_mode_combo.currentText()
        self.settings['scanner_device_id'] = self.scanner_combo.currentData() or ''
        self.settings['scan_format'] = self.scan_format_combo.currentText()
        self.settings['scan_folder'] = self.scan_folder_edit.text()
        self.settings['scanner_app_path'] = self.scanner_app_edit.text()
        self.settings['scanner_output_folder'] = self.scanner_output_folder_edit.text()

        # Backup settings
        self.settings['auto_backup_enabled'] = self.auto_backup_enabled.isChecked()
        self.settings['daily_backup_enabled'] = self.daily_backup_enabled.isChecked()
        self.settings['weekly_backup_enabled'] = self.weekly_backup_enabled.isChecked()
        self.settings['backup_location'] = self.backup_location.text()

        # Azure OCR settings
        self.settings['azure_di_endpoint'] = self.azure_endpoint.text().strip()
        self.settings['azure_di_key'] = self.azure_key.text().strip()

        # OpenAI AI Parser settings
        self.settings['openai_api_key'] = self.openai_key.text().strip()
        self.settings['openai_model'] = self.openai_model.currentText()
    
    def reset_to_defaults(self):
        """Reset all settings to default values."""
        reply = QMessageBox.question(
            self, "Reset Settings",
            "This will reset all settings to their default values.\n"
            "Are you sure you want to continue?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            # Reset to default settings
            self.settings = {
                "last_folder": DEFAULT_FOLDER_PATH,
                "quick_folders": []
            }
            self.load_current_settings()
    
    def accept(self):
        """Save settings and close dialog."""
        self.save_settings()
        self.parent_app.apply_settings(self.settings)
        # Reconfigure Azure OCR singleton
        try:
            azure_endpoint = self.settings.get('azure_di_endpoint', '')
            azure_key = self.settings.get('azure_di_key', '')
            if azure_endpoint and azure_key:
                from dmelogic.services.azure_ocr import configure_azure_ocr
                configure_azure_ocr(azure_endpoint, azure_key)
        except Exception:
            pass
        # Reconfigure OpenAI AI Parser singleton
        try:
            openai_key = self.settings.get('openai_api_key', '')
            openai_model = self.settings.get('openai_model', 'gpt-4o-mini')
            if openai_key:
                from dmelogic.services.ai_rx_parser import configure_openai
                configure_openai(openai_key, openai_model)
        except Exception:
            pass
        super().accept()


