    prescriber_saved = pyqtSignal(dict)
    
    def __init__(self, parent=None, prescriber_data=None):
        super().__init__(parent)
        self.prescriber_data = prescriber_data
        self.setWindowTitle("Add Prescriber" if prescriber_data is None else "Edit Prescriber")
        # Use Window flag to make it a separate top-level window that doesn't block
        self.setWindowFlags(
            Qt.WindowType.Window |
            Qt.WindowType.WindowMinimizeButtonHint |
            Qt.WindowType.WindowMaximizeButtonHint |
            Qt.WindowType.WindowCloseButtonHint
        )
        self.setModal(False)  # Non-modal so user can work on main window
