    def view_connected_orders(self):
        """Show all patients and orders connected to this prescriber."""
        # Get prescriber name and NPI from current fields
        prescriber_name = f"{self.last_name.text()}, {self.first_name.text()}"
        prescriber_npi = self.npi_number.text()
        
        # Show the orders dialog
        orders_dialog = PrescriberOrdersDialog(self.parent(), prescriber_name, prescriber_npi)
        orders_dialog.exec()
    
    def _update_fax_button_state(self):
        """Enable/disable fax button based on whether fax number is entered."""
        fax_number = self.fax.text().strip()
        # Remove common formatting to check if there are actual digits
        digits_only = ''.join(c for c in fax_number if c.isdigit())
        has_fax = len(digits_only) >= 10
        self.send_fax_btn.setEnabled(has_fax)
        if has_fax:
            self.send_fax_btn.setToolTip("Send a fax to this prescriber's fax number")
        else:
            self.send_fax_btn.setToolTip("Enter a fax number to enable sending")
    
    def _send_fax_to_prescriber(self):
        """Open SendFaxDialog to send a fax to this prescriber."""
        fax_number = self.fax.text().strip()
        if not fax_number:
            QMessageBox.warning(self, "No Fax Number", "Please enter a fax number for this prescriber.")
            return
        
        # Get prescriber name for context
        prescriber_name = f"{self.first_name.text()} {self.last_name.text()}".strip()
        
        try:
            from dmelogic.ui.dialogs.communications import SendFaxDialog
            
            # Get main window to pass username
            main_window = self.parent()
            username = getattr(main_window, 'username', '') if main_window else ''
            
            dialog = SendFaxDialog(
                parent=self,
                to_number=fax_number,
                patient_name=f"Prescriber: {prescriber_name}" if prescriber_name else "Prescriber",
                username=username,
                recipient_name=prescriber_name or ""
            )
            dialog.exec()
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to open fax dialog: {e}")

    def populate_fields(self):
        """Populate fields with existing prescriber data."""
        if not self.prescriber_data:
            return
            
        # Map database columns to form fields
        field_mapping = {
            1: self.first_name,
            2: self.last_name,
            3: self.title,
            4: self.npi_number,
            5: self.license_number,
            6: self.specialty,
            7: self.phone,
            8: self.fax,
            9: self.email,
            10: self.practice_name,
            11: self.address_line1,
            12: self.address_line2,
            13: self.city,
            14: self.state,
            15: self.zip_code,
            16: self.dea_number,
            17: self.tax_id,
            20: self.status  # status is at index 20
        }
        
        for idx, field in field_mapping.items():
            if idx < len(self.prescriber_data) and self.prescriber_data[idx]:
                value = str(self.prescriber_data[idx])
                if isinstance(field, QComboBox):
                    field.setCurrentText(value)
                else:
                    field.setText(value)
        
        # Handle notes field separately (index 21)
        if len(self.prescriber_data) > 21 and self.prescriber_data[21]:
            self.notes.setPlainText(str(self.prescriber_data[21]))
    
    def get_prescriber_data(self):
        """Get prescriber data from form fields."""
        return {
            'first_name': self.first_name.text().strip().upper(),
            'last_name': self.last_name.text().strip().upper(),
            'title': self.title.currentText().strip().upper(),
            'npi_number': self.npi_number.text().strip(),
            'license_number': self.license_number.text().strip(),
            'specialty': self.specialty.currentText().strip(),
            'phone': self.phone.text().strip(),
            'fax': self.fax.text().strip(),
            'email': self.email.text().strip(),
            'practice_name': self.practice_name.text().strip(),
            'address_line1': self.address_line1.text().strip(),
            'address_line2': self.address_line2.text().strip(),
            'city': self.city.text().strip(),
            'state': self.state.currentText().strip(),
            'zip_code': self.zip_code.text().strip(),
            'dea_number': self.dea_number.text().strip(),
            'tax_id': self.tax_id.text().strip(),
            'status': self.status.currentText(),
            'notes': self.notes.toPlainText().strip()
        }
    
    def accept(self):
        """Validate required fields before saving."""
        if not self.first_name.text().strip():
            QMessageBox.warning(self, "Validation Error", "First name is required!")
            self.first_name.setFocus()
            return
            
        if not self.last_name.text().strip():
            QMessageBox.warning(self, "Validation Error", "Last name is required!")
            self.last_name.setFocus()
            return
            
        # NPI validation (optional but if provided must be 10 digits)
        npi = self.npi_number.text().strip()
        if npi and (not npi.isdigit() or len(npi) != 10):
            QMessageBox.warning(self, "Validation Error", "NPI number must be exactly 10 digits!")
            self.npi_number.setFocus()
            return
            
        super().accept()

    def convert_to_uppercase(self, field, text):
        """Convert field text to uppercase automatically"""
        if text != text.upper():
            # Block signals to prevent infinite loop
            field.blockSignals(True)
            # Get cursor position
            cursor_pos = field.cursorPosition()
            # Set uppercase text
            field.setText(text.upper())
            # Restore cursor position
            field.setCursorPosition(cursor_pos)
            # Unblock signals
            field.blockSignals(False)

    def convert_to_uppercase_combo(self, combo, text):
        """Convert combo box text to uppercase automatically"""
        if text != text.upper():
            # Block signals to prevent infinite loop
            combo.blockSignals(True)
            # Get cursor position if available
            line_edit = combo.lineEdit()
            if line_edit:
                cursor_pos = line_edit.cursorPosition()
                # Set uppercase text
                combo.setEditText(text.upper())
                # Restore cursor position
                line_edit.setCursorPosition(cursor_pos)
            else:
                combo.setEditText(text.upper())
            # Unblock signals
            combo.blockSignals(False)
    
    def format_phone_number(self, field, text):
        """Auto-format phone number with dashes: 347-555-1234"""
        # Remove all non-digit characters
        digits = ''.join(c for c in text if c.isdigit())
        
        # Limit to 10 digits
        digits = digits[:10]
        
        # Build formatted phone number
        if len(digits) <= 3:
            formatted = digits
        elif len(digits) <= 6:
            formatted = f"{digits[:3]}-{digits[3:]}"
        else:
            formatted = f"{digits[:3]}-{digits[3:6]}-{digits[6:]}"
        
        # Only update if different (avoid infinite loop)
        if text != formatted:
            field.blockSignals(True)
            cursor_pos = field.cursorPosition()
            field.setText(formatted)
            # Adjust cursor position for added dashes
            new_pos = min(cursor_pos + (len(formatted) - len(text)), len(formatted))
            field.setCursorPosition(max(0, new_pos))
            field.blockSignals(False)
    
    def format_date_field(self, field, text):
        """Auto-format date with slashes: MM/DD/YYYY"""
        # Remove all non-digit characters
        digits = ''.join(c for c in text if c.isdigit())
        
        # Limit to 8 digits (MMDDYYYY)
        digits = digits[:8]
        
        # Build formatted date
        if len(digits) <= 2:
            formatted = digits
        elif len(digits) <= 4:
            formatted = f"{digits[:2]}/{digits[2:]}"
        else:
            formatted = f"{digits[:2]}/{digits[2:4]}/{digits[4:]}"
        
        # Only update if different (avoid infinite loop)
        if text != formatted:
            field.blockSignals(True)
            cursor_pos = field.cursorPosition()
            field.setText(formatted)
            # Adjust cursor position for added slashes
            new_pos = min(cursor_pos + (len(formatted) - len(text)), len(formatted))
            field.setCursorPosition(max(0, new_pos))
            field.blockSignals(False)
    
    def format_fax_number(self, field, text):
        """Auto-format fax number with dashes: 347-555-1234 (same as phone)"""
        self.format_phone_number(field, text)
    
    def on_lookup_npi(self):
        """Handle the NPI Registry lookup button click."""
        try:
            from prescriber_lookup_dialog import PrescriberLookupDialog
            
            lookup_dialog = PrescriberLookupDialog(parent=self)
            
            if lookup_dialog.exec() == QDialog.DialogCode.Accepted:
                prescriber_data = lookup_dialog.get_selected_prescriber()
                if prescriber_data:
                    self.fill_form_with_npi_data(prescriber_data)
                    QMessageBox.information(
                        self,
                        "Success",
                        f"Prescriber data loaded from NPI Registry:\n\n"
                        f"{prescriber_data.get('first_name', '')} {prescriber_data.get('last_name', '')}\n"
                        f"NPI: {prescriber_data.get('npi_number', '')}\n\n"
                        f"Please verify all information before saving."
                    )
        except ImportError as e:
            QMessageBox.warning(
                self,
                "Feature Unavailable",
                f"NPI Registry lookup requires additional modules.\n\n"
                f"Error: {e}\n\n"
                f"Please ensure 'requests' package is installed."
            )
        except Exception as e:
            QMessageBox.critical(
                self,
                "Lookup Error",
                f"Failed to perform NPI lookup:\n{e}"
            )
    
    def fill_form_with_npi_data(self, data):
        """Fill form fields with prescriber data from NPI lookup."""
        # Personal Information
        if data.get('first_name'):
            self.first_name.setText(data['first_name'].upper())
        if data.get('last_name'):
            self.last_name.setText(data['last_name'].upper())
        
        # Title/Credentials
        title = data.get('title', '')
        if title:
            index = self.title.findText(title.upper())
            if index >= 0:
                self.title.setCurrentIndex(index)
            else:
                self.title.setEditText(title.upper())
        
        # License & Identification
        if data.get('npi_number'):
            self.npi_number.setText(data['npi_number'])
        if data.get('license_number'):
            self.license_number.setText(data['license_number'])
        
        # Specialty
        specialty = data.get('specialty', '')
        if specialty:
            index = self.specialty.findText(specialty.upper())
            if index >= 0:
                self.specialty.setCurrentIndex(index)
            else:
                self.specialty.setEditText(specialty.upper())
        
        # Contact Information
        if data.get('phone'):
            self.phone.setText(data['phone'])
        if data.get('fax'):
            self.fax.setText(data['fax'])
        if data.get('email'):
            self.email.setText(data['email'])
        
        # Practice Information
        if data.get('practice_name'):
            self.practice_name.setText(data['practice_name'].upper())
        if data.get('address_line1'):
            self.address_line1.setText(data['address_line1'])
        if data.get('address_line2'):
            self.address_line2.setText(data['address_line2'])
        if data.get('city'):
            self.city.setText(data['city'])
        
        state = data.get('state', '')
        if state:
            index = self.state.findText(state.upper())
            if index >= 0:
                self.state.setCurrentIndex(index)
            else:
                self.state.setEditText(state.upper())
        
        if data.get('zip_code'):
            self.zip_code.setText(data['zip_code'])
        if data.get('tax_id'):
            self.tax_id.setText(data['tax_id'])
        
        # Add note about source
        existing_notes = self.notes.toPlainText()
        today = datetime.now().strftime("%Y-%m-%d")
        
        npi_note = f"Data retrieved from NPI Registry on {today}\n"
        if data.get('last_updated'):
            npi_note += f"Last updated in NPPES: {data['last_updated']}\n"
        
        if existing_notes:
            self.notes.setPlainText(f"{existing_notes}\n{npi_note}")
        else:
            self.notes.setPlainText(npi_note)


