        self.bill_amount.setPlaceholderText("0.00")
        
        financial_layout.addWidget(QLabel("Cost ($):"), 0, 0)
        financial_layout.addWidget(self.cost, 0, 1)
        financial_layout.addWidget(QLabel("Bill Amount ($):"), 0, 2)
        financial_layout.addWidget(self.bill_amount, 0, 3)
        
        # Inventory Information
        inventory_group = QGroupBox("Inventory Information")
        inventory_layout = QGridLayout(inventory_group)
        
        self.stock_quantity = QLineEdit()
        self.stock_quantity.setPlaceholderText("0")
        self.reorder_level = QLineEdit()
        self.reorder_level.setPlaceholderText("0")
