    def backfill_orders_patient_dob(self):
        """Ensure orders.patient_dob is populated for legacy rows by looking up
        the patient's DOB from the patients table via case-insensitive name match.

        This is idempotent and safe to run at startup. It addresses historical
        orders that were saved without DOB, which prevents patient history,
        prescribers, and ICD-10 views from matching.
        """
        try:
            orders_db = self.orders_database_file
            patients_db = self.patient_database_file

            # If databases somehow point to different folders, still proceed
            conn_o = sqlite3.connect(orders_db)
            cur_o = conn_o.cursor()
            cur_o.execute("SELECT COUNT(*) FROM orders WHERE patient_dob IS NULL OR TRIM(patient_dob) = ''")
            missing = cur_o.fetchone()[0]
            if missing == 0:
                conn_o.close()
                print("✅ Backfill skip: No orders with missing patient_dob")
                return

            # Read all patients into a dict for quick lookup (UPPER(last,first) -> dob)
            conn_p = sqlite3.connect(patients_db)
            cur_p = conn_p.cursor()
            cur_p.execute("SELECT UPPER(last_name), UPPER(first_name), dob FROM patients")
            rows = cur_p.fetchall()
            conn_p.close()
            name_to_dob = {}
            for ln, fn, dob in rows:
                if ln and fn and dob:
                    name_to_dob[(ln.strip(), fn.strip())] = dob.strip()

            # Fetch orders missing DOB
            cur_o.execute("SELECT id, patient_last_name, patient_first_name FROM orders WHERE patient_dob IS NULL OR TRIM(patient_dob) = ''")
            to_fix = cur_o.fetchall()
            updated = 0
            for oid, ln, fn in to_fix:
                key = (str(ln or '').strip().upper(), str(fn or '').strip().upper())
                dob = name_to_dob.get(key)
                if dob:
                    cur_o.execute("UPDATE orders SET patient_dob = ? WHERE id = ?", (dob, oid))
                    updated += 1
            conn_o.commit()
            conn_o.close()
            print(f"✅ Backfill complete: Updated {updated} of {missing} orders missing DOB")
        except Exception as e:
            print(f"❌ Backfill error: {e}")

    def get_order_id_from_display(self, display_text: str):
        """Resolve an order display string to the actual orders.id.

        Accepts formats like 'ORD-001' (root order) or 'ORD-001-R2' (refill #2
        of root order 001). Also handles continuation format '  ↳ ORD-001'.
        Returns the concrete row id from the orders table,
        or 0 if parsing/lookup fails.
        """
        try:
            if not display_text:
                return 0
            text = display_text.strip().upper()
            
            # Remove continuation arrow if present
            if "↳" in text:
                text = text.split("↳", 1)[1].strip()
            
            # Strip refill chain collapse indicators (▶/▼)
            for ch in ('▶', '▼', '►', '▾'):
                text = text.replace(ch, '')
            text = text.strip()
            
            if text.startswith("ORD-"):
                text = text[4:]
            refill_no = 0
            if "-R" in text:
                base, rpart = text.split("-R", 1)
                try:
                    refill_no = int((rpart or "0").strip())
                except Exception:
                    refill_no = 0
                text = base
            # Root id (as shown) -> int
            root_str = text.lstrip("0") or "0"
            root_id = int(root_str)

            # If no refill suffix, the display refers to the root order row
            if refill_no <= 0:
                return root_id

            # With a refill suffix, find the specific child row with
            # parent_order_id = root_id and refill_number = refill_no
            try:
                conn = sqlite3.connect(self.orders_db_path)
                cur = conn.cursor()
                cur.execute(
                    "SELECT id FROM orders WHERE parent_order_id = ? AND refill_number = ? ORDER BY id LIMIT 1",
                    (root_id, refill_no),
                )
                row = cur.fetchone()
                conn.close()
                if row and row[0]:
                    return int(row[0])
            except Exception:
                # On DB error, fall back to root id
                return root_id
            # If nothing matched, fall back to root id
            return root_id
        except Exception:
            return 0

    def format_order_number(self, order_id: int) -> str:
        """Return display number 'ORD-<root_id padded>' with optional '-R#'.

        - For non-refill orders: ORD-001
        - For refills: uses the root order id + '-R<refill_number>', e.g., ORD-001-R1
        """
        try:
            if not order_id:
                return ""
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            cur.execute("SELECT COALESCE(parent_order_id,0), COALESCE(refill_number,0) FROM orders WHERE id = ?", (order_id,))
            row = cur.fetchone()
            conn.close()
            if not row:
                return f"ORD-{str(order_id).zfill(3)}"
            parent_id, refill_no = int(row[0] or 0), int(row[1] or 0)
            root_id = parent_id if parent_id else order_id
            base = f"ORD-{str(root_id).zfill(3)}"
            return base + (f"-R{refill_no}" if refill_no > 0 else "")
        except Exception:
            return f"ORD-{str(order_id).zfill(3)}"

    def format_date_display(self, value):
        """Return a date string formatted as MM/DD/YYYY for UI/report display.

        Accepts QDate, datetime/date-like strings (e.g., 'YYYY-MM-DD', 'YYYY/MM/DD',
        'MM/DD/YYYY', 'MM-DD-YYYY', optionally with time), or None/empty.
        If parsing fails, returns the original string.
        """
        try:
            if value is None:
                return ""
            # QDate support
            if isinstance(value, QDate):
                return value.toString("MM/dd/yyyy")
            s = str(value).strip()
            if not s:
                return ""
            # Remove time portion if present
            if " " in s:
                s_part = s.split(" ", 1)[0]
            elif "T" in s:
                s_part = s.split("T", 1)[0]
            else:
                s_part = s

            from datetime import datetime as _dt
            for fmt in ("%Y-%m-%d", "%Y/%m/%d", "%m/%d/%Y", "%m-%d-%Y"):
                try:
                    dt = _dt.strptime(s_part, fmt)
                    return dt.strftime("%m/%d/%Y")
                except Exception:
                    pass
            # Try full datetime patterns as a fallback
            for fmt in ("%Y-%m-%d %H:%M:%S", "%Y/%m/%d %H:%M:%S", "%m/%d/%Y %H:%M:%S", "%Y-%m-%dT%H:%M:%S"):
                try:
                    dt = _dt.strptime(s, fmt)
                    return dt.strftime("%m/%d/%Y")
                except Exception:
                    pass
            return s
        except Exception:
            return str(value) if value is not None else ""

    def ensure_patient_documents_table(self):
        """Ensure the patient_documents table exists for linking documents to patients."""
        try:
            if not hasattr(self, 'patient_database_file'):
                print("⚠️ patient_database_file not set, cannot ensure patient_documents table")
                return
            
            conn = sqlite3.connect(self.patient_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                CREATE TABLE IF NOT EXISTS patient_documents (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    patient_id INTEGER NOT NULL,
                    description TEXT,
                    file_path TEXT NOT NULL,
                    original_filename TEXT,
                    added_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (patient_id) REFERENCES patients(id) ON DELETE CASCADE
                )
            """)
            conn.commit()
            conn.close()
            print("✅ patient_documents table ensured")
        except Exception as e:
            print(f"⚠️ Error ensuring patient_documents table: {e}")

    def normalize_dob_digits(self, s: str) -> str:
        """Return only the digits from a DOB string. Useful for comparing across formats.

        Examples:
        - '03/12/1964' -> '03121964'
        - '1964-03-12' -> '19640312'
        - '1964-03-12 00:00:00' -> '19640312000000' (we only pass the digits that exist)
        """
        try:
            if s is None:
                return ""
            return "".join(ch for ch in str(s) if ch.isdigit())
        except Exception:
            return ""

    def compute_order_billed_total(self, order_id: int) -> float:
        """Compute the billed total for an order as sum(qty_dispensed * bill_amount).

        bill_amount is stored in the inventory database as 'retail_price'.
        Fallbacks per line if inventory price is missing:
          1) use order_items.total when numeric
          2) else use qty * cost_ea when numeric
          3) else 0.0
        """
        try:
            if not order_id:
                return 0.0

            # Read order items
            conn_o = sqlite3.connect(self.orders_db_path)
            cur_o = conn_o.cursor()
            cur_o.execute(
                """
                SELECT COALESCE(hcpcs_code,''), COALESCE(description,''), COALESCE(qty,''), COALESCE(total,''), COALESCE(cost_ea,'')
                FROM order_items WHERE order_id = ?
                """,
                (order_id,),
            )
            items = cur_o.fetchall()
            conn_o.close()

            total_amount = 0.0
            for hcpcs, desc_val, qty_val, total_val, cost_ea in items:
                # Parse qty
                try:
                    qty = float(str(qty_val).strip()) if str(qty_val).strip() != '' else 0.0
                except Exception:
                    qty = 0.0

                price = None
                # Try inventory price (prefer exact HCPCS + Description, then by HCPCS only; pick most recently updated)
                try:
                    if hasattr(self, 'inventory_database_file') and self.inventory_database_file:
                        conn_i = sqlite3.connect(self.inventory_database_file)
                        cur_i = conn_i.cursor()
                        # Try HCPCS + Description exact match first
                        cur_i.execute(
                            """
                            SELECT COALESCE(retail_price,0) FROM inventory
                            WHERE UPPER(hcpcs_code)=UPPER(?) AND UPPER(description)=UPPER(?)
                            ORDER BY datetime(COALESCE(updated_date, created_date)) DESC, item_id DESC
                            LIMIT 1
                            """,
                            (hcpcs or '', desc_val or ''),
                        )
                        row = cur_i.fetchone()
                        if not row or row[0] in (None, ''):
                            # Fallback to HCPCS only, prefer most recently updated
                            cur_i.execute(
                                """
                                SELECT COALESCE(retail_price,0) FROM inventory
                                WHERE UPPER(hcpcs_code)=UPPER(?)
                                ORDER BY datetime(COALESCE(updated_date, created_date)) DESC, item_id DESC
                                LIMIT 1
                                """,
                                (hcpcs or '',),
                            )
                            row = cur_i.fetchone()
                        conn_i.close()
                        if row is not None:
                            price = float(row[0] or 0)
                except Exception:
                    price = None

                if price is None or price == 0:
                    # Fallback to order_items.total (already a line amount)
                    try:
                        if str(total_val).strip() != '':
                            line_total = float(total_val)
                            total_amount += line_total
                            continue
                    except Exception:
                        pass
                    # Fallback to qty * cost_ea
                    try:
                        ce = float(str(cost_ea).strip()) if str(cost_ea).strip() != '' else 0.0
                        total_amount += qty * ce
                        continue
                    except Exception:
                        total_amount += 0.0
                        continue

                # Preferred path: qty * inventory retail_price
                total_amount += qty * float(price)

            return float(total_amount)
        except Exception as e:
            print(f"compute_order_billed_total error for order {order_id}: {e}")
            return 0.0

