    def _start_message_notifier(self):
        """Initialize and start the message notification service."""
        try:
            from dmelogic.services.ringcentral_service import get_ringcentral_service
            from dmelogic.services.message_notifier import MessageNotifier
            
            # Get the RingCentral service
            service = get_ringcentral_service()
            if not service or not service.is_connected:
                print("Message notifier: RingCentral not connected, skipping")
                return
            
            # Stop existing notifier if any
            if self._message_notifier:
                self._message_notifier.stop()
            
            # Create new notifier
            self._message_notifier = MessageNotifier(self, check_interval_ms=180000)  # 3 minutes
            self._message_notifier.set_service(service)
            self._message_notifier.set_inbox_callback(self.show_communications_inbox)
            
            # Connect signals
            self._message_notifier.unread_count_changed.connect(self._on_unread_count_changed)
            self._message_notifier.new_sms_received.connect(self._on_new_sms)
            self._message_notifier.new_fax_received.connect(self._on_new_fax)
            
            # Set up system tray (use app icon if available)
            icon_path = os.path.join(os.path.dirname(__file__), 'assets', 'DMELogic Icon.ico')
            self._message_notifier.setup_tray_icon(icon_path)
            
            # Start polling
            self._message_notifier.start()
            print("✅ Message notifier started")
            
        except Exception as e:
            print(f"⚠️ Failed to start message notifier: {e}")
            import traceback
            traceback.print_exc()
    
    def _on_unread_count_changed(self, counts: dict):
        """Update inbox menu badge when unread count changes."""
        self._unread_counts = counts
        total = counts.get('total', 0)
        
        # Update inbox action text with badge
        if self._inbox_action:
            if total > 0:
                self._inbox_action.setText(f'📬 Inbox ({total})')
            else:
                self._inbox_action.setText('📬 Inbox')
    
    def _on_new_sms(self, messages: list):
        """Handle new SMS messages received."""
        count = len(messages)
        print(f"📱 Received {count} new SMS message(s)")
    
    def _on_new_fax(self, messages: list):
        """Handle new fax messages received."""
        count = len(messages)
        print(f"📠 Received {count} new fax(es)")
    
    def _stop_message_notifier(self):
        """Stop the message notification service."""
        if self._message_notifier:
            self._message_notifier.stop()
            self._message_notifier = None

    def edit_order_from_patient_dialog(self, orders_table):
        """Edit selected order from patient dialog order history"""
        current_row = orders_table.currentRow()
        if current_row < 0:
            return
        
        # Get order ID from the first column (format: "ORD-036")
        order_item = orders_table.item(current_row, 0)
        if not order_item:
            return
        
        order_text = order_item.text()
        # Extract numeric ID from "ORD-036" format
        try:
            order_id = int(order_text.replace("ORD-", ""))
            # Open the modern Order Editor
            self.open_order_editor(order_id)
        except Exception as e:
            QMessageBox.warning(self, "Error", f"Could not open order for editing: {e}")
    
    def view_patient_orders(self):
        """View orders for selected patient"""
        current_row = self.patients_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a patient first.")
            return
        
        # TODO: Switch to Orders tab and filter by patient
        QMessageBox.information(self, "View Orders", "Switching to Orders tab...")
    
    def view_patient_documents(self):
        """View documents for selected patient"""
        current_row = self.patients_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a patient first.")
            return
        
        # TODO: Open document viewer for selected patient
        QMessageBox.information(self, "View Documents", "Opening document viewer...")
    
    def new_order_for_patient(self):
        """Create new order for selected patient"""
        current_row = self.patients_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a patient first.")
            return
        
        # Get patient data from selected row
        patient = None
        try:
            last_item = self.patients_table.item(current_row, 0)
            first_item = self.patients_table.item(current_row, 1)
            dob_item = self.patients_table.item(current_row, 2)
            phone_item = self.patients_table.item(current_row, 3)
            
            if last_item and first_item:
                # Extract patient_id from UserRole data stored in first column
                patient_id = 0
                if last_item:
                    stored_id = last_item.data(Qt.ItemDataRole.UserRole)
                    if stored_id is not None:
                        patient_id = int(stored_id)
                
                patient = {
                    "patient_id": patient_id,
                    "name": f"{last_item.text()}, {first_item.text()}".strip(", "),
                    "dob": dob_item.text() if dob_item else "",
                    "phone": phone_item.text() if phone_item else "",
                }
        except Exception:
            patient = None
        
        # Call the wizard (inherited from MainWindow)
        if hasattr(self, 'open_new_order_wizard'):
            self.open_new_order_wizard(patient_context=patient)
        else:
            QMessageBox.information(self, "New Order", "Order wizard not available.")
    
    def delete_patient_from_table(self):
        """Delete selected patient"""
        current_row = self.patients_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a patient first.")
            return
        
        last_item = self.patients_table.item(current_row, 0)
        first_item = self.patients_table.item(current_row, 1)
        if not last_item or not first_item:
            return
        
        reply = QMessageBox.question(
            self, "Confirm Delete",
            f"Are you sure you want to delete {first_item.text()} {last_item.text()}?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            # TODO: Delete from database
            self.patients_table.removeRow(current_row)
            QMessageBox.information(self, "Deleted", "Patient deleted successfully.")

