    def load_clinics(self):
        """Load clinics from database into table."""
        try:
            if not hasattr(self, 'clinics_database_file') or not self.clinics_database_file:
                print("⚠️ Clinics database not configured")
                return
            
            conn = sqlite3.connect(self.clinics_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT id, clinic_name, address_line1, city, phone,
                       contact_person, contact_position, contact_phone, contact_extension, status
                FROM clinics
                ORDER BY clinic_name
            """)
            rows = cursor.fetchall()
            conn.close()
            
            self.clinic_table.setRowCount(len(rows))
            for i, row in enumerate(rows):
                for j, val in enumerate(row):
                    item = QTableWidgetItem(str(val) if val else '')
                    if j == 0:  # ID column - not editable
                        item.setFlags(item.flags() & ~Qt.ItemFlag.ItemIsEditable)
                    self.clinic_table.setItem(i, j, item)
            
            self.clinic_status.setText(f"Loaded {len(rows)} clinics")
            
            # Also refresh clinic combos in order dialogs
            self._refresh_clinic_combos()
            
        except Exception as e:
            print(f"⚠️ Error loading clinics: {e}")
            self.clinic_status.setText(f"Error: {e}")

    def _refresh_clinic_combos(self):
        """Refresh clinic combo boxes in any open order dialogs."""
        try:
            if hasattr(self, 'clinic_combo'):
                current_text = self.clinic_combo.currentText()
                self.clinic_combo.clear()
                self.clinic_combo.addItem("")  # Empty option
                
                conn = sqlite3.connect(self.clinics_database_file)
                cursor = conn.cursor()
                cursor.execute("SELECT id, clinic_name, city FROM clinics WHERE status='Active' ORDER BY clinic_name")
                for row in cursor.fetchall():
                    clinic_id, name, city = row
                    display = f"{name}" + (f" ({city})" if city else "")
                    self.clinic_combo.addItem(display, clinic_id)
                conn.close()
                
                # Restore selection
                idx = self.clinic_combo.findText(current_text)
                if idx >= 0:
                    self.clinic_combo.setCurrentIndex(idx)
        except Exception as e:
            print(f"⚠️ Error refreshing clinic combos: {e}")

    def search_clinics(self, text):
        """Filter clinics table based on search text."""
        search_text = text.lower()
        for row in range(self.clinic_table.rowCount()):
            match = False
            for col in range(self.clinic_table.columnCount()):
                item = self.clinic_table.item(row, col)
                if item and search_text in item.text().lower():
                    match = True
                    break
            self.clinic_table.setRowHidden(row, not match)

    def add_clinic(self):
        """Open dialog to add a new clinic."""
        dialog = ClinicDialog(self)
        
        def on_save():
            try:
                clinic_data = dialog.get_clinic_data()
                
                conn = sqlite3.connect(self.clinics_database_file)
                cursor = conn.cursor()
                
                cursor.execute("""
                    INSERT INTO clinics (
                        clinic_name, address_line1, address_line2, city, state, zip_code,
                        phone, fax, email, contact_person, contact_position, contact_phone,
                        contact_extension, notes, status
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (
                    clinic_data['clinic_name'].upper(),
                    clinic_data['address_line1'],
                    clinic_data['address_line2'],
                    clinic_data['city'],
                    clinic_data['state'],
                    clinic_data['zip_code'],
                    clinic_data['phone'],
                    clinic_data['fax'],
                    clinic_data['email'],
                    clinic_data['contact_person'].upper(),
                    clinic_data['contact_position'],
                    clinic_data['contact_phone'],
                    clinic_data['contact_extension'],
                    clinic_data['notes'],
                    clinic_data['status']
                ))
                
                conn.commit()
                conn.close()
                
                self.load_clinics()
                print(f"✅ Added clinic: {clinic_data['clinic_name']}")
                
            except Exception as e:
                print(f"Error adding clinic: {e}")
                QMessageBox.critical(self, "Error", f"Failed to add clinic: {e}")
        
        dialog.accepted.connect(on_save)
        
        if hasattr(self, 'register_child_window'):
            self.register_child_window(dialog)
        
        dialog.show()
        dialog.raise_()
        dialog.activateWindow()

    def edit_clinic(self):
        """Edit selected clinic."""
        current_row = self.clinic_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a clinic to edit.")
            return
        
        clinic_id = int(self.clinic_table.item(current_row, 0).text())
        
        try:
            conn = sqlite3.connect(self.clinics_database_file)
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM clinics WHERE id = ?", (clinic_id,))
            row = cursor.fetchone()
            conn.close()
            
            if not row:
                QMessageBox.warning(self, "Error", "Clinic not found.")
                return
            
            dialog = ClinicDialog(self, clinic_data=row)
            
            def on_save():
                try:
                    clinic_data = dialog.get_clinic_data()
                    
                    conn = sqlite3.connect(self.clinics_database_file)
                    cursor = conn.cursor()
                    
                    cursor.execute("""
                        UPDATE clinics SET
                            clinic_name=?, address_line1=?, address_line2=?, city=?, state=?, zip_code=?,
                            phone=?, fax=?, email=?, contact_person=?, contact_position=?, contact_phone=?,
                            contact_extension=?, notes=?, status=?, updated_date=CURRENT_TIMESTAMP
                        WHERE id=?
                    """, (
                        clinic_data['clinic_name'].upper(),
                        clinic_data['address_line1'],
                        clinic_data['address_line2'],
                        clinic_data['city'],
                        clinic_data['state'],
                        clinic_data['zip_code'],
                        clinic_data['phone'],
                        clinic_data['fax'],
                        clinic_data['email'],
                        clinic_data['contact_person'].upper(),
                        clinic_data['contact_position'],
                        clinic_data['contact_phone'],
                        clinic_data['contact_extension'],
                        clinic_data['notes'],
                        clinic_data['status'],
                        clinic_id
                    ))
                    
                    conn.commit()
                    conn.close()
                    
                    self.load_clinics()
                    print(f"✅ Updated clinic: {clinic_data['clinic_name']}")
                    
                except Exception as e:
                    print(f"Error updating clinic: {e}")
                    QMessageBox.critical(self, "Error", f"Failed to update clinic: {e}")
            
            dialog.accepted.connect(on_save)
            
            if hasattr(self, 'register_child_window'):
                self.register_child_window(dialog)
            
            dialog.show()
            dialog.raise_()
            dialog.activateWindow()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load clinic: {e}")

    def delete_clinic(self):
        """Delete selected clinic."""
        current_row = self.clinic_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a clinic to delete.")
            return
        
        clinic_name = self.clinic_table.item(current_row, 1).text()
        clinic_id = int(self.clinic_table.item(current_row, 0).text())
        
        reply = QMessageBox.question(
            self, "Confirm Delete",
            f"Are you sure you want to delete '{clinic_name}'?",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            try:
                conn = sqlite3.connect(self.clinics_database_file)
                cursor = conn.cursor()
                cursor.execute("DELETE FROM clinics WHERE id = ?", (clinic_id,))
                conn.commit()
                conn.close()
                
                self.load_clinics()
                QMessageBox.information(self, "Deleted", f"Clinic '{clinic_name}' deleted successfully.")
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to delete clinic: {e}")

    def add_new_clinic_from_order(self):
        """Add new clinic from order dialog - opens clinic dialog."""
        self.add_clinic()

    def create_patient_list_panel(self):
        """Create patient list panel"""
        panel = QWidget()
