    def load_dme_inventory_data(self):
        """Load inventory data from database into the DME inventory table."""
        try:
            # If the DME Inventory tab/table hasn't been created in this window, skip safely
            if not hasattr(self, 'dme_inventory_table'):
                return
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT item_id, hcpcs_code, description, category, cost, 
                       retail_price, brand, supplier, stock_quantity, reorder_level
                FROM inventory 
                ORDER BY description
            """)
            items = cursor.fetchall()
            conn.close()
            
            self.dme_inventory_table.setRowCount(len(items))
            for row, item in enumerate(items):
                for col, value in enumerate(item):
                    # Format currency columns
                    if col in [4, 5] and value is not None:  # Cost and Bill Amount
                        display_value = f"${float(value):.2f}"
                    else:
                        display_value = str(value) if value is not None else ""
                    
                    self.dme_inventory_table.setItem(row, col, QTableWidgetItem(display_value))
            
        except Exception as e:
            # Fallback sample data if database fails
            sample_inventory = [
                ["1", "A4495", "STOCKING THIGH-HIGH 20-30MMHG CLOSED TOE BEIGE LARGE", "COMPRESSION", "$5.25", "$15.12", "VIVE", "VIVE", "1", "4"],
                ["2", "A4495", "STOCKING THIGH-HIGH 20-30MMHG CLOSED TOE BEIGE MEDIUM", "COMPRESSION", "$5.25", "$15.12", "VIVE", "VIVE", "1", "4"],
                ["3", "A4495", "STOCKING THIGH-HIGH 20-30MMHG CLOSED TOE BEIGE SMALL", "COMPRESSION", "$5.25", "$15.12", "VIVE", "VIVE", "1", "4"]
            ]
            
            self.dme_inventory_table.setRowCount(len(sample_inventory))
            for row, item in enumerate(sample_inventory):
                for col, value in enumerate(item):
                    self.dme_inventory_table.setItem(row, col, QTableWidgetItem(str(value)))
        
        # Set specific column widths to ensure all columns are visible
        column_widths = [80, 80, 300, 120, 80, 100, 150, 150, 80, 120]
        for i, width in enumerate(column_widths):
            if hasattr(self, 'dme_inventory_table') and i < self.dme_inventory_table.columnCount():
                self.dme_inventory_table.setColumnWidth(i, width)
    
    def edit_dme_inventory_item(self):
        """Edit selected inventory item from DME inventory tab."""
        current_row = self.dme_inventory_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an inventory item to edit.")
            return
        
        # Get item ID from the first column
        item_id = self.dme_inventory_table.item(current_row, 0).text()
        
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM inventory WHERE item_id = ?", (item_id,))
            item_data = cursor.fetchone()
            conn.close()
            
            if item_data:
                dialog = InventoryItemDialog(self, item_data)
                if dialog.exec() == QDialog.DialogCode.Accepted:
                    updated_data = dialog.get_item_data()
                    
                    conn = sqlite3.connect(self.inventory_database_file)
                    cursor = conn.cursor()
                    
                    cursor.execute(
                        """
                        UPDATE inventory SET
                            hcpcs_code = ?, description = ?, category = ?, cost = ?,
                            retail_price = ?, stock_quantity = ?, reorder_level = ?,
                            supplier = ?, notes = ?, item_number = ?, updated_date = datetime('now')
                        WHERE item_id = ?
                        """,
                        (
                            updated_data['hcpcs_code'], updated_data['description'],
                            updated_data['category'], updated_data['cost'],
                            updated_data['bill_amount'], updated_data['stock_quantity'],
                            updated_data['reorder_level'], updated_data['source'],
                            updated_data['notes'], updated_data.get('item_number', ''), item_id,
                        ),
                    )
                    
                    conn.commit()
                    conn.close()
                    
                    # Refresh both inventory tables
                    if hasattr(self, 'load_inventory_data'):
                        self.load_inventory_data()
                    self.load_dme_inventory_data()
                    # Track supplier usage/name in suppliers database
                    try:
                        if hasattr(self, 'save_supplier_name'):
                            self.save_supplier_name(updated_data.get('source', ''))
                    except Exception:
                        pass
                    # Track category in categories master
                    try:
                        if hasattr(self, 'save_category_name'):
                            self.save_category_name(updated_data.get('category', ''))
                    except Exception:
                        pass
                    QMessageBox.information(self, "Success", "Inventory item updated successfully!")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to edit inventory item: {e}")

    def delete_dme_inventory_item(self):
        """Delete selected inventory item from DME inventory tab."""
        current_row = self.dme_inventory_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an inventory item to delete.")
            return
        
        # Get item details for confirmation
        item_id = self.dme_inventory_table.item(current_row, 0).text()
        description = self.dme_inventory_table.item(current_row, 2).text()
        
        # Confirm deletion
        reply = QMessageBox.question(
            self, "Confirm Deletion", 
            f"Are you sure you want to delete this inventory item?\n\n"
            f"Item ID: {item_id}\n"
            f"Description: {description}\n\n"
            f"This action cannot be undone.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            try:
                conn = sqlite3.connect(self.inventory_database_file)
                cursor = conn.cursor()
                
                # Delete the item from database
                cursor.execute("DELETE FROM inventory WHERE item_id = ?", (item_id,))
                
                conn.commit()
                conn.close()
                
                # Refresh main inventory table (and DME table only if present)
                self.load_inventory_data()
                if hasattr(self, 'dme_inventory_table'):
                    self.load_dme_inventory_data()
                QMessageBox.information(self, "Success", "Inventory item deleted successfully!")
                
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to delete inventory item: {e}")

    def create_orders_tracking_tab(self):
        """Create the Orders & Tracking tab with modern layout using build_orders_tab"""
        # Import the build function from main_window
        from dmelogic.ui.main_window import build_orders_tab
        
        # First, create and configure the orders table
        self.orders_table = QTableWidget()
        self.orders_table.setAlternatingRowColors(True)
        
        # Enable multi-select for batch operations
        self.orders_table.setSelectionMode(QTableWidget.SelectionMode.ExtendedSelection)
        self.orders_table.setSelectionBehavior(QTableWidget.SelectionBehavior.SelectRows)
        
        # Set up table columns
        columns = [
            "Order #", "Patient", "DOB", "HCPCS", "Description",
            "Qty Disp.", "Refills", "Days", "Order Date",
            "Refill Due Date", "Del/PU Date", "Status", "Tracking #", "Notes", "Paid", "Paid Date"
        ]
        self.orders_table.setColumnCount(len(columns))
        self.orders_table.setHorizontalHeaderLabels(columns)
        
        # Disable built-in sorting to keep order items grouped together
        # Items must stay with their parent order when sorting
        self.orders_table.setSortingEnabled(False)
        
        # Start with empty table - orders will be loaded from database
        self.orders_table.setRowCount(0)
        
        # Auto-resize columns
        self.orders_table.resizeColumnsToContents()
        
        # Enable custom sorting that keeps order items grouped
        header = self.orders_table.horizontalHeader()
        header.setSectionsClickable(True)
        header.sectionClicked.connect(self.sort_orders_table)
        self._orders_sort_column = 0
        self._orders_sort_order = Qt.SortOrder.AscendingOrder
        
        # Enable double-click to edit
        self.orders_table.doubleClicked.connect(self.on_orders_double_clicked)
        
        # Enable cell click for inline editing of Paid Date and Delivery Date
        self.orders_table.cellClicked.connect(self.handle_cell_click)
        
        # Watch for edits (Paid Yes/No)
        try:
            self.orders_table.itemChanged.connect(self.on_orders_item_changed)
        except Exception:
            pass
        
        # Use Yes/No dropdown for Paid column (now at index 15)
        try:
            self._orders_yesno_delegate = YesNoDelegate(self.orders_table)
            self.orders_table.setItemDelegateForColumn(14, self._orders_yesno_delegate)
        except Exception:
            pass

        # Use color-preserving delegate for Refill Due Date column (index 9)
        # so programmatic setForeground() isn't overridden by QSS
        try:
            self._refill_due_delegate = ColorPreservingDelegate(self.orders_table)
            self.orders_table.setItemDelegateForColumn(9, self._refill_due_delegate)
        except Exception:
            pass
            pass
        
        # Build the new tab layout with filter bar and action panel
        orders_tab = build_orders_tab(self)
        
        # Wire up all the action buttons to existing handlers
        if hasattr(self, 'btn_new_order'):
            try:
                self.btn_new_order.clicked.disconnect()
            except Exception:
                pass
        self.btn_edit_order.clicked.connect(self._handle_edit_order_button)
        self.btn_update_status.clicked.connect(self.update_order_status)
        self.btn_delivery_report.clicked.connect(self.show_delivery_report)
        self.btn_clear_delivery.clicked.connect(self.clear_delivery_date)
        self.btn_process_refill.clicked.connect(self.process_refill)
        if hasattr(self, "btn_reverse_refill"):
            self.btn_reverse_refill.clicked.connect(self.reverse_refill_order)
        if hasattr(self, "btn_refill_request"):
            self.btn_refill_request.clicked.connect(lambda: self.create_refill_request_for_order())
        if hasattr(self, "btn_batch_delivered"):
            self.btn_batch_delivered.clicked.connect(self.batch_mark_delivered)
        if hasattr(self, "btn_batch_billed"):
            self.btn_batch_billed.clicked.connect(self.batch_mark_billed)
        self.btn_export_portal.clicked.connect(self.export_order_to_state_portal)
        self.btn_epaces.clicked.connect(self.open_epaces_helper)
        self.btn_print_delivery_ticket.clicked.connect(self.print_delivery_ticket_for_selected_order)
        self.btn_generate_1500.clicked.connect(self.generate_1500_for_selected)
        self.btn_print_1500.clicked.connect(self.print_1500_for_selected_order)
        self.btn_delete_order.clicked.connect(self.delete_order)
        self.btn_link_patient.clicked.connect(self.show_link_order_dialog)
        if hasattr(self, "btn_import_rx"):
            self.btn_import_rx.clicked.connect(self._open_rx_import)
        
        # Connect table selection to update summary
        self.orders_table.selectionModel().currentRowChanged.connect(
            lambda current, previous: self.on_order_selected(current.row())
        )
        
        self.main_tabs.addTab(orders_tab, "Orders")
        
        # Load orders from database
        self.load_orders()
    
