        header.setFont(header_font)
        header.setStyleSheet("color: #ffffff;")
        main_layout.addWidget(header)

        # ===== Toolbar – report selectors + date range =====
        toolbar_row = QHBoxLayout()
        toolbar_row.setSpacing(6)

        def make_primary_button(text: str) -> QPushButton:
            btn = QPushButton(text)
            btn.setCursor(Qt.CursorShape.PointingHandCursor)
            btn.setMinimumWidth(110)
            btn.setStyleSheet("""
                QPushButton {
                    background-color: #1976d2;
                    color: white;
                    border-radius: 4px;
                    padding: 4px 10px;
                }
                QPushButton:hover {
                    background-color: #1565c0;
                }
            """)
            return btn

        # Report buttons
        patient_btn = make_primary_button("Patient Report")
        order_btn = make_primary_button("Order Report")
        recon_btn = make_primary_button("Reconciliation")
        delivery_btn = make_primary_button("Delivery Report")
        invoice_btn = make_primary_button("Invoice Report")
        inventory_btn = make_primary_button("Inventory Report")
        billing_btn = make_primary_button("Billing Report")
        profit_btn = make_primary_button("Profit Report")
        ar_aging_btn = make_primary_button("AR Aging")
        refills_btn = make_primary_button("Refills Due")
