    def update_kpis(self):
        """Update KPI cards with real-time data from databases"""
        try:
            if not hasattr(self, 'orders_db_path') or not hasattr(self, 'inventory_db_path'):
                return
            
            import sqlite3
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()

            # KPI 1: Orders created this month
            cur.execute("""
                SELECT COUNT(*) FROM orders
                WHERE strftime('%Y-%m', order_date) = strftime('%Y-%m', 'now')
            """)
            orders_this_month = cur.fetchone()[0]

            # KPI 2: Pending refills
            cur.execute("""
                SELECT COUNT(*) FROM orders
                WHERE order_status = 'Pending' AND refill_due_date <= date('now')
            """)
            pending_refills = cur.fetchone()[0]

            # KPI 3: Claims awaiting billing
            cur.execute("""
                SELECT COUNT(*) FROM orders
                WHERE billed = 0
            """)
            claims_unbilled = cur.fetchone()[0]

            conn.close()

            # KPI 4: Low stock items
            conn_inv = sqlite3.connect(self.inventory_db_path)
            cur_inv = conn_inv.cursor()
            cur_inv.execute("""
                SELECT COUNT(*) FROM inventory
                WHERE stock_quantity <= reorder_level
            """)
            low_stock_items = cur_inv.fetchone()[0]
            conn_inv.close()

            # Update UI
            self.kpi_titles[0].setText("Orders This Month")
            self.kpi_values[0].setText(str(orders_this_month))
            
            self.kpi_titles[1].setText("Pending Refills")
            self.kpi_values[1].setText(str(pending_refills))
            
            self.kpi_titles[2].setText("Unbilled Claims")
            self.kpi_values[2].setText(str(claims_unbilled))
            
            self.kpi_titles[3].setText("Low Stock Items")
            self.kpi_values[3].setText(str(low_stock_items))

        except Exception as e:
            print(f"Error updating KPIs: {e}")

    def refresh_reports_overview(self):
        """
        Populate the KPI cards with a live overview snapshot when the Reports
        tab is opened, even before any specific report is generated.

        Metrics:
        - Total Orders
        - Pending Orders
        - Refills Due (refill_due_date <= today)
        - Inventory items at/below reorder level
        """
        try:
            import sqlite3, os
            from datetime import date

            # Small helper to update the 4 KPI cards
            def set_kpis(labels_vals):
                display = list(labels_vals)[:4]
                while len(display) < 4:
                    display.append(("", "-"))
                for i, (label, val) in enumerate(display):
                    if i < len(getattr(self, "kpi_titles", [])):
                        self.kpi_titles[i].setText(str(label))
                    if i < len(getattr(self, "kpi_values", [])):
                        self.kpi_values[i].setText(str(val))

            total_orders = 0
            pending_orders = 0
            due_refills = 0
            low_stock_items = 0

            # --- Orders / refills ---
            orders_path = getattr(self, "orders_database_file", None)
            if orders_path and os.path.exists(orders_path):
                conn = sqlite3.connect(orders_path)
                cur = conn.cursor()

                # Total orders
                cur.execute("SELECT COUNT(*) FROM orders")
                row = cur.fetchone()
                total_orders = int(row[0]) if row and row[0] is not None else 0

                # Pending orders (status column exists in your schema)
                try:
                    cur.execute("SELECT COUNT(*) FROM orders WHERE status = 'Pending'")
                    row = cur.fetchone()
                    pending_orders = int(row[0]) if row and row[0] is not None else 0
                except Exception:
                    pending_orders = 0

                # Refills due (refill_due_date column, date <= today)
                try:
                    cur.execute(
                        "SELECT COUNT(*) FROM orders "
                        "WHERE refill_due_date IS NOT NULL "
                        "AND date(refill_due_date) <= date('now')"
                    )
                    row = cur.fetchone()
                    due_refills = int(row[0]) if row and row[0] is not None else 0
                except Exception:
                    due_refills = 0

                conn.close()

            # --- Inventory low stock snapshot ---
            inv_path = getattr(self, "inventory_database_file", None)
            if inv_path and os.path.exists(inv_path):
                conn = sqlite3.connect(inv_path)
                cur = conn.cursor()
                try:
                    cur.execute(
                        "SELECT COUNT(*) FROM inventory "
                        "WHERE stock_quantity IS NOT NULL "
                        "AND reorder_level IS NOT NULL "
                        "AND stock_quantity <= reorder_level "
                        "AND reorder_level > 0"
                    )
                    row = cur.fetchone()
                    low_stock_items = int(row[0]) if row and row[0] is not None else 0
                except Exception:
                    low_stock_items = 0
                conn.close()

            # Push values to the KPI cards
            set_kpis([
                ("Total Orders", total_orders),
                ("Pending Orders", pending_orders),
                ("Refills Due", due_refills),
                ("At/Below Reorder", low_stock_items),
            ])

        except Exception as e:
            # Non-fatal; just log to console so the UI keeps working
            try:
                print(f"refresh_reports_overview failed: {e}")
            except Exception:
                pass

    def on_kpi_clicked(self, index: int) -> None:
        """
        Drill-down for KPI cards.

        Uses self.current_report_headers / self.current_report_rows, which are
        already populated by the report generators (orders, reconciliation,
        inventory, billing, etc.).
        """
        headers = getattr(self, "current_report_headers", None)
        rows = getattr(self, "current_report_rows", None)
        report_type = getattr(self, "current_report_type", None)

        if not headers or not rows:
            QMessageBox.information(self, "Reports", "Generate a report first.")
            return

        # Default: show all rows for the current report
        filtered_rows = list(rows)

        # For order / reconciliation reports, try to filter by STATUS column
        if report_type in ("orders", "reconciliation"):
            status_col = None
            for col_idx, h in enumerate(headers):
                if str(h).strip().upper().startswith("STATUS"):
                    status_col = col_idx
                    break

            # KPI 0 is usually "Total Orders" / "Orders in range" – no filter
            if status_col is not None and index > 0:
                kpi_label = self.kpi_titles[index].text().strip()
                if kpi_label:
                    filtered_rows = [
                        r for r in rows
                        if len(r) > status_col and str(r[status_col]).strip() == kpi_label
                    ]

        # For inventory we could later add special filters; for now, show all
        # (still fully functional and consistent with the table).

        title = self.kpi_titles[index].text() or "Details"
        self.show_kpi_drilldown_dialog(title, headers, filtered_rows)

    def show_kpi_drilldown_dialog(self, title: str, headers: list, rows: list) -> None:
        """Simple table dialog used for KPI drill-downs."""
        dlg = QDialog(self)
        dlg.setWindowTitle(title)
        dlg.resize(900, 500)

        layout = QVBoxLayout(dlg)

        table = QTableWidget()
        table.setColumnCount(len(headers))
        table.setHorizontalHeaderLabels([str(h) for h in headers])
        table.setRowCount(len(rows))

        for r_idx, row in enumerate(rows):
            for c_idx, value in enumerate(row):
                item = QTableWidgetItem(str(value))
                item.setFlags(item.flags() ^ Qt.ItemFlag.ItemIsEditable)
                table.setItem(r_idx, c_idx, item)

        table.resizeColumnsToContents()
        layout.addWidget(table)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Close)
        buttons.rejected.connect(dlg.reject)
        layout.addWidget(buttons)

        dlg.exec()

    def show_orders_this_month(self):
        """Show detailed list of orders created this month"""
        try:
            import sqlite3
            from PyQt6.QtWidgets import QDialog, QVBoxLayout, QTableWidget, QTableWidgetItem, QLabel
            
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            cur.execute("""
                SELECT id, order_date, patient_last_name, patient_first_name, order_status
                FROM orders
                WHERE strftime('%Y-%m', order_date) = strftime('%Y-%m', 'now')
                ORDER BY order_date DESC
            """)
            rows = cur.fetchall()
            conn.close()
            
            dlg = QDialog(self)
            dlg.setWindowTitle("Orders This Month")
            dlg.resize(700, 400)
            layout = QVBoxLayout(dlg)
            
            header = QLabel(f"<b>Orders Created This Month:</b> {len(rows)} orders")
            layout.addWidget(header)
            
            table = QTableWidget()
            table.setColumnCount(5)
            table.setHorizontalHeaderLabels(["Order ID", "Date", "Last Name", "First Name", "Status"])
            table.setRowCount(len(rows))
            
            for i, row in enumerate(rows):
                for j, val in enumerate(row):
                    table.setItem(i, j, QTableWidgetItem(str(val) if val else ""))
            
            table.resizeColumnsToContents()
            layout.addWidget(table)
            dlg.exec()
            
        except Exception as e:
            print(f"Error showing orders this month: {e}")

