    def optimize_ocr_database(self):
        """Vacuum/optimize the OCR database and show updated stats."""
        try:
            self.ocr_indexer.vacuum()
            stats = self.ocr_indexer.get_stats()
            QMessageBox.information(
                self,
                "Database Optimized",
                f"OCR database has been optimized.\n\n"
                f"Files indexed: {stats.get('total_files', 0)}\n"
                f"Total characters: {stats.get('total_characters', 0):,}\n"
                f"Database size: {stats.get('db_size', 0):,} bytes"
            )
        except Exception as e:
            QMessageBox.warning(self, "Optimization Failed", f"Failed to optimize database: {e}")

    def backup_ocr_database(self):
        """Create a timestamped backup of the OCR database and prune older backups."""
        try:
            from dmelogic.paths import ocr_cache_db
            db_path = str(ocr_cache_db())
            if not os.path.exists(db_path):
                QMessageBox.warning(self, "Backup Failed", "OCR database not found")
                return

            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            backup_path = db_path.replace(".db", f"_backup_{timestamp}.db")
            shutil.copy2(db_path, backup_path)
            self.cleanup_old_ocr_backups()
            QMessageBox.information(self, "Backup Complete", f"Database backed up to:\n{backup_path}")
        except Exception as e:
            QMessageBox.warning(self, "Backup Failed", f"Failed to backup database: {e}")

    def cleanup_old_ocr_backups(self):
        """Keep only the last 7 OCR database backups in the data folder."""
        try:
            from dmelogic.paths import ocr_cache_db
            db_dir = ocr_cache_db().parent
            if not db_dir.exists():
                return
            backups = sorted(db_dir.glob("ocr_cache_backup_*.db"), key=lambda p: p.stat().st_mtime)
            # Remove all but last 7
            for old in backups[:-7]:
                try:
                    old.unlink()
                except Exception:
                    pass
        except Exception as e:
            print(f"❌ Backup cleanup failed: {e}")

    # --- OCR Extraction System ---
    def extract_and_populate_from_ocr(self):
        """Intelligently extract data from current PDF and populate fields with user confirmation."""
        try:
            if not getattr(self, 'current_file', None) or not getattr(self, 'doc', None):
                QMessageBox.information(self, "OCR Extract", "No PDF file is currently loaded.")
                return

            # Get the file path
            clean_filename = self.current_file
            if clean_filename.startswith("★ "):
                clean_filename = clean_filename[2:]
            
            file_path = os.path.join(self.folder_path, clean_filename)
            if not os.path.exists(file_path):
                QMessageBox.warning(self, "OCR Extract", "PDF file not found.")
                return

            # Show progress
            QApplication.setOverrideCursor(Qt.CursorShape.WaitCursor)
            self.statusBar().showMessage("Analyzing PDF pages...")
            
            # Intelligent page-by-page extraction with classification
            extracted_text = self._extract_text_smart(file_path)
            
            QApplication.restoreOverrideCursor()
            
            if not extracted_text:
                QMessageBox.warning(self, "OCR Extract", "Could not extract text from PDF.")
                return

            # Parse all possible data
            extracted_data = self.parse_comprehensive_medical_data(extracted_text)
            
            # Show confirmation dialog
            self.show_ocr_confirmation_dialog(extracted_data, extracted_text)
            
        except Exception as e:
            QApplication.restoreOverrideCursor()
            QMessageBox.critical(self, "OCR Extract Error", f"Error extracting data: {e}")
            print(f"OCR extraction error: {e}")

    def _extract_text_smart(self, file_path: str) -> str:
        """Extract text with intelligent page classification - skip cover sheets, prioritize prescriptions."""
        import fitz
        from PIL import Image
        import pytesseract
        
        doc = fitz.open(file_path)
        pages_data = []
        
        for page_num in range(len(doc)):
            page = doc[page_num]
            
            # Try embedded text first
            page_text = page.get_text()
            
            # If no embedded text or very little, use OCR
            if not page_text or len(page_text.strip()) < 50:
                try:
                    # Use Tesseract OCR for scanned images
                    pix = page.get_pixmap(matrix=fitz.Matrix(2, 2))  # Higher resolution
                    img = Image.frombytes("RGB", [pix.width, pix.height], pix.samples)
                    page_text = pytesseract.image_to_string(img, config='--psm 6')
                except Exception as e:
                    print(f"OCR failed for page {page_num + 1}: {e}")
                    page_text = ""
            
            # Classify and score page
            page_info = self._classify_page(page_text, page_num)
            pages_data.append(page_info)
        
        doc.close()
        
        # Sort: prescription pages first (type != 'cover'), then by score (highest first)
        pages_data.sort(key=lambda x: (x['type'] == 'cover', -x['score']))
        
        # Build text from non-cover pages only
        prescription_pages = [p for p in pages_data if p['type'] != 'cover']
        
        if prescription_pages:
            # Use only prescription pages
            result = "\n\n".join([f"--- Page {p['page_num'] + 1} ({p['type']}, score: {p['score']:.1f}) ---\n{p['text']}" 
                                  for p in prescription_pages])
            return result
        else:
            # Fallback: use all pages if no prescription detected
            result = "\n\n".join([f"--- Page {p['page_num'] + 1} ---\n{p['text']}" for p in pages_data])
            return result
    
    def _classify_page(self, text: str, page_num: int) -> dict:
        """Classify page type and score relevance for medical data extraction."""
        import re
        
        text_upper = text.upper()
        text_lower = text.lower()
        score = 0
        page_type = 'unknown'
        
        # Cover sheet indicators (negative signals)
        cover_keywords = [
            'FAX SHEET', 'FACSIMILE', 'TELECOPY', 'TRANSMISSION', 
            'TO COMPANY:', 'FROM COMPANY:', 'NUMBER OF PAGE',
            'CONFIDENTIAL', 'PRIVILEGED', 'LEGALLY PRIVILEGED',
            'ARRANGE FOR RETURN', 'NOTIFY BY TELEPHONE'
        ]
        
        cover_score = sum(1 for kw in cover_keywords if kw in text_upper)
        
        if cover_score >= 3:  # Strong cover sheet signal
            return {'page_num': page_num, 'text': text, 'type': 'cover', 'score': -100}
        
        # Prescription indicators (positive signals)
        rx_indicators = {
            'STATE PRESCRIPTION': 10,
            'OFFICIAL': 8,
            'PRESCRIPTION': 8,
            'PRESCRIBER SIGNATURE': 7,
            'DEA': 6,
            'NPI:': 6,
            'LIC:': 5,
            'REFILLS': 5,
            'DISPENSE AS WRITTEN': 5,
            'PHARMACIST': 5,
        }
        
        for indicator, points in rx_indicators.items():
            if indicator in text_upper:
                score += points
                page_type = 'prescription'
        
        # Medical data indicators
        medical_patterns = [
            (r'\bDOB\b|\bD\.?O\.?B\.?\b|DATE OF BIRTH|BIRTH DATE', 3),
            (r'\bDIAGNOSIS\b|\bICD[\-\s]?10\b|\b[A-Z]\d{2,3}\.?\d{0,2}\b', 3),  # ICD codes
            (r'\bPATIENT NAME\b|\bPT NAME\b', 3),
            (r'\bADDRESS\b.*\bCITY\b.*\bSTATE\b.*\bZIP\b', 4),
            (r'\bQTY\b|\bQUANTITY\b|SIG:', 2),
            (r'\b\d{5}(?:-\d{4})?\b', 1),  # ZIP codes
            (r'\b\d{10}\b', 2),  # NPI format
        ]
        
        for pattern, points in medical_patterns:
            if re.search(pattern, text_upper):
                score += points
                if page_type == 'unknown':
                    page_type = 'medical'
        
        # DME equipment keywords
        dme_keywords = ['WALKER', 'WHEELCHAIR', 'CANE', 'UNDERPAD', 'BRIEF', 'GLOVE', 
                       'CATHETER', 'CANNULA', 'TUBING', 'MASK', 'NEBULIZER', 'CPAP',
                       'DIAPER', 'CREAM', 'OINTMENT', 'GAUZE', 'BANDAGE']
        
        dme_found = sum(1 for kw in dme_keywords if kw in text_upper)
        if dme_found > 0:
            score += dme_found * 2
            if page_type == 'unknown':
                page_type = 'medical'
        
        # Page position heuristic (first page often cover)
        if page_num == 0 and score < 10:
            score -= 5  # Slight penalty for first page if not clearly medical
        
        return {
            'page_num': page_num,
            'text': text,
            'type': page_type if score > 5 else 'cover' if cover_score > 0 else 'unknown',
            'score': score
        }

    def parse_comprehensive_medical_data(self, text: str) -> dict:
        """Parse all relevant medical data from OCR text."""
        import re
        from datetime import datetime
        
        data = {
            'patient_last_name': None,
            'patient_first_name': None,
            'patient_dob': None,
            'patient_phone': None,
            'patient_address': None,
            'patient_city': None,
            'patient_state': None,
            'patient_zip': None,
            'insurance_id': None,
            'insurance_name': None,
            'icd10_codes': [],
            'prescriber_name': None,
            'prescriber_npi': None,
            'items': [],
            'raw_ocr_text': None
        }
        
        lines = text.split('\n')
        text_upper = text.upper()
        
        # Patient name patterns - enhanced for handwritten scripts
        name_patterns = [
            # "Patient: LASTNAME, FIRSTNAME" or "Patient Name: ..."
            r'(?:patient\s*(?:name)?|pt\s*(?:name)?|name)[\s:]+([A-Z][A-Za-z\-]+)[\s,]+([A-Z][A-Za-z\-]+)',
            # "LASTNAME, FIRSTNAME" at start of line
            r'^([A-Z][A-Z\-]+)[\s,]+([A-Z][A-Z\-]+)',
            # "LASTNAME-FIRSTNAME, MIDDLENAME" format
            r'([A-Z][A-Za-z]+(?:\-[A-Z][A-Za-z]+)?)[\s,]+([A-Z][A-Za-z]+)',
            # Capture from common prescription headers
            r'Patient:\s*([A-Z][A-Za-z\-]+)\s+([A-Z][A-Za-z\-]+)',
        ]
        
        for pattern in name_patterns:
            match = re.search(pattern, text, re.IGNORECASE | re.MULTILINE)
            if match:
                last = match.group(1).strip().title()
                first = match.group(2).strip().title()
                # Skip if these look like form labels or common words
                if last.lower() not in ['patient', 'name', 'prescriber', 'doctor', 'physician']:
                    data['patient_last_name'] = last
                    data['patient_first_name'] = first
                    break
        
        # Date of Birth patterns - enhanced with context filtering to avoid Rx date confusion
        dob_patterns = [
            r'(?:dob|date\s*of\s*birth|birth\s*date|d\.?o\.?b\.?)[\s:]*(\d{1,2}[\s/\-\.]\d{1,2}[\s/\-\.]\d{2,4})',
            r'(?:born|birth)[\s:]*(\d{1,2}[\s/\-\.]\d{1,2}[\s/\-\.]\d{2,4})',
            # Standalone date patterns near "DOB" or at document start
            r'DOB[\s:]*(\d{1,2}[\s/\-\.]\d{1,2}[\s/\-\.]\d{2,4})',
            # Any date pattern that looks like MM/DD/YYYY or MM-DD-YYYY
            r'\b(\d{1,2}[\s/\-\.]\d{1,2}[\s/\-\.]\d{4})\b',
        ]
        
        # Collect all DOB candidates with context for filtering
        dob_candidates = []
        for pattern in dob_patterns:
            for match in re.finditer(pattern, text, re.IGNORECASE):
                dob_str = match.group(1).strip()
                context_start = max(0, match.start() - 200)
                context_end = min(len(text), match.end() + 200)
                context = text[context_start:context_end].upper()
                
                # Score based on context to prioritize patient header DOB
                score = 0
                
                # GOOD context (patient header section)
                if any(keyword in context for keyword in ['PATIENT NAME', 'PT NAME', 'PATIENT:', 'PT:']):
                    score += 10
                if any(keyword in context for keyword in ['ADDRESS', 'CITY', 'STATE', 'ZIP']):
                    score += 5
                
                # BAD context (prescription body section)
                if any(keyword in context for keyword in ['RX:', 'PRESCRIPTION:', 'RX DATE', 'DATE WRITTEN']):
                    score -= 15
                if any(keyword in context for keyword in ['ICD10', 'ICD-10', 'DIAGNOSIS', 'DX:']):
                    score -= 10
                if any(keyword in context for keyword in ['PRESCRIBER', 'PROVIDER', 'PHYSICIAN', 'NPI']):
                    score -= 10
                
                dob_candidates.append((dob_str, score, match.start()))
        
        # Sort by score (highest first), then by position (earliest first)
        dob_candidates.sort(key=lambda x: (-x[1], x[2]))
        
        # Try to parse the best candidate
        for dob_str, score, pos in dob_candidates:
            # Remove spaces and normalize separators
            dob_str = re.sub(r'[\s]', '', dob_str)
            dob_str = re.sub(r'[.\-]', '/', dob_str)
            
            # Try to parse date
            try:
                # Try MM/DD/YYYY
                parsed_date = datetime.strptime(dob_str, '%m/%d/%Y')
                data['patient_dob'] = parsed_date.strftime('%m/%d/%Y')
                break
            except:
                try:
                    # Try MM/DD/YY
                    parsed_date = datetime.strptime(dob_str, '%m/%d/%y')
                    data['patient_dob'] = parsed_date.strftime('%m/%d/%Y')
                    break
                except:
                    pass
        
        # Address patterns - enhanced for handwritten and multi-line addresses
        address_patterns = [
            r'(?:address|addr)[\s:]*(.+?)(?=\n|city|state|zip|\d{5})',
            r'(?:address|addr)[\s:]*(\d+\s+[A-Za-z0-9\s]+(?:street|st|avenue|ave|road|rd|drive|dr|lane|ln|way|blvd|boulevard|circle|ct|court)?)',
            # Direct number + street pattern
            r'\b(\d+\s+[A-Z][A-Za-z\s]+(?:Street|St|Avenue|Ave|Road|Rd|Drive|Dr|Lane|Ln|Way|Blvd|Boulevard))\b',
            # Capture line after "Address" label
            r'Address[\s:]*\n?\s*(.+?)(?=\n)',
        ]
        
        for pattern in address_patterns:
            address_match = re.search(pattern, text, re.IGNORECASE)
            if address_match:
                addr = address_match.group(1).strip()
                # Clean up common OCR artifacts
                addr = re.sub(r'\s+', ' ', addr)
                if len(addr) > 5 and not addr.lower().startswith('address'):
                    data['patient_address'] = addr
                    break
        
        # City, State, ZIP - enhanced for various formats including "Bronx, NY 10461"
        city_state_zip_patterns = [
            # "Bronx, NY 10461" or "City, ST ZIP" format
            r'\b([A-Z][A-Za-z\s]+),\s*([A-Z]{2})\s*(\d{5}(?:\-\d{4})?)',
            # "City: xxx State: ST Zip: 12345"
            r'City[\s:]*([A-Za-z\s]+).*State[\s:]*([A-Z]{2}).*Zip[\s:]*(\d{5})',
            # Just "ST ZIP" pattern (will search for city separately)
            r'\b([A-Z]{2})\s+(\d{5}(?:\-\d{4})?)\b',
        ]
        
        for pattern in city_state_zip_patterns:
            match = re.search(pattern, text, re.IGNORECASE)
            if match:
                if len(match.groups()) == 3:
                    city_raw = match.group(1).strip()
                    # Clean city name (remove extra spaces, numbers, etc.)
                    city_clean = re.sub(r'[\d]+', '', city_raw).strip().title()
                    if len(city_clean) > 2:  # Valid city name
                        data['patient_city'] = city_clean
                    data['patient_state'] = match.group(2).strip().upper()
                    data['patient_zip'] = match.group(3).strip()
                    break
                elif len(match.groups()) == 2:
                    # Only state and zip found - search for city nearby
                    data['patient_state'] = match.group(1).strip().upper()
                    data['patient_zip'] = match.group(2).strip()
                    
                    # Look for city word before state/zip pattern
                    city_before_pattern = rf'([A-Z][a-z]+)\s*,?\s*{match.group(1)}\s+{match.group(2)}'
                    city_match = re.search(city_before_pattern, text, re.IGNORECASE)
                    if city_match:
                        data['patient_city'] = city_match.group(1).strip().title()
                    else:
                        # Try to extract from line before state/zip
                        state_zip_line = [l for l in lines if match.group(1) in l and match.group(2) in l]
                        if state_zip_line:
                            line_idx = lines.index(state_zip_line[0])
                            # Check same line first
                            words_before = state_zip_line[0].split(match.group(1))[0].strip().split()
                            if words_before:
                                potential_city = words_before[-1].strip(',')
                                if len(potential_city) > 2 and not potential_city.isdigit():
                                    data['patient_city'] = potential_city.title()
                    break
        
        # Phone number patterns
        phone_patterns = [
            r'(?:phone|tel|telephone|mobile|cell)[\s:]*([\(]?\d{3}[\)]?[\s\-\.]?\d{3}[\s\-\.]?\d{4})',
            r'(?:home|work)[\s:]*([\(]?\d{3}[\)]?[\s\-\.]?\d{3}[\s\-\.]?\d{4})',
            r'\b(\d{3}[\-\.]\d{3}[\-\.]\d{4})\b',
            r'\b(\(\d{3}\)\s*\d{3}[\-\.]\d{4})\b',
        ]
        
        for pattern in phone_patterns:
            phone_match = re.search(pattern, text, re.IGNORECASE)
            if phone_match:
                phone = phone_match.group(1).strip()
                # Normalize format
                phone_digits = re.sub(r'[^\d]', '', phone)
                if len(phone_digits) == 10:
                    data['patient_phone'] = f"({phone_digits[:3]}) {phone_digits[3:6]}-{phone_digits[6:]}"
                    break
        
        # Insurance ID patterns
        insurance_patterns = [
            r'(?:member\s*id|insurance\s*id|subscriber\s*id|policy\s*#)[\s:]*([A-Z0-9]{6,})',
            r'ID[\s:]*([A-Z0-9]{6,})'
        ]
        
        for pattern in insurance_patterns:
            match = re.search(pattern, text, re.IGNORECASE)
            if match:
                data['insurance_id'] = match.group(1).strip()
                break
        
        # Insurance name
        insurance_name_match = re.search(r'(?:insurance|payer|plan)[\s:]*(.+?)(?=\n|$)', text, re.IGNORECASE)
        if insurance_name_match:
            data['insurance_name'] = insurance_name_match.group(1).strip()
        
        # ICD-10 codes
        icd10_matches = re.findall(r'\b([A-Z]\d{2}(?:\.\d{1,2})?)\b', text)
        data['icd10_codes'] = list(set(icd10_matches))[:5]  # Limit to 5 unique codes
        
        # Prescriber name patterns - enhanced for various formats
        prescriber_patterns = [
            # "LASTNAME, FIRSTNAME MD" format
            r'(?:prescriber|physician|doctor|provider|ordered\s*by|prescribed\s*by|md|dr\.?)[\s:]*([A-Z][A-Za-z\-]+)[\s,]+([A-Z][A-Za-z\-]+)',
            # "FIRSTNAME LASTNAME MD" format
            r'(?:prescriber|physician|doctor|provider)[\s:]*([A-Z][a-z]+)\s+([A-Z][a-z]+)',
            # Direct MD name pattern: "LASTNAME FIRSTNAME MD" or "LASTNAME, FIRSTNAME MD"
            r'([A-Z][A-Z\-]+)[\s,]+([A-Z][A-Z\-]+)\s+(?:MD|DO|NP|PA)',
            # Name followed by license or NPI
            r'([A-Z][A-Za-z]+)\s+([A-Z][A-Za-z]+)\s+(?:MD|DO)\s*(?:LIC|NPI)',
            # Search near NPI numbers
            r'([A-Z][A-Z\-]+)\s+([A-Z][A-Z\-]+).*?NPI',
        ]
        
        for pattern in prescriber_patterns:
            match = re.search(pattern, text, re.IGNORECASE | re.DOTALL)
            if match:
                if len(match.groups()) == 1:
                    # Single capture group (e.g., "Aa Es" after label)
                    name = match.group(1).strip()
                    # Skip if looks like a label
                    if name.lower() not in ['prescriber', 'physician', 'doctor', 'provider', 'patient', 'name', 'signature']:
                        data['prescriber_name'] = name.title()
                        break
                elif len(match.groups()) >= 2:
                    first_part = match.group(1).strip()
                    second_part = match.group(2).strip()
                    
                    # Skip if these are common labels
                    skip_words = ['prescriber', 'physician', 'doctor', 'provider', 'patient', 'name', 'signature']
                    if first_part.lower() not in skip_words and second_part.lower() not in skip_words:
                        # Check if it's "LASTNAME, FIRSTNAME" format (usually all caps or title case)
                        if first_part.isupper() or len(first_part) > len(second_part):
                            # Likely LASTNAME FIRSTNAME format
                            data['prescriber_name'] = f"{second_part.title()} {first_part.title()}"
                        else:
                            # Likely FIRSTNAME LASTNAME format
                            data['prescriber_name'] = f"{first_part.title()} {second_part.title()}"
                        
                        # If pattern also captured NPI, extract it
                        if len(match.groups()) >= 3:
                            potential_npi = match.group(3).strip()
                            if len(potential_npi) == 10 and potential_npi.isdigit():
                                data['prescriber_npi'] = potential_npi
                        break
        
        # NPI number - enhanced patterns
        npi_patterns = [
            r'NPI[\s:#]*(\d{10})',
            r'(?:national\s*provider|npi\s*number)[\s:#]*(\d{10})',
            # Look for 10-digit numbers near "NPI" or prescriber info
            r'\b(\d{10})\b',
        ]
        
        for pattern in npi_patterns:
            npi_match = re.search(pattern, text, re.IGNORECASE)
            if npi_match:
                npi = npi_match.group(1)
                # Validate it's actually 10 digits
                if len(npi) == 10 and npi.isdigit():
                    data['prescriber_npi'] = npi
                    break
        
        # Extract items/equipment - enhanced with more patterns
        dme_keywords = [
            'walker', 'wheelchair', 'cane', 'crutch', 'crutches', 'cpap', 'bipap', 'oxygen', 
            'nebulizer', 'hospital bed', 'commode', 'lift', 'scooter', 'rollator',
            'mask', 'cannula', 'tubing', 'humidifier', 'concentrator', 'underpad', 'underpads',
            'pad', 'pads', 'brief', 'briefs', 'diaper', 'diapers', 'glove', 'gloves',
            'catheter', 'syringe', 'needle', 'gauze', 'bandage', 'wrap', 'brace', 'splint',
            'boot', 'walker', 'cane', 'quad cane', 'transfer bench', 'shower chair',
            'raised toilet seat', 'grab bar', 'reacher', 'sock aid', 'shoe horn'
        ]
        
        items_found = {}  # Track unique items by full description
        
        # Extract all item lines that have descriptions (HCPCS codes, product codes, or keywords)
        # Look for patterns like:
        # "Item: FTUP23X36 - Description Qty: 30"
        # "Rx: Underpad 30x36 Quantity: 4"
        item_line_patterns = [
            r'(?:rx|item|items?|equipment|supply|supplies|order)[\s:]+([^\n]+)',
            r'(\w+[-\w]*\d+[-\w]*)\s*[-:]?\s*([^\n]{0,50}?)(?:qty|quantity|#)?\s*[:=]?\s*(\d+)',
            r'(\d+)\s*(?:x|X)?\s*([A-Z][\w\s-]+(?:pad|brief|diaper|glove|mask|cannula|tubing))',
        ]
        
        # Search entire document for item descriptions
        text_lower = text.lower()
        for pattern in item_line_patterns:
            for match in re.finditer(pattern, text, re.IGNORECASE):
                item_text = match.group(0).strip()
                item_text_lower = item_text.lower()
                
                # Extract description - look for HCPCS code or keyword
                description = None
                qty = 1
                
                # Try to find HCPCS-like code (letters+numbers+optional dashes)
                hcpcs_match = re.search(r'\b([A-Z][\w-]*\d[\w-]*)\b', item_text, re.IGNORECASE)
                if hcpcs_match:
                    description = hcpcs_match.group(1).upper()
                else:
                    # Check for DME keywords
                    for keyword in dme_keywords:
                        if keyword.lower() in item_text_lower:
                            description = keyword.title()
                            break
                
                if not description:
                    continue
                
                # Extract quantity
                qty_patterns = [
                    r'(?:qty|quantity|#)[\s:=]*(\d+)',
                    r'(\d+)\s*(?:x|X)',
                    r'\b(\d+)\s*$',  # Number at end of line
                ]
                for qty_pattern in qty_patterns:
                    qty_match = re.search(qty_pattern, item_text)
                    if qty_match:
                        try:
                            extracted_qty = int(qty_match.group(1))
                            if 1 <= extracted_qty <= 9999:
                                qty = extracted_qty
                            break
                        except:
                            pass
                
                # Deduplicate by description - keep highest quantity
                item_key = description.lower().strip()
                if item_key not in items_found or qty > items_found[item_key]['quantity']:
                    items_found[item_key] = {
                        'description': description,
                        'quantity': qty,
                        'confidence': 'high',
                        'raw_text': item_text[:80]
                    }
        
        # Add found items to data
        for item_data in items_found.values():
            data['items'].append(item_data)
        
        # Fallback: search entire text if no items found
        if not data['items']:
            items_found_fallback = {}
            for keyword in dme_keywords:
                if keyword.lower() in text.lower():
                    # Try to extract quantity
                    qty_pattern = rf'(\d+)\s*{re.escape(keyword)}'
                    qty_match = re.search(qty_pattern, text, re.IGNORECASE)
                    qty = 1
                    if qty_match:
                        try:
                            extracted_qty = int(qty_match.group(1))
                            if 1 <= extracted_qty <= 9999:
                                qty = extracted_qty
                        except:
                            pass
                    
                    # Only add unique keywords
                    item_key = keyword.lower()
                    if item_key not in items_found_fallback:
                        items_found_fallback[item_key] = True
                        data['items'].append({
                            'description': keyword.title(),
                            'quantity': qty,
                            'confidence': 'medium',
                            'raw_text': ''
                        })
        
        # Store raw OCR text for reference
        data['raw_ocr_text'] = text
        
        return data

    def show_ocr_confirmation_dialog(self, extracted_data: dict, full_text: str):
        """Show dialog to confirm/edit extracted data with database matching."""
        # Stop auto-refresh timer while dialog is open to prevent form clearing
        if hasattr(self, 'auto_refresh_timer'):
            self.auto_refresh_timer.stop()
        
        dialog = QDialog(self)
        dialog.setWindowTitle("🤖 Confirm Extracted Data")
        dialog.setMinimumWidth(1400)
        dialog.setMinimumHeight(850)
        
        main_layout = QHBoxLayout(dialog)
        
        # === LEFT SIDE: PDF VIEWER ===
        pdf_viewer_widget = QWidget()
        pdf_viewer_layout = QVBoxLayout(pdf_viewer_widget)
        pdf_viewer_layout.setContentsMargins(0, 0, 0, 0)
        
        # PDF display label
        pdf_label = QLabel()
        pdf_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        pdf_label.setStyleSheet("background-color: #2b2b2b; border: 2px solid #555;")
        pdf_label.setMinimumSize(500, 600)
        
        # Page navigation controls
        nav_layout = QHBoxLayout()
        prev_btn = QPushButton("◀ Previous")
        page_label = QLabel("Page 1")
        page_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        page_label.setStyleSheet("font-weight: bold; font-size: 12px;")
        next_btn = QPushButton("Next ▶")
        
        nav_layout.addWidget(prev_btn)
        nav_layout.addWidget(page_label, 1)
        nav_layout.addWidget(next_btn)
        
        # Zoom controls
        zoom_layout = QHBoxLayout()
        zoom_out_btn = QPushButton("🔍-")
        zoom_out_btn.setMaximumWidth(50)
        zoom_label = QLabel("100%")
        zoom_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
        zoom_label.setStyleSheet("font-weight: bold; font-size: 11px; min-width: 50px;")
        zoom_in_btn = QPushButton("🔍+")
        zoom_in_btn.setMaximumWidth(50)
        zoom_reset_btn = QPushButton("Reset")
        zoom_reset_btn.setMaximumWidth(60)
        
        zoom_layout.addWidget(QLabel("Zoom:"))
        zoom_layout.addWidget(zoom_out_btn)
        zoom_layout.addWidget(zoom_label)
        zoom_layout.addWidget(zoom_in_btn)
        zoom_layout.addWidget(zoom_reset_btn)
        zoom_layout.addStretch()
        
        pdf_viewer_layout.addWidget(pdf_label)
        pdf_viewer_layout.addLayout(nav_layout)
        pdf_viewer_layout.addLayout(zoom_layout)
        
        # Store PDF viewer components in dialog
        dialog.pdf_label = pdf_label
        dialog.page_label = page_label
        dialog.zoom_label = zoom_label
        dialog.current_page = 0
        dialog.zoom_level = 1.2
        
        # Load PDF document
        try:
            clean_filename = self.current_file
            if clean_filename.startswith("★ "):
                clean_filename = clean_filename[2:]
            file_path = os.path.join(self.folder_path, clean_filename)
            
            import fitz
            dialog.pdf_doc = fitz.open(file_path)
            dialog.total_pages = len(dialog.pdf_doc)
            
            def render_pdf_page():
                """Render current page to the label."""
                try:
                    page = dialog.pdf_doc[dialog.current_page]
                    zoom = dialog.zoom_level
                    mat = fitz.Matrix(zoom, zoom)
                    pix = page.get_pixmap(matrix=mat)
                    
                    # Convert to QPixmap
                    from PyQt6.QtGui import QImage, QPixmap
                    img_format = QImage.Format.Format_RGB888
                    img = QImage(pix.samples, pix.width, pix.height, pix.stride, img_format)
                    pixmap = QPixmap.fromImage(img)
                    
                    # Scale to fit label while maintaining aspect ratio
                    scaled_pixmap = pixmap.scaled(
                        pdf_label.width() - 10,
                        pdf_label.height() - 10,
                        Qt.AspectRatioMode.KeepAspectRatio,
                        Qt.TransformationMode.SmoothTransformation
                    )
                    pdf_label.setPixmap(scaled_pixmap)
                    page_label.setText(f"Page {dialog.current_page + 1} of {dialog.total_pages}")
                except Exception as e:
                    pdf_label.setText(f"Error rendering page:\n{str(e)}")
                    print(f"PDF render error: {e}")
            
            def go_prev():
                if dialog.current_page > 0:
                    dialog.current_page -= 1
                    render_pdf_page()
            
            def go_next():
                if dialog.current_page < dialog.total_pages - 1:
                    dialog.current_page += 1
                    render_pdf_page()
            
            def zoom_in():
                dialog.zoom_level = min(dialog.zoom_level + 0.2, 3.0)
                zoom_label.setText(f"{int(dialog.zoom_level * 100)}%")
                render_pdf_page()
            
            def zoom_out():
                dialog.zoom_level = max(dialog.zoom_level - 0.2, 0.4)
                zoom_label.setText(f"{int(dialog.zoom_level * 100)}%")
                render_pdf_page()
            
            def zoom_reset():
                dialog.zoom_level = 1.2
                zoom_label.setText(f"{int(dialog.zoom_level * 100)}%")
                render_pdf_page()
            
            prev_btn.clicked.connect(go_prev)
            next_btn.clicked.connect(go_next)
            zoom_in_btn.clicked.connect(zoom_in)
            zoom_out_btn.clicked.connect(zoom_out)
            zoom_reset_btn.clicked.connect(zoom_reset)
            
            # Initial render
            render_pdf_page()
            page_label.setText(f"Page 1 of {dialog.total_pages}")
            zoom_label.setText(f"{int(dialog.zoom_level * 100)}%")
            
        except Exception as e:
            pdf_label.setText(f"Could not load PDF preview:\n{e}")
            pdf_label.setStyleSheet("background-color: #2b2b2b; color: #ff6b6b; border: 2px solid #555; padding: 20px;")
        
