    def open_ocr_folder(self):
        """Open the OCR folder in Windows Explorer."""
        import subprocess
        from dmelogic.paths import ocr_folder as _ocr_folder
        
        # Check for configured folder first, then local
        main_folder = str(_ocr_folder())
        local_folder = "faxes"
        
        if os.path.exists(main_folder):
            folder_path = main_folder
        elif os.path.exists(local_folder):
            folder_path = os.path.abspath(local_folder)
        else:
            QMessageBox.warning(self, "Folder Not Found", 
                f"OCR folder not found.\n\nExpected locations:\n• {main_folder}\n• {local_folder}")
            return
        
        try:
            # Open in Windows Explorer
            subprocess.Popen(['explorer', folder_path])
        except Exception as e:
            QMessageBox.warning(self, "Error", f"Failed to open folder: {e}")

