    def export_inventory_template(self):
        """Create and save an Excel template for bulk inventory import.
        Also writes a CSV copy next to the chosen file name for convenience.
        """
        try:
            default_dir = self.settings.get('db_folder') or os.path.dirname(self.inventory_database_file)
            default_path = os.path.join(default_dir, 'inventory_template.xlsx')
            file_path, _ = QFileDialog.getSaveFileName(self, 'Save Excel Template', default_path, 'Excel Workbook (*.xlsx)')
            if not file_path:
                return

            if Workbook is None:
                QMessageBox.warning(self, 'Missing Dependency', 'openpyxl is not installed. The Excel template will be created as CSV instead.')
            
            headers = [
                'Item Number', 'HCPCS Code', 'Description', 'Category', 'Cost', 'Bill Amount',
                'Stock Quantity', 'Reorder Level', 'Brand', 'Supplier', 'Notes', 'Last Restocked Date (YYYY-MM-DD)'
            ]

            # Create Excel if openpyxl is available
            if Workbook is not None:
                wb = Workbook()
                ws = wb.active
                ws.title = 'Inventory'
                ws.append(headers)
                # Add one example row to guide formatting (values are comments-like)
                example = ['INT-001', 'E0143', 'Walker, Folding', 'Mobility', 35.00, 55.00, 10, 3, 'Drive Medical', 'MobilityPlus Inc', 'Optional notes', '2025-01-15']
                ws.append(example)

                info = wb.create_sheet('Instructions')
                info.append(['How to use this template'])
                info.append(['- Fill one row per item on the Inventory sheet.'])
                info.append(['- Description is required. Other fields are optional but recommended.'])
                info.append(['- Cost and Bill Amount are numbers (do not include $).'])
                info.append(['- Dates must be YYYY-MM-DD.'])
                info.append(['- You can delete the example row before importing.'])
                wb.save(file_path)

            # Also create a CSV companion for quick editing if desired
            try:
                csv_path = os.path.splitext(file_path)[0] + '.csv'
                with open(csv_path, 'w', newline='', encoding='utf-8') as f:
                    writer = csv.writer(f)
                    writer.writerow(headers)
                # Don't write example row to avoid confusion in CSV
            except Exception:
                pass

            QMessageBox.information(self, 'Template Saved', f'Template saved to:\n{file_path}')
        except Exception as e:
            QMessageBox.critical(self, 'Error', f'Failed to create template:\n\n{str(e)}')

    def _normalize_header(self, text: str) -> str:
        keep = [c for c in (text or '').lower() if c.isalnum()]
        return ''.join(keep)

    def _map_headers(self, headers: List[str]) -> Dict[int, str]:
        """Return a mapping of column index -> internal field name.
        Accepts several header synonyms to be friendly.
        """
        synonyms = {
            'itemnumber': 'item_number',
            'hcpcscode': 'hcpcs_code',
            'hcpcs': 'hcpcs_code',
            'description': 'description',
            'category': 'category',
            'cost': 'cost',
            'cost$': 'cost',
            'billamount': 'bill_amount',
            'retailprice': 'bill_amount',
            'price': 'bill_amount',
            'stockquantity': 'stock_quantity',
            'qty': 'stock_quantity',
            'quantity': 'stock_quantity',
            'reorderlevel': 'reorder_level',
            'brand': 'brand',
            'supplier': 'supplier',
            'source': 'supplier',
            'notes': 'notes',
            'lastrestockeddate': 'last_restocked_date',
            'lastrestocked': 'last_restocked_date',
        }
        mapping: Dict[int, str] = {}
        for idx, h in enumerate(headers):
            norm = self._normalize_header(h)
            mapping[idx] = synonyms.get(norm, None)
        return mapping

    def _iter_rows_from_excel_or_csv(self, path: str) -> List[Dict[str, Any]]:
        """Load rows from .xlsx or .csv and return a list of dicts using normalized headers.
        Empty rows are skipped.
        """
        ext = os.path.splitext(path)[1].lower()
        rows: List[Dict[str, Any]] = []
        if ext == '.csv':
            with open(path, 'r', encoding='utf-8-sig', newline='') as f:
                reader = csv.reader(f)
                headers = next(reader, [])
                colmap = self._map_headers(headers)
                for r in reader:
                    rec: Dict[str, Any] = {}
                    empty = True
                    for i, val in enumerate(r):
                        key = colmap.get(i)
                        if key:
                            rec[key] = (val or '').strip()
                            if rec[key]:
                                empty = False
                    if not empty:
                        rows.append(rec)
            return rows
        else:
            if openpyxl is None:
                raise RuntimeError('openpyxl is required to read Excel files. Please install it or use CSV.')
            wb = openpyxl.load_workbook(path)
            ws = wb.active
            headers = [str(c.value or '') for c in next(ws.iter_rows(min_row=1, max_row=1))]
            colmap = self._map_headers(headers)
            for row in ws.iter_rows(min_row=2):
                rec: Dict[str, Any] = {}
                empty = True
                for i, cell in enumerate(row):
                    key = colmap.get(i)
                    if not key:
                        continue
                    val = cell.value
                    if isinstance(val, str):
                        val = val.strip()
                    rec[key] = val if val is not None else ''
                    if str(rec[key]).strip():
                        empty = False
                if not empty:
                    rows.append(rec)
            return rows

    def _to_float(self, v) -> float:
        try:
            if v is None or v == '':
                return 0.0
            return float(str(v).replace('$', '').replace(',', '').strip())
        except Exception:
            return 0.0

    def _to_int(self, v) -> int:
        try:
            if v is None or v == '':
                return 0
            return int(float(str(v).replace(',', '').strip()))
        except Exception:
            return 0

    def import_inventory_from_excel(self):
        """Import inventory items from an Excel (.xlsx) or CSV file.
        For each imported item, also write a JSON file into the inventory_items folder.
        """
        try:
            start_dir = self.settings.get('db_folder') or os.path.dirname(self.inventory_database_file)
            path, _ = QFileDialog.getOpenFileName(self, 'Import Inventory', start_dir, 'Excel/CSV (*.xlsx *.csv)')
            if not path:
                return

            rows = self._iter_rows_from_excel_or_csv(path)
            if not rows:
                QMessageBox.information(self, 'Import', 'No rows found to import.')
                return

            # Ask whether to clear existing inventory first
            reply = QMessageBox.question(
                self,
                'Replace or Append',
                'Do you want to REPLACE all existing inventory with this import?\n\nChoose Yes to clear first, No to append.',
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            )

            conn = sqlite3.connect(self.inventory_database_file)
            cur = conn.cursor()
            if reply == QMessageBox.StandardButton.Yes:
                cur.execute('DELETE FROM inventory_transactions')
                cur.execute('DELETE FROM inventory')
                # Also clear item files
                try:
                    if self.inventory_items_folder and os.path.isdir(self.inventory_items_folder):
                        for name in os.listdir(self.inventory_items_folder):
                            try:
                                os.remove(os.path.join(self.inventory_items_folder, name))
                            except Exception:
                                pass
                except Exception:
                    pass

            imported = 0
            for rec in rows:
                description = (rec.get('description') or '').strip()
                if not description:
                    # Require at least description
                    continue
                data = {
                    'item_number': (rec.get('item_number') or '').strip(),
                    'hcpcs_code': (rec.get('hcpcs_code') or '').strip(),
                    'description': description,
                    'category': (rec.get('category') or '').strip(),
                    'cost': self._to_float(rec.get('cost')),
                    'retail_price': self._to_float(rec.get('bill_amount')),
                    'brand': (rec.get('brand') or '').strip(),
                    'supplier': (rec.get('supplier') or '').strip(),
                    'stock_quantity': self._to_int(rec.get('stock_quantity')),
                    'reorder_level': self._to_int(rec.get('reorder_level')),
                    'notes': (rec.get('notes') or '').strip(),
                    'last_restocked_date': (rec.get('last_restocked_date') or ''),
                }

                cur.execute(
                    '''INSERT INTO inventory (
                        item_number, hcpcs_code, description, category, cost, retail_price,
                        brand, supplier, stock_quantity, reorder_level, notes,
                        created_date, updated_date, last_restocked_date
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), datetime('now'), ?)''',
                    (
                        data['item_number'], data['hcpcs_code'], data['description'], data['category'],
                        data['cost'], data['retail_price'], data['brand'], data['supplier'],
                        data['stock_quantity'], data['reorder_level'], data['notes'], data['last_restocked_date'],
                    )
                )
                item_id = cur.lastrowid

                # Create per-item JSON file
                try:
                    folder = self.inventory_items_folder
                    if folder:
                        os.makedirs(folder, exist_ok=True)
                        base_name = data['item_number'] or data['hcpcs_code'] or 'ITEM'
                        base_name = ''.join(c for c in base_name if c.isalnum() or c in ('-', '_'))
                        file_name = f"{base_name}_{item_id}.json"
                        payload = dict(data)
                        payload['item_id'] = item_id
                        with open(os.path.join(folder, file_name), 'w', encoding='utf-8') as jf:
                            json.dump(payload, jf, ensure_ascii=False, indent=2)
                except Exception as _e:
                    # Non-fatal
                    pass

                # Track supplier usage/name in suppliers database
                try:
                    if hasattr(self, 'save_supplier_name'):
                        self.save_supplier_name(data.get('supplier', ''))
                except Exception:
                    pass

                imported += 1

            conn.commit()
            conn.close()

            # Refresh UIs
            if hasattr(self, 'load_inventory_data'):
                self.load_inventory_data()
            # Only refresh DME tab if it exists in this UI context
            if hasattr(self, 'dme_inventory_table') and hasattr(self, 'load_dme_inventory_data'):
                self.load_dme_inventory_data()

            QMessageBox.information(self, 'Import Complete', f'Imported {imported} item(s).')
        except Exception as e:
            # Print full traceback to help diagnose where the failure occurs in user builds
            try:
                import traceback
                print("\n==== Inventory Import Error Traceback ====")
                print(traceback.format_exc())
                print("==== End Traceback ====\n")
            except Exception:
                pass
            QMessageBox.critical(self, 'Import Error', f"Failed to import inventory:\n\n{str(e)}")

    def clear_all_inventory(self):
        """Delete all inventory items and transactions, and remove per-item files."""
        try:
            reply = QMessageBox.question(
                self,
                'Confirm Clear',
                'This will permanently delete ALL inventory items and transactions.\n\nDo you want to continue?',
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            )
            if reply != QMessageBox.StandardButton.Yes:
                return
            conn = sqlite3.connect(self.inventory_database_file)
            cur = conn.cursor()
            cur.execute('DELETE FROM inventory_transactions')
            cur.execute('DELETE FROM inventory')
            conn.commit()
            conn.close()
            # Clear item files
            try:
                if self.inventory_items_folder and os.path.isdir(self.inventory_items_folder):
                    for name in os.listdir(self.inventory_items_folder):
                        try:
                            os.remove(os.path.join(self.inventory_items_folder, name))
                        except Exception:
                            pass
            except Exception:
                pass
            # Refresh UI
            if hasattr(self, 'load_inventory_data'):
                self.load_inventory_data()
            # Only refresh DME tab if it exists
            if hasattr(self, 'dme_inventory_table') and hasattr(self, 'load_dme_inventory_data'):
                self.load_dme_inventory_data()
            QMessageBox.information(self, 'Cleared', 'All inventory has been cleared.')
        except Exception as e:
            QMessageBox.critical(self, 'Error', f'Failed to clear inventory:\n\n{str(e)}')

