    def setup_inventory_database(self):
        """Creates the inventory database and tables if they don't exist."""
        # Inventory database file
        self.inventory_database_file = self.resolve_db_path("inventory.db")
        # Fallback to creating in db_folder or app directory if not found
        if not self.inventory_database_file:
            db_folder = self.settings.get('db_folder') if hasattr(self, 'settings') else None
            if db_folder and os.path.exists(db_folder):
                self.inventory_database_file = os.path.join(db_folder, "inventory.db")
            else:
                app_root = os.path.dirname(os.path.abspath(__file__))
                self.inventory_database_file = os.path.join(app_root, "inventory.db")
        self.inventory_db_path = self.inventory_database_file
        # Folder for per-item files
        try:
            base_dir = os.path.dirname(self.inventory_database_file)
            self.inventory_items_folder = os.path.join(base_dir, "inventory_items")
            os.makedirs(self.inventory_items_folder, exist_ok=True)
        except Exception:
            self.inventory_items_folder = None
        
        conn = sqlite3.connect(self.inventory_database_file)
        cursor = conn.cursor()
        
        # Create inventory table
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS inventory (
                item_id INTEGER PRIMARY KEY AUTOINCREMENT,
                hcpcs_code TEXT,
                description TEXT NOT NULL,
                category TEXT,
                cost REAL,
                retail_price REAL,
                brand TEXT,
                supplier TEXT,
                stock_quantity INTEGER DEFAULT 0,
                reorder_level INTEGER DEFAULT 0,
                notes TEXT,
                created_date TEXT,
                updated_date TEXT,
                last_used_date TEXT,
                last_restocked_date TEXT
            )
        """)
        
        # Add new columns if they don't exist (for existing databases)
        try:
            cursor.execute("ALTER TABLE inventory ADD COLUMN brand TEXT")
            print("✅ Added brand column to existing inventory database")
        except sqlite3.OperationalError:
            pass
        
        # Add last_used_date column if it doesn't exist
        try:
            cursor.execute("ALTER TABLE inventory ADD COLUMN last_used_date TEXT")
            print("✅ Added last_used_date column to existing inventory database")
        except sqlite3.OperationalError:
            pass
        
        # Add last_restocked_date column if it doesn't exist
        try:
            cursor.execute("ALTER TABLE inventory ADD COLUMN last_restocked_date TEXT")
            print("✅ Added last_restocked_date column to existing inventory database")
        except sqlite3.OperationalError:
            pass

        # Ensure item_number column exists (append-only migration to keep indices stable)
        try:
            cursor.execute("ALTER TABLE inventory ADD COLUMN item_number TEXT")
            print("✅ Added item_number column to existing inventory database")
        except sqlite3.OperationalError:
            # Column already exists
            pass
        
        # Create inventory transactions table
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS inventory_transactions (
                transaction_id INTEGER PRIMARY KEY AUTOINCREMENT,
                item_id INTEGER,
                transaction_type TEXT, -- 'IN', 'OUT', 'ADJUSTMENT'
                quantity INTEGER,
                reference_id TEXT, -- order_id or adjustment reason
                transaction_date TEXT,
                notes TEXT,
                FOREIGN KEY (item_id) REFERENCES inventory (item_id)
            )
        """)
        
        # No sample seeding: start with empty inventory so users can import/build from scratch
        
        # Categories master table for managing inventory categories
        try:
            cursor.execute(
                """
                CREATE TABLE IF NOT EXISTS inventory_categories (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT UNIQUE NOT NULL,
                    active INTEGER DEFAULT 1,
                    sort_order INTEGER,
                    created_date TEXT DEFAULT (datetime('now')),
                    updated_date TEXT DEFAULT (datetime('now'))
                )
                """
            )
            # Seed from distinct categories in inventory if table is empty
            cursor.execute("SELECT COUNT(*) FROM inventory_categories")
            cnt = cursor.fetchone()[0]
            if cnt == 0:
                cursor.execute(
                    """
                    INSERT OR IGNORE INTO inventory_categories(name)
                    SELECT DISTINCT TRIM(category) FROM inventory
                    WHERE category IS NOT NULL AND TRIM(category) <> ''
                    ORDER BY UPPER(TRIM(category))
                    """
                )
        except Exception as e:
            print(f"Warning: could not initialize inventory_categories table: {e}")
        
        conn.commit()
        conn.close()
        print(f"✅ Inventory database initialized: {self.inventory_database_file}")
        
