                for name, npi, title, practice in all_prescribers:
                    title_display = f", {title}" if title else " (no title)"
                    practice_display = f" - {practice}" if practice else ""
                    display_text = f"{name}{title_display}{practice_display} (NPI: {npi or 'N/A'})"
                    if not filter_text or filter_text.lower() in name.lower() or filter_text.lower() in (npi or '').lower() or filter_text.lower() in (title or '').lower() or filter_text.lower() in (practice or '').lower():
                        item = QListWidgetItem(display_text)
