            # Main body text - NEW PRESCRIPTION VERSION
            c.setFont('Helvetica', 10)
            c.drawString(0.5*inch, y, "The patient (or the patient's parent/guardian) has requested that we obtain prescriptions for the items")
            y -= 0.15*inch
            c.drawString(0.5*inch, y, "listed below and has provided your contact information so that we may reach out on their behalf.")
            y -= 0.25*inch
            c.setFont('Helvetica-Bold', 10)
            c.drawString(0.5*inch, y, "If you have any questions, please contact us at 347-647-2347.")
            y -= 0.15*inch
