    def add_inventory_item(self):
        """Add a new inventory item."""
        dialog = InventoryItemDialog(self)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            item_data = dialog.get_item_data()
            
            try:
                conn = sqlite3.connect(self.inventory_database_file)
                cursor = conn.cursor()
                
                cursor.execute("""
                    INSERT INTO inventory (
                        hcpcs_code, description, category, cost, retail_price,
                        brand, stock_quantity, reorder_level, supplier, notes,
                        created_date, updated_date, item_number, last_restocked_date
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), datetime('now'), ?, datetime('now'))
                """, (
                    item_data['hcpcs_code'], item_data['description'],
                    item_data['category'], item_data['cost'], item_data['bill_amount'],
                    item_data.get('brand', ''), item_data['stock_quantity'], item_data['reorder_level'],
                    item_data['source'], item_data['notes'], item_data.get('item_number', '')
                ))
                
                conn.commit()
                conn.close()
                
                # Audit log the inventory addition
                try:
                    from dmelogic.security.audit import audit_create
                    audit_create("inventory", None, f"Added: {item_data['hcpcs_code']} - {item_data['description']}")
                except Exception:
                    pass
                
                # Track supplier usage/name in suppliers database
                try:
                    if hasattr(self, 'save_supplier_name'):
                        self.save_supplier_name(item_data.get('source', ''))
                except Exception:
                    pass
                # Track category in categories master
                try:
                    if hasattr(self, 'save_category_name'):
                        self.save_category_name(item_data.get('category', ''))
                except Exception:
                    pass

                # Refresh inventory table
                self.load_inventory_data()
                QMessageBox.information(self, "Success", "Inventory item added successfully!")
                
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to add inventory item: {e}")
    
    def open_add_inventory_dialog(self):
        """Open non-modal dialog to add inventory item (can be called from order wizard)."""
        try:
            dialog = InventoryItemDialog(self)
            dialog.setModal(False)  # Make it non-modal
            dialog.setWindowFlags(
                Qt.WindowType.Window |
                Qt.WindowType.WindowMinimizeButtonHint |
                Qt.WindowType.WindowMaximizeButtonHint |
                Qt.WindowType.WindowCloseButtonHint
            )
            
            # Register as child window
            if hasattr(self, 'register_child_window'):
                self.register_child_window(dialog)
            
            # Connect accepted signal to refresh inventory
            def on_accepted():
                item_data = dialog.get_item_data()
                try:
                    conn = sqlite3.connect(self.inventory_database_file)
                    cursor = conn.cursor()
                    
                    cursor.execute("""
                        INSERT INTO inventory (
                            hcpcs_code, description, category, cost, retail_price,
                            brand, stock_quantity, reorder_level, supplier, notes,
                            created_date, updated_date, item_number, last_restocked_date
                        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), datetime('now'), ?, datetime('now'))
                    """, (
                        item_data['hcpcs_code'], item_data['description'],
                        item_data['category'], item_data['cost'], item_data['bill_amount'],
                        item_data.get('brand', ''), item_data['stock_quantity'], item_data['reorder_level'],
                        item_data['source'], item_data['notes'], item_data.get('item_number', '')
                    ))
                    
                    conn.commit()
                    conn.close()
                    
                    # Track supplier and category
                    try:
                        if hasattr(self, 'save_supplier_name'):
                            self.save_supplier_name(item_data.get('source', ''))
                        if hasattr(self, 'save_category_name'):
                            self.save_category_name(item_data.get('category', ''))
                    except Exception:
                        pass
                    
                    # Refresh inventory
                    self.load_inventory_data()
                    print(f"✅ Added inventory item: {item_data['hcpcs_code']} - {item_data['description']}")
                    
                except Exception as e:
                    QMessageBox.critical(self, "Error", f"Failed to add inventory item: {e}")
            
            dialog.accepted.connect(on_accepted)
            dialog.show()
            dialog.raise_()
            dialog.activateWindow()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to open add inventory dialog: {e}")

