    def choose_fee_schedule_file(self):
        """Allow the user to select an Excel file for the fee schedule and remember it."""
        try:
            start_dir = None
            try:
                if isinstance(self.settings, dict):
                    start_dir = self.settings.get('db_folder') or os.path.dirname(self.fee_schedule_path or '')
            except Exception:
                start_dir = None
            file_path, _ = QFileDialog.getOpenFileName(self, "Select Fee Schedule Excel", start_dir or os.getcwd(), "Excel Files (*.xlsx)")
            if not file_path:
                return
            self.fee_schedule_path = file_path
            if isinstance(self.settings, dict):
                self.settings['fee_schedule_path'] = file_path
                try:
                    self.save_settings()
                except Exception:
                    pass
            self.refresh_fee_schedule()

            # Keep shared fee_reader in sync after re-import
            try:
                if hasattr(self, 'fee_reader') and self.fee_reader:
                    self.fee_reader.reload(folder_path=self.folder_path)
            except Exception:
                pass
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to select fee schedule file: {e}")

