    def delete_inventory_item(self):
        """Delete selected inventory item."""
        current_row = self.inventory_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an inventory item to delete.")
            return
        
        # Get item details for confirmation
        item_id = self.inventory_table.item(current_row, 0).text()
        description = self.inventory_table.item(current_row, 2).text()
        
        reply = QMessageBox.question(
            self, "Confirm Delete", 
            f"Are you sure you want to delete this inventory item?\n\n{description}\n\nThis action cannot be undone.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            try:
                conn = sqlite3.connect(self.inventory_database_file)
                cursor = conn.cursor()
                cursor.execute("DELETE FROM inventory WHERE item_id = ?", (item_id,))
                conn.commit()
                conn.close()
                
                # Audit log the inventory deletion
                try:
                    from dmelogic.security.audit import audit_delete
                    audit_delete("inventory", item_id, f"Deleted: {description}")
                except Exception:
                    pass
                
                self.load_inventory_data()
                QMessageBox.information(self, "Success", "Inventory item deleted successfully!")
                
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to delete inventory item: {e}")

    def delete_order(self):
        """Delete selected order from the orders table."""
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order to delete.")
            return
        
        # Get order details for confirmation
        order_number = self.orders_table.item(current_row, 0).text()
        patient_name = self.orders_table.item(current_row, 1).text()
        item_desc = self.orders_table.item(current_row, 2).text()
        
        # Confirm deletion
        reply = QMessageBox.question(
            self, "Confirm Deletion", 
            f"Are you sure you want to delete this order?\n\n"
            f"Order #: {order_number}\n"
            f"Patient: {patient_name}\n"
            f"Item: {item_desc}\n\n"
            f"This action cannot be undone.",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            try:
                # Extract order ID from order number (e.g., "ORD-001" -> 1)
                if hasattr(self, 'orders_db_path'):
                    # If using real database, delete from DB
                    order_id_val = self.get_order_id_from_display(order_number)
                    if order_id_val:
                        # Log the complete order to deleted_orders table before removing
                        try:
                            self.log_deleted_order(int(order_id_val))
                        except Exception as e:
                            print(f"Deleted order logging failed: {e}")
                        
                        # Log RX deletions before removing items
                        try:
                            if hasattr(self, 'log_rx_deleted_for_order'):
                                self.log_rx_deleted_for_order(int(order_id_val))
                        except Exception as e:
                            print(f"RX delete logging failed: {e}")
                        # If this is a refill order, reverse the refill count to previous order in chain
                        try:
                            conn = sqlite3.connect(self.orders_db_path)
                            cursor = conn.cursor()
                            cursor.execute("SELECT COALESCE(parent_order_id,0), COALESCE(refill_number,0) FROM orders WHERE id = ?", (order_id_val,))
                            row = cursor.fetchone()
                            if row:
                                parent_id, rno = int(row[0] or 0), int(row[1] or 0)
                                if rno > 0 and parent_id:
                                    # Determine previous order id in chain
                                    if rno == 1:
                                        prev_id = parent_id
                                    else:
                                        cursor.execute("SELECT id FROM orders WHERE parent_order_id = ? AND refill_number = ?", (parent_id, rno - 1))
                                        prev_row = cursor.fetchone()
                                        prev_id = int(prev_row[0]) if prev_row else parent_id
                                    # Increment refills on previous order items by 1
                                    cursor.execute("SELECT id, COALESCE(refills,'') FROM order_items WHERE order_id = ?", (prev_id,))
                                    prev_items = cursor.fetchall()
                                    for (it_id, ref_val) in prev_items:
                                        try:
                                            n = int(float(str(ref_val).strip())) if str(ref_val).strip() != '' else 0
                                        except Exception:
                                            n = 0
                                        cursor.execute("UPDATE order_items SET refills = ? WHERE id = ?", (str(n + 1), it_id))
                                    # Unlock parent and clear refill_completed so it can be refilled again
                                    cursor.execute("UPDATE orders SET refill_completed = 0, refill_completed_at = NULL, is_locked = 0 WHERE id = ?", (prev_id,))
                                    conn.commit()
                            # Proceed to delete items and main order
                            cursor.execute("DELETE FROM order_items WHERE order_id = ?", (order_id_val,))
                            cursor.execute("DELETE FROM orders WHERE id = ?", (order_id_val,))
                            conn.commit()
                            conn.close()
                        except Exception as e:
                            QMessageBox.warning(self, "Refill Reversal Warning", f"Deleted order, but couldn't fully reverse refill counts: {e}")
                            try:
                                conn.close()
                            except Exception:
                                pass
                
                # Remove from table display
                self.orders_table.removeRow(current_row)
                
                # Audit log the order deletion
                try:
                    from dmelogic.security.audit import audit_delete
                    audit_delete("order", order_number, f"Deleted order for {patient_name}: {item_desc}")
                except Exception:
                    pass
                
                QMessageBox.information(self, "Success", f"Order {order_number} has been deleted.")
                
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to delete order: {e}")

    def delete_prescriber(self):
        """Delete selected prescriber."""
        current_row = self.prescriber_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select a prescriber to delete.")
            return
            
        try:
            # Get prescriber info from selected row
            # Column 0 = ID, Column 1 = Last Name, Column 2 = First Name
            last_name = self.prescriber_table.item(current_row, 1).text()
            first_name = self.prescriber_table.item(current_row, 2).text()
            npi = self.prescriber_table.item(current_row, 4).text()
            
            prescriber_name = f"{last_name}, {first_name}"
            
            # First, show dialog with all connected orders
            orders_dialog = PrescriberOrdersDialog(self, prescriber_name, npi)
            orders_dialog.exec()
            
            # After viewing orders, confirm deletion
            reply = QMessageBox.question(
                self, "Confirm Deletion",
                f"Are you sure you want to delete prescriber:\n{prescriber_name}?\n\n"
                "Note: This will NOT delete the associated orders, but future reports may be affected.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No
            )
            
            if reply == QMessageBox.StandardButton.Yes:
                # Get prescriber ID from database
                conn = sqlite3.connect(self.prescriber_database_file)
                cursor = conn.cursor()
                cursor.execute("""
                    SELECT id FROM prescribers 
                    WHERE last_name = ? AND first_name = ?
                """, (last_name, first_name))
                
                prescriber_id = cursor.fetchone()
                if prescriber_id:
                    # Delete prescriber
                    cursor.execute("DELETE FROM prescribers WHERE id = ?", (prescriber_id[0],))
                    conn.commit()
                    
                    # Audit log the prescriber deletion
                    try:
                        from dmelogic.security.audit import audit_delete
                        audit_delete("prescriber", prescriber_id[0], f"Deleted: {prescriber_name} (NPI: {npi})")
                    except Exception:
                        pass
                    
                    # Refresh the prescriber list
                    self.load_prescribers()
                    print(f"✅ Deleted prescriber: {last_name}, {first_name}")
                    QMessageBox.information(self, "Success", "Prescriber deleted successfully!")
                
                conn.close()
                
        except Exception as e:
            print(f"Error deleting prescriber: {e}")
            QMessageBox.critical(self, "Error", f"Failed to delete prescriber: {e}")

    def duplicate_inventory_item(self):
        """Duplicate selected inventory item."""
        current_row = self.inventory_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an inventory item to duplicate.")
            return
        
        # Get item ID from the first column
        item_id = self.inventory_table.item(current_row, 0).text()
        
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM inventory WHERE item_id = ?", (item_id,))
            item_data = cursor.fetchone()
            conn.close()
            
            if item_data:
                # Open dialog with existing data (but without item_id to create new)
                dialog = InventoryItemDialog(self, item_data)
                dialog.setWindowTitle("Duplicate Inventory Item")
                
                if dialog.exec() == QDialog.DialogCode.Accepted:
                    duplicated_data = dialog.get_item_data()
                    
                    conn = sqlite3.connect(self.inventory_database_file)
                    cursor = conn.cursor()
                    
                    cursor.execute("""
                        INSERT INTO inventory (
                            hcpcs_code, description, category, cost, retail_price,
                            brand, stock_quantity, reorder_level, supplier, notes,
                            created_date, updated_date, item_number
                        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now'), datetime('now'), ?)
                    """, (
                        duplicated_data['hcpcs_code'], duplicated_data['description'],
                        duplicated_data['category'], duplicated_data['cost'], duplicated_data['bill_amount'],
                        duplicated_data.get('brand', ''), duplicated_data['stock_quantity'],
                        duplicated_data['reorder_level'], duplicated_data['source'], duplicated_data['notes'],
                        duplicated_data.get('item_number', ''),
                    ))
                    
                    conn.commit()
                    conn.close()
                    
                    # Track supplier usage/name in suppliers database
                    try:
                        if hasattr(self, 'save_supplier_name'):
                            self.save_supplier_name(duplicated_data.get('source', ''))
                    except Exception:
                        pass
                    # Track category in categories master
                    try:
                        if hasattr(self, 'save_category_name'):
                            self.save_category_name(duplicated_data.get('category', ''))
                    except Exception:
                        pass

                    self.load_inventory_data()
                    QMessageBox.information(self, "Success", "Inventory item duplicated successfully!")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to duplicate inventory item: {e}")

    def edit_inventory_item(self):
        """Edit selected inventory item."""
        current_row = self.inventory_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an inventory item to edit.")
            return
        
        # Get item ID from the first column
        item_id = self.inventory_table.item(current_row, 0).text()
        
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT item_id, hcpcs_code, description, category, cost, 
                       retail_price, brand, supplier, stock_quantity, reorder_level, notes
                FROM inventory WHERE item_id = ?
            """, (item_id,))
            item_data = cursor.fetchone()
            conn.close()
            
            if item_data:
                old_stock = item_data[8]  # Current stock quantity
                dialog = InventoryItemDialog(self, item_data)
                if dialog.exec() == QDialog.DialogCode.Accepted:
                    updated_data = dialog.get_item_data()
                    new_stock = updated_data['stock_quantity']
                    
                    conn = sqlite3.connect(self.inventory_database_file)
                    cursor = conn.cursor()
                    
                    # Check if stock increased (restocked)
                    if new_stock > old_stock:
                        cursor.execute("""
                            UPDATE inventory SET
                                hcpcs_code = ?, description = ?, category = ?, cost = ?,
                                retail_price = ?, brand = ?, stock_quantity = ?, reorder_level = ?,
                                supplier = ?, notes = ?, item_number = ?, updated_date = datetime('now'),
                                last_restocked_date = datetime('now')
                            WHERE item_id = ?
                        """, (
                            updated_data['hcpcs_code'], updated_data['description'],
                            updated_data['category'], updated_data['cost'],
                            updated_data['bill_amount'], updated_data.get('brand', ''),
                            updated_data['stock_quantity'], updated_data['reorder_level'],
                            updated_data['source'], updated_data['notes'], updated_data.get('item_number', ''), item_id,
                        ))
                        
                        # Log transaction
                        qty_added = new_stock - old_stock
                        cursor.execute("""
                            INSERT INTO inventory_transactions 
                            (item_id, transaction_type, quantity, reference_id, transaction_date, notes)
                            VALUES (?, 'IN', ?, 'RESTOCK', datetime('now'), ?)
                        """, (item_id, qty_added, f"Restocked: {old_stock} → {new_stock}"))
                    else:
                        cursor.execute("""
                            UPDATE inventory SET
                                hcpcs_code = ?, description = ?, category = ?, cost = ?,
                                retail_price = ?, brand = ?, stock_quantity = ?, reorder_level = ?,
                                supplier = ?, notes = ?, item_number = ?, updated_date = datetime('now')
                            WHERE item_id = ?
                        """, (
                            updated_data['hcpcs_code'], updated_data['description'],
                            updated_data['category'], updated_data['cost'],
                            updated_data['bill_amount'], updated_data.get('brand', ''),
                            updated_data['stock_quantity'], updated_data['reorder_level'],
                            updated_data['source'], updated_data['notes'], updated_data.get('item_number', ''), item_id,
                        ))
                    
                    conn.commit()
                    conn.close()
                    
                    # Track supplier usage/name in suppliers database
                    try:
                        if hasattr(self, 'save_supplier_name'):
                            self.save_supplier_name(updated_data.get('source', ''))
                    except Exception:
                        pass
                    # Track category in categories master
                    try:
                        if hasattr(self, 'save_category_name'):
                            self.save_category_name(updated_data.get('category', ''))
                    except Exception:
                        pass

                    self.load_inventory_data()
                    QMessageBox.information(self, "Success", "Inventory item updated successfully!")
        
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to edit inventory item: {e}")

