    def generate_order_report(self):
        """Generate an Order Report in table format with items listed vertically for better pagination.

        When an order has multiple HCPCS items, they are listed one per row beneath the order header.
        Columns: ORDER # | ORDER DATE | PATIENT NAME | DOB | PRESCRIBER | HCPCS +QTY | STATUS
        """
        try:
            import sqlite3
            # Reset current report buffers
            self.current_report_headers = None
            self.current_report_rows = None
            self.current_report_summary_lines = None
            self.current_report_title = "Order Report"

            # ISO for DB filtering
            start_date = self.report_start_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_start_date') else None
            end_date = self.report_end_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_end_date') else None
            # Pretty for display
            start_display = self.report_start_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_start_date') else None
            end_display = self.report_end_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_end_date') else None

            # Include date range in the report title if provided
            title_text = "Order Report"
            if start_date and end_date:
                title_text = f"{title_text} — {start_display} to {end_display}"
            self.current_report_title = title_text

            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()

            # Normalize date for filtering/sorting: prefer order_date, fallback to rx_date if missing
            # Convert MM/DD/YYYY -> YYYY-MM-DD on the fly for proper comparisons
            norm_used_date = (
                "CASE WHEN instr(COALESCE(NULLIF(order_date,''), rx_date),'/')>0 "
                "THEN substr(COALESCE(NULLIF(order_date,''), rx_date),7,4)||'-'||substr(COALESCE(NULLIF(order_date,''), rx_date),1,2)||'-'||substr(COALESCE(NULLIF(order_date,''), rx_date),4,2) "
                "ELSE COALESCE(NULLIF(order_date,''), rx_date) END"
            )

            # Build base query with optional date filtering (use normalized date for correctness)
            params = []
            date_clause = ""
            if start_date and end_date:
                date_clause = f" WHERE {norm_used_date} BETWEEN ? AND ?"
                params = [start_date, end_date]

            cur.execute(
                f"""
          SELECT id, COALESCE(NULLIF(order_date,''), rx_date) as used_date, patient_last_name, patient_first_name,
                       COALESCE(patient_dob,''),
                       COALESCE(prescriber_name,''),
                       COALESCE(order_status,'')
                FROM orders{date_clause}
          ORDER BY {norm_used_date} DESC, id DESC
                """,
                params,
            )
            orders = cur.fetchall()

            # Collect per-order data; structure will list items vertically (one row per item)
            per_order = []
            total_item_count = 0
            for oid, odate, ln, fn, dob, presc, status in orders:
                # Trim prescriber to name only (strip practice and NPI if present)
                presc_name = (presc or "").split(" - ")[0]
                if "(" in presc_name:
                    presc_name = presc_name.split("(")[0]
                presc_name = presc_name.strip()

                # Uppercase formatting to match template style
                patient_name = f"{(ln or '').strip()}, {(fn or '').strip()}".strip().strip(', ')
                patient_name = patient_name.upper()
                presc_name = presc_name.upper()

                try:
                    cur.execute(
                        "SELECT COALESCE(hcpcs_code,''), COALESCE(qty,'') FROM order_items WHERE order_id = ? AND COALESCE(hcpcs_code,'') <> '' ORDER BY id ASC",
                        (oid,),
                    )
                    items = cur.fetchall()
                except Exception:
                    items = []
                codes_with_qty = []
                for code, qty in items:
                    code = (code or '').strip()
                    qty = (str(qty) or '').strip()
                    if code:
                        if qty:
                            codes_with_qty.append(f"{code} x{qty}")
                        else:
                            codes_with_qty.append(code)
                total_item_count += len(codes_with_qty)

                # Fallback: if DOB missing in orders, try to pull from patients.db by name
                dob_value = dob or ""
                if not dob_value:
                    try:
                        pconn = sqlite3.connect(self.patient_database_file)
                        pcur = pconn.cursor()
                        pcur.execute(
                            "SELECT COALESCE(dob,'') FROM patients WHERE last_name = ? AND first_name = ? ORDER BY updated_date DESC LIMIT 1",
                            (ln or '', fn or ''),
                        )
                        prow = pcur.fetchone()
                        if prow and prow[0]:
                            dob_value = prow[0]
                        pconn.close()
                    except Exception:
                        pass

                per_order.append({
                    'oid': oid,
                    'odate': self.format_date_display(odate or ""),
                    'patient': patient_name,
                    'dob': self.format_date_display(dob_value),
                    'presc': presc_name,
                    'codes': codes_with_qty,
                    'status': status or "",
                })

            # Simplified headers for vertical item listing
            headers = [
                "ORDER #",
                "ORDER DATE",
                "PATIENT NAME(LAST, FIRST )",
                "DOB",
                "PRESCRIBER",
                "HCPCS +QTY",
                "STATUS"
            ]

            # Build rows: each order gets one or more rows (one per HCPCS item)
            # If an order has no items, still show one row with empty HCPCS
            rows = []
            for entry in per_order:
                order_num = self.format_order_number(entry['oid']) if hasattr(self, 'format_order_number') else entry['oid']
                if not entry['codes']:
                    # No items: show one row with empty HCPCS
                    rows.append([
                        order_num,
                        entry['odate'],
                        entry['patient'],
                        entry['dob'],
                        entry['presc'],
                        "",
                        entry['status'],
                    ])
                else:
                    # Multiple items: first item shows all order info, subsequent items show only HCPCS
                    for idx, hcpcs in enumerate(entry['codes']):
                        if idx == 0:
                            # First row: full order details
                            rows.append([
                                order_num,
                                entry['odate'],
                                entry['patient'],
                                entry['dob'],
                                entry['presc'],
                                hcpcs,
                                entry['status'],
                            ])
                        else:
                            # Subsequent rows: blank order details, just HCPCS
                            rows.append([
                                "",
                                "",
                                "",
                                "",
                                "",
                                hcpcs,
                                "",
                            ])

            conn.close()

            # Store for export
            self.current_report_headers = headers
            self.current_report_rows = rows

            # Build summary for the bottom of the report (within date range if provided)
            # Re-open for summary queries
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            # Counts (use per_order list for accurate order count, not rows)
            total_orders = None
            try:
                cur.execute("SELECT COUNT(*) FROM orders")
                total_orders = cur.fetchone()[0]
            except Exception:
                total_orders = len(per_order)

            range_count = len(per_order)  # Number of orders, not rows

            status_list = ["Pending", "Ready", "Picked Up", "Delivered", "Cancelled"]
            status_counts = {}
            try:
                if date_clause:
                    cur.execute(
                        f"SELECT COALESCE(order_status,''), COUNT(*) FROM orders WHERE {norm_used_date} BETWEEN ? AND ? GROUP BY order_status",
                        (start_date, end_date),
                    )
                else:
                    cur.execute("SELECT COALESCE(order_status,''), COUNT(*) FROM orders GROUP BY order_status")
                for s, c in cur.fetchall():
                    status_counts[s or ""] = c
            except Exception:
                status_counts = {}

            # Top HCPCS with description and total units in selected range
            try:
                if date_clause:
                    # Normalize used date (order_date or fallback rx_date) for correct range filtering
                    cur.execute(
                        f"""
                        SELECT oi.hcpcs_code, COALESCE(oi.description,''), COALESCE(oi.qty,'')
                        FROM order_items oi
                        JOIN orders o ON o.id = oi.order_id
                        WHERE COALESCE(oi.hcpcs_code,'') <> ''
                          AND CASE WHEN instr(COALESCE(NULLIF(o.order_date,''), o.rx_date),'/')>0
                                   THEN substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),7,4)||'-'||substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),1,2)||'-'||substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),4,2)
                                   ELSE COALESCE(NULLIF(o.order_date,''), o.rx_date) END BETWEEN ? AND ?
                        """,
                        (start_date, end_date),
                    )
                else:
                    cur.execute(
                        "SELECT COALESCE(hcpcs_code,''), COALESCE(description,''), COALESCE(qty,'') FROM order_items WHERE COALESCE(hcpcs_code,'') <> ''"
                    )
                agg = {}
                for code, desc, qty in cur.fetchall():
                    code = (code or '').strip()
                    desc = (desc or '').strip()
                    try:
                        q = float(str(qty).strip()) if str(qty).strip() else 0.0
                    except Exception:
                        q = 0.0
                    key = (code, desc)
                    agg[key] = agg.get(key, 0.0) + q
                # Sort by total units desc and take top 10
                top_units = sorted(agg.items(), key=lambda kv: kv[1], reverse=True)[:10]
            except Exception:
                top_units = []
            conn.close()

            summary_lines = []
            summary_lines.append(f"Total orders: {total_orders if total_orders is not None else len(per_order)}")
            summary_lines.append(f"Orders in range: {range_count}")
            summary_lines.append(f"Total items in range: {total_item_count}")
            summary_lines.append("")
            summary_lines.append("By Status:")
            for label in status_list:
                summary_lines.append(f"• {label}: {status_counts.get(label, 0)}")
            summary_lines.append("")
            summary_lines.append("Top HCPCS:")
            if top_units:
                for (code, desc), total_q in top_units:
                    units_str = (
                        f"{int(total_q)}" if abs(total_q - int(total_q)) < 1e-6 else f"{total_q:g}"
                    )
                    label_desc = f" - {desc}" if desc else ""
                    summary_lines.append(f"• {code}{label_desc}: {units_str} UNITS")
            else:
                summary_lines.append("• None")

            self.current_report_summary_lines = summary_lines

            # Build an HTML table preview for proper alignment
            html = []
            html.append('<div style="font-family:Segoe UI, Arial, sans-serif; font-size:11px; color:#000;">')
            html.append(f'<div style="margin-bottom:6px; font-weight:600; color:#000;">{title_text} (preview)</div>')
            html.append('<table style="border-collapse:collapse; width:100%;">')
            # Header row
            html.append('<tr>')
            for h in headers:
                html.append(f'<th style="border:1px solid #999; padding:4px 6px; text-align:left; background:#f0f0f0; color:#000;">{h}</th>')
            html.append('</tr>')
            # Data rows
            for r in rows[:200]:
                html.append('<tr>')
                for c in r:
                    html.append(f'<td style="border:1px solid #999; padding:4px 6px; text-align:left; color:#000;">{str(c)}</td>')
                html.append('</tr>')
            html.append('</table>')
            # Summary
            html.append('<div style="margin-top:10px; white-space:pre-wrap; color:#000;">')
            html.append("\n".join(summary_lines))
            html.append('</div>')
            html.append('</div>')

            self.reports_text.setHtml("".join(html))
            # Update embedded visuals
            if hasattr(self, 'update_reports_visuals'):
                self.update_reports_visuals(report_type="orders")

            # If we have rows, also generate a PDF file and show location
            try:
                if rows and len(rows) > 0:
                    pdf_path = self._save_current_report_pdf(dest_dir=None, silent=True)
                    if pdf_path and os.path.exists(pdf_path):
                        # Show PDF location in status bar instead of switching tabs
                        self.statusBar().showMessage(f"✅ Report generated: {pdf_path}", 10000)
                        # Offer to open in default PDF viewer
                        reply = QMessageBox.question(
                            self,
                            "Report Generated",
                            f"Report saved to:\n{pdf_path}\n\nOpen in default PDF viewer?",
                            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                            QMessageBox.StandardButton.Yes
                        )
                        if reply == QMessageBox.StandardButton.Yes:
                            try:
                                os.startfile(pdf_path)
                            except Exception as e:
                                QMessageBox.warning(self, "Open PDF", f"Could not open PDF: {e}")
                    else:
                        QMessageBox.warning(self, "No Data", "No orders found in the selected date range.")
                else:
                    QMessageBox.warning(self, "No Data", "No orders found in the selected date range.")
            except Exception as _e:
                # Non-fatal: leave preview visible
                pass
        except Exception as e:
            self.reports_text.setPlainText(f"Error generating order report: {e}")

    def generate_profit_report_per_order(self):
        """Profit report at the order level using billed totals minus inventory cost."""
        try:
            import sqlite3
            from decimal import Decimal, InvalidOperation

            # Reset buffers
            self.current_report_headers = None
            self.current_report_rows = None
            self.current_report_summary_lines = None
            self.current_report_title = "Profit Report"

            # Date range
            start_date = self.report_start_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_start_date') else None
            end_date = self.report_end_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_end_date') else None
            start_display = self.report_start_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_start_date') else None
            end_display = self.report_end_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_end_date') else None

            title_text = "Profit Report (per Order)"
            if start_date and end_date:
                title_text = f"{title_text} — {start_display} to {end_display}"
            self.current_report_title = title_text

            # Helper to parse decimals safely
            def dec(val) -> Decimal:
                try:
                    return Decimal(str(val))
                except (InvalidOperation, TypeError, ValueError):
                    return Decimal("0")

            # Load inventory costs once
            inv_costs: dict[str, Decimal] = {}
            try:
                iconn = sqlite3.connect(self.inventory_database_file)
                icur = iconn.cursor()
                icur.execute("SELECT UPPER(COALESCE(hcpcs_code,'')), COALESCE(cost, 0) FROM inventory")
                for code, cost_val in icur.fetchall():
                    inv_costs[code or ""] = dec(cost_val)
                iconn.close()
            except Exception:
                inv_costs = {}

            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()

            norm_used_date = (
                "CASE WHEN instr(COALESCE(NULLIF(order_date,''), rx_date),'/')>0 "
                "THEN substr(COALESCE(NULLIF(order_date,''), rx_date),7,4)||'-'||substr(COALESCE(NULLIF(order_date,''), rx_date),1,2)||'-'||substr(COALESCE(NULLIF(order_date,''), rx_date),4,2) "
                "ELSE COALESCE(NULLIF(order_date,''), rx_date) END"
            )

            params = []
            date_clause = ""
            status_clause = " WHERE LOWER(COALESCE(order_status,'')) IN ('billed','shipped','delivered','picked up')"
            if start_date and end_date:
                date_clause = f" AND {norm_used_date} BETWEEN ? AND ?"
                params = [start_date, end_date]

            cur.execute(
                f"""
                SELECT id, COALESCE(NULLIF(order_date,''), rx_date) AS used_date,
                       COALESCE(patient_last_name,''), COALESCE(patient_first_name,''),
                       COALESCE(order_status,'')
                FROM orders{status_clause}{date_clause}
                ORDER BY {norm_used_date} DESC, id DESC
                """,
                params,
            )
            orders = cur.fetchall()

            headers = [
                "ORDER #",
                "ORDER DATE",
                "PATIENT",
                "STATUS",
                "ITEMS",
                "REVENUE",
                "COST",
                "PROFIT",
                "MARGIN %",
            ]

            rows = []
            total_revenue = Decimal("0")
            total_cost = Decimal("0")

            for oid, odate, ln, fn, status in orders:
                cur.execute(
                    "SELECT COALESCE(hcpcs_code,''), COALESCE(qty,''), COALESCE(total,''), COALESCE(cost_ea,'') FROM order_items WHERE order_id = ?",
                    (oid,),
                )
                items = cur.fetchall()

                item_count = 0
                revenue = Decimal("0")
                cost = Decimal("0")

                for code, qty_raw, total_raw, unit_raw in items:
                    qty = dec(qty_raw)
                    total_val = dec(total_raw)
                    if total_val == 0 and unit_raw not in (None, ""):
                        total_val = dec(unit_raw) * qty
                    revenue += total_val

                    inv_cost = inv_costs.get((code or "").upper(), Decimal("0"))
                    if inv_cost == 0 and unit_raw not in (None, ""):
                        # If no inventory cost, use provided unit price as cost baseline
                        inv_cost = dec(unit_raw)
                    cost += inv_cost * qty
                    item_count += 1

                profit = revenue - cost
                margin = (profit / revenue * Decimal("100")) if revenue > 0 else Decimal("0")

                total_revenue += revenue
                total_cost += cost

                rows.append([
                    self.format_order_number(oid) if hasattr(self, 'format_order_number') else oid,
                    self.format_date_display(odate or ""),
                    f"{(ln or '').upper()}, {(fn or '').upper()}",
                    status,
                    item_count,
                    f"${revenue:,.2f}",
                    f"${cost:,.2f}",
                    f"${profit:,.2f}",
                    f"{margin:.1f}%",
                ])

            conn.close()

            total_profit = total_revenue - total_cost
            overall_margin = (total_profit / total_revenue * Decimal("100")) if total_revenue > 0 else Decimal("0")

            self.current_report_headers = headers
            self.current_report_rows = rows

            summary_lines = [
                f"Orders in range: {len(rows)}",
                f"Total revenue: ${total_revenue:,.2f}",
                f"Total cost: ${total_cost:,.2f}",
                f"Total profit: ${total_profit:,.2f}",
                f"Avg margin: {overall_margin:.1f}%",
            ]
            self.current_report_summary_lines = summary_lines

            html = []
            html.append('<div style="font-family:Segoe UI, Arial, sans-serif; font-size:11px; color:#000;">')
            html.append(f'<div style="margin-bottom:6px; font-weight:600; color:#000;">{title_text} (preview)</div>')
            html.append('<table style="border-collapse:collapse; width:100%;">')
            html.append('<tr>')
            for h in headers:
                html.append(f'<th style="border:1px solid #999; padding:4px 6px; text-align:left; background:#f0f0f0; color:#000;">{h}</th>')
            html.append('</tr>')
            for r in rows[:200]:
                html.append('<tr>')
                for c in r:
                    html.append(f'<td style="border:1px solid #999; padding:4px 6px; text-align:left; color:#000;">{c}</td>')
                html.append('</tr>')
            html.append('</table>')
            html.append('<div style="margin-top:10px; white-space:pre-wrap; color:#000;">')
            html.append("\n".join(summary_lines))
            html.append('</div>')
            html.append('</div>')

            self.reports_text.setHtml("".join(html))
            if hasattr(self, 'update_reports_visuals'):
                self.update_reports_visuals(report_type="profit")

            try:
                if rows:
                    pdf_path = self._save_current_report_pdf(dest_dir=None, silent=True)
                    if pdf_path and os.path.exists(pdf_path):
                        self.statusBar().showMessage(f"✅ Profit report saved: {pdf_path}", 10000)
                        reply = QMessageBox.question(
                            self,
                            "Report Generated",
                            f"Report saved to:\n{pdf_path}\n\nOpen in default PDF viewer?",
                            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                            QMessageBox.StandardButton.No
                        )
                        if reply == QMessageBox.StandardButton.Yes:
                            try:
                                os.startfile(pdf_path)
                            except Exception:
                                pass
                else:
                    QMessageBox.information(self, "Profit Report", "No orders found in the selected date range.")
            except Exception:
                pass
        except Exception as e:
            self.reports_text.setPlainText(f"Error generating profit report: {e}")

