    def generate_reconciliation_report(self):
        """Generate billing reconciliation report with a bordered table preview and structured export."""
        try:
            import sqlite3
            # Reset current report buffers
            self.current_report_headers = None
            self.current_report_rows = None
            self.current_report_summary_lines = None
            self.current_report_title = "Billing & Payment Reconciliation Report"

            # ISO for DB filtering
            start_date = self.report_start_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_start_date') else None
            end_date = self.report_end_date.date().toString("yyyy-MM-dd") if hasattr(self, 'report_end_date') else None
            # Pretty for display
            start_display = self.report_start_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_start_date') else None
            end_display = self.report_end_date.date().toString("MM/dd/yyyy") if hasattr(self, 'report_end_date') else None

            # Include date range in the report title if provided
            if start_date and end_date:
                self.current_report_title = f"Billing Reconciliation — {start_display} to {end_display}"

            # Prefer orders_database_file, fallback to orders_db_path if present
            db_path = getattr(self, 'orders_database_file', None) or getattr(self, 'orders_db_path', None)
            conn = sqlite3.connect(db_path)
            cur = conn.cursor()

            # Filter by order_date with fallback to rx_date if range is provided; normalize to ISO for saved MM/DD/YYYY
            params = []
            date_clause = ""
            if start_date and end_date:
                # We'll inject a normalized date expression in the WHERE below
                date_clause = " AND {NORM_DATE} BETWEEN ? AND ?"
                params = [start_date, end_date]

            # Get all orders with itemized details
            norm_order_date = (
                "CASE WHEN instr(COALESCE(NULLIF(o.order_date,''), o.rx_date),'/')>0 "
                "THEN substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),7,4)||'-'||substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),1,2)||'-'||substr(COALESCE(NULLIF(o.order_date,''), o.rx_date),4,2) "
                "ELSE COALESCE(NULLIF(o.order_date,''), o.rx_date) END"
            )
            where_clause = (date_clause.replace("{NORM_DATE}", norm_order_date) if date_clause else "")
            cur.execute(
                f"""
                SELECT o.id, COALESCE(NULLIF(o.order_date,''), o.rx_date) as used_date, o.patient_last_name, o.patient_first_name,
                       o.prescriber_name, o.order_status, COALESCE(o.billed, 0), 
                       COALESCE(o.paid, 0), o.paid_date
                FROM orders o
                WHERE 1=1{where_clause}
                ORDER BY {norm_order_date} DESC, o.id DESC
                """,
                params,
            )
            orders = cur.fetchall()

            # Prepare itemized list with revenue
            rows = []
            total_revenue = 0.0
            billed_revenue = 0.0
            paid_revenue = 0.0
            unbilled_revenue = 0.0
            unpaid_revenue = 0.0
            billed_count = 0
            paid_count = 0

            headers = ["ORDER", "DATE", "PATIENT", "PRESCRIBER", "STATUS", "BILLED", "PAID", "REVENUE"]

            for order in orders:
                order_id, used_date, last_name, first_name, prescriber, status, is_billed, is_paid, paid_date = order

                # Revenue for this order
                # Robust revenue calculation: prefer stored total; fallback to qty * cost_ea when total is empty
                cur.execute(
                    """
                    SELECT COALESCE(
                               SUM(CASE WHEN COALESCE(NULLIF(total,''), '') <> '' THEN CAST(total AS REAL) ELSE NULL END),
                               SUM(CAST(COALESCE(NULLIF(qty,''),'0') AS REAL) * CAST(COALESCE(NULLIF(cost_ea,''),'0') AS REAL))
                           )
                    FROM order_items
                    WHERE order_id = ?
                    """,
                    (order_id,),
                )
                revenue = cur.fetchone()[0] or 0.0

                order_num = self.format_order_number(order_id) if hasattr(self, 'format_order_number') else f"ORD-{order_id:03d}"
                patient_name = f"{(last_name or '').upper()}, {(first_name or '').upper()}".strip().strip(', ')
                presc_name = (prescriber or "N/A").split(" - ")[0]
                if "(" in presc_name:
                    presc_name = presc_name.split("(")[0]
                presc_name = presc_name.strip().upper() or "N/A"

                # For reconciliation: treat all statuses as "Billed" except Hold/On Hold or Unbilled
                status_lower = (status or "").lower().strip()
                is_billed_by_status = status_lower not in ("hold", "on hold", "unbilled")
                
                billed_status = "✅ Yes" if is_billed_by_status else "⚠️ No"
                paid_status = "✅ Yes" if is_paid else "⚠️ No"

                rows.append([
                    order_num,
                    self.format_date_display(used_date) if hasattr(self, 'format_date_display') else (used_date or ""),
                    patient_name,
                    presc_name,
                    (status or "Pending"),
                    billed_status,
                    paid_status,
                    f"${revenue:,.2f}",
                ])

                total_revenue += revenue
                if is_billed_by_status:
                    billed_count += 1
                    billed_revenue += revenue
                else:
                    unbilled_revenue += revenue
                if is_paid:
                    paid_count += 1
                    paid_revenue += revenue
                else:
                    unpaid_revenue += revenue

            conn.close()

            # Store for export
            self.current_report_headers = headers
            self.current_report_rows = rows

            # Summary lines
            summary_lines = []
            summary_lines.append(f"Total Orders: {len(orders)}")
            summary_lines.append("")
            summary_lines.append("Billing Status:")
            summary_lines.append(
                f"• Billed Orders: {billed_count} ({(billed_count/len(orders)*100):.1f}%)" if len(orders) > 0 else "• Billed Orders: 0"
            )
            summary_lines.append(
                f"• Unbilled Orders: {len(orders)-billed_count} ({((len(orders)-billed_count)/len(orders)*100):.1f}%)" if len(orders) > 0 else "• Unbilled Orders: 0"
            )
            summary_lines.append(f"• Billed Revenue: ${billed_revenue:,.2f}")
            summary_lines.append(f"• Unbilled Revenue: ${unbilled_revenue:,.2f}")
            summary_lines.append("")
            summary_lines.append("Payment Status:")
            summary_lines.append(
                f"• Paid Orders: {paid_count} ({(paid_count/len(orders)*100):.1f}%)" if len(orders) > 0 else "• Paid Orders: 0"
            )
            summary_lines.append(
                f"• Unpaid Orders: {len(orders)-paid_count} ({((len(orders)-paid_count)/len(orders)*100):.1f}%)" if len(orders) > 0 else "• Unpaid Orders: 0"
            )
            summary_lines.append(f"• Paid Revenue: ${paid_revenue:,.2f}")
            summary_lines.append(f"• Unpaid Revenue: ${unpaid_revenue:,.2f}")
            summary_lines.append("")
            summary_lines.append(f"TOTAL REVENUE: ${total_revenue:,.2f}")
            self.current_report_summary_lines = summary_lines

            # HTML preview with borders similar to Orders table
            title_text = self.current_report_title
            html = []
            html.append('<div style="font-family:Segoe UI, Arial, sans-serif; font-size:11px; color:#000;">')
            html.append(f'<div style="margin-bottom:6px; font-weight:600; color:#000;">{title_text} (preview)</div>')
            html.append('<table style="border-collapse:collapse; width:100%;">')
            # Header row
            html.append('<tr>')
            for h in headers:
                html.append(f'<th style="border:1px solid #999; padding:4px 6px; text-align:left; background:#f0f0f0; color:#000;">{h}</th>')
            html.append('</tr>')
            # Rows (limit for performance)
            for r in rows[:500]:
                html.append('<tr>')
                for c in r:
                    html.append(f'<td style="border:1px solid #999; padding:4px 6px; text-align:left; color:#000;">{str(c)}</td>')
                html.append('</tr>')
            html.append('</table>')
            # Summary
            html.append('<div style="margin-top:10px; white-space:pre-wrap; color:#000;">')
            html.append("\n".join(summary_lines))
            html.append('</div>')
            html.append('</div>')

            self.reports_text.setHtml("".join(html))
            if hasattr(self, 'update_reports_visuals'):
                self.update_reports_visuals(report_type="reconciliation")

            # Also render to PDF and show location, if there is data
            try:
                if rows and len(rows) > 0:
                    pdf_path = self._save_current_report_pdf(dest_dir=None, silent=True)
                    if pdf_path and os.path.exists(pdf_path):
                        # Show PDF location in status bar instead of switching tabs
                        self.statusBar().showMessage(f"✅ Reconciliation report generated: {pdf_path}", 10000)
                        # Offer to open in default PDF viewer
                        reply = QMessageBox.question(
                            self,
                            "Report Generated",
                            f"Reconciliation report saved to:\n{pdf_path}\n\nOpen in default PDF viewer?",
                            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                            QMessageBox.StandardButton.Yes
                        )
                        if reply == QMessageBox.StandardButton.Yes:
                            try:
                                os.startfile(pdf_path)
                            except Exception as e:
                                QMessageBox.warning(self, "Open PDF", f"Could not open PDF: {e}")
                    else:
                        QMessageBox.warning(self, "No Data", "No orders found in the selected date range.")
                else:
                    QMessageBox.warning(self, "No Data", "No orders found in the selected date range.")
            except Exception:
                pass
        except Exception as e:
            import traceback
            self.reports_text.setPlainText(f"Error generating reconciliation report: {e}\n\nStack trace:\n{traceback.format_exc()}")

    def import_payment_reconciliation(self):
        """
        Import a Medicaid remittance CSV file and auto-mark orders as paid.
        
        Matches by: Patient Last Name + Service Date + Amount (within $0.01 tolerance)
        
        Expected CSV columns:
        - patient_name: Patient last name
        - service_date: Date of service (column K)
        - amount_paid: Payment amount
        - cycle_date: Payment cycle date (used as paid_date)
        - tcn: Transaction Control Number (optional, for reference)
        """
        import csv
        import sqlite3
        from datetime import datetime
        from PyQt6.QtWidgets import QFileDialog, QMessageBox, QProgressDialog
        from PyQt6.QtCore import Qt
        
        # Open file dialog
        file_path, _ = QFileDialog.getOpenFileName(
            self,
            "Select Medicaid Remittance CSV",
            "",
            "CSV Files (*.csv);;All Files (*)"
        )
        
        if not file_path:
            return
        
        try:
            # Read CSV file
            with open(file_path, 'r', encoding='utf-8-sig') as f:
                reader = csv.DictReader(f)
                rows = list(reader)
            
            if not rows:
                QMessageBox.warning(self, "Empty File", "The selected CSV file contains no data.")
                return
            
            # Validate required columns - now using name, service_date, amount
            required_cols = ['patient_name', 'service_date', 'amount_paid']
            first_row_keys = [k.lower().strip() for k in rows[0].keys()]
            missing = [c for c in required_cols if c not in first_row_keys]
            if missing:
                QMessageBox.warning(
                    self, 
                    "Missing Columns", 
                    f"CSV is missing required columns: {', '.join(missing)}\n\n"
                    f"Required: patient_name, service_date, amount_paid\n"
                    f"Found columns: {', '.join(rows[0].keys())}"
                )
                return
            
            # Normalize column names in rows
            normalized_rows = []
            for row in rows:
                normalized = {k.lower().strip(): v for k, v in row.items()}
                normalized_rows.append(normalized)
            rows = normalized_rows
            
            # Get database connection
            db_path = getattr(self, 'orders_database_file', None) or getattr(self, 'orders_db_path', None)
            conn = sqlite3.connect(db_path)
            conn.row_factory = sqlite3.Row
            cur = conn.cursor()
            
            # Pre-load all unpaid orders with their revenue for efficient matching
            # Query orders and calculate revenue from order_items
            cur.execute("""
                SELECT o.id, o.patient_last_name, o.patient_first_name,
                       COALESCE(NULLIF(o.order_date,''), o.rx_date) as service_date,
                       o.paid, o.order_status,
                       COALESCE(
                           (SELECT SUM(CASE WHEN COALESCE(NULLIF(total,''), '') <> '' 
                                       THEN CAST(total AS REAL) 
                                       ELSE CAST(COALESCE(NULLIF(qty,''),'0') AS REAL) * CAST(COALESCE(NULLIF(cost_ea,''),'0') AS REAL) 
                                       END)
                            FROM order_items WHERE order_id = o.id), 0
                       ) as revenue
                FROM orders o
            """)
            all_orders = cur.fetchall()
            
            # Build lookup dict: key = (last_name_upper, normalized_date, rounded_amount)
            def normalize_date(date_str):
                """Convert various date formats to MM/DD/YYYY for comparison"""
                if not date_str:
                    return None
                date_str = str(date_str).strip()
                # Try different formats
                for fmt in ("%m/%d/%Y", "%Y-%m-%d", "%m-%d-%Y", "%m/%d/%y"):
                    try:
                        dt = datetime.strptime(date_str, fmt)
                        return dt.strftime("%m/%d/%Y")
                    except:
                        pass
                return date_str  # Return as-is if can't parse
            
            order_lookup = {}
            for order in all_orders:
                last_name = (order['patient_last_name'] or '').strip().upper()
                svc_date = normalize_date(order['service_date'])
                revenue = round(float(order['revenue'] or 0), 2)
                
                # Create key for lookup
                key = (last_name, svc_date, revenue)
                if key not in order_lookup:
                    order_lookup[key] = []
                order_lookup[key].append(dict(order))
            
            # Progress dialog
            progress = QProgressDialog("Processing payments...", "Cancel", 0, len(rows), self)
            progress.setWindowModality(Qt.WindowModality.WindowModal)
            progress.setMinimumDuration(0)
            
            # Track results
            matched_count = 0
            already_paid_count = 0
            not_found_count = 0
            updated_orders = []
            not_found_records = []
            
            today_str = datetime.now().strftime("%m/%d/%Y")
            
            for idx, row in enumerate(rows):
                if progress.wasCanceled():
                    break
                    
                progress.setValue(idx)
                
                # Get matching fields from CSV
                patient_name = (row.get('patient_name', '') or '').strip().upper()
                service_date = normalize_date(row.get('service_date', ''))
                try:
                    amount_paid = round(float(row.get('amount_paid', '0') or '0'), 2)
                except:
                    amount_paid = 0.0
                
                if not patient_name or not service_date:
                    not_found_count += 1
                    not_found_records.append(row)
                    continue
                
                # Look up by exact match: name + date + amount
                key = (patient_name, service_date, amount_paid)
                matches = order_lookup.get(key, [])
                
                # If no exact match, try with $0.01 tolerance on amount
                if not matches:
                    for amt_offset in [0.01, -0.01, 0.02, -0.02]:
                        alt_key = (patient_name, service_date, round(amount_paid + amt_offset, 2))
                        matches = order_lookup.get(alt_key, [])
                        if matches:
                            break
                
                if not matches:
                    not_found_count += 1
                    not_found_records.append(row)
                    continue
                
                # Find first unpaid order from matches
                order = None
                for m in matches:
                    if not m['paid']:
                        order = m
                        break
                
                if not order:
                    # All matches already paid
                    already_paid_count += 1
                    continue
                
                order_id = order['id']
                
                # Get payment info
                cycle_date = row.get('cycle_date', today_str)
                tcn = row.get('tcn', '')
                hcpcs = row.get('hcpcs', '')
                
                # Update order as paid
                cur.execute("""
                    UPDATE orders 
                    SET paid = 1, 
                        paid_date = ?,
                        order_status = CASE 
                            WHEN order_status IN ('Pending', 'Billed', 'Shipped', 'Delivered') 
                            THEN 'Paid' 
                            ELSE order_status 
                        END
                    WHERE id = ?
                """, (cycle_date, order_id))
                
                # Mark as paid in our lookup to avoid double-matching
                order['paid'] = 1
                
                matched_count += 1
                updated_orders.append({
                    'order_id': order_id,
                    'patient': patient_name,
                    'amount': amount_paid,
                    'hcpcs': hcpcs,
                    'tcn': tcn
                })
            
            conn.commit()
            conn.close()
            progress.setValue(len(rows))
            
            # Build summary message
            summary = f"✅ Payment Import Complete\n\n"
            summary += f"📊 Results:\n"
            summary += f"   • Orders marked as paid: {matched_count}\n"
            summary += f"   • Already paid (skipped): {already_paid_count}\n"
            summary += f"   • Not found in system: {not_found_count}\n"
            summary += f"   • Total records processed: {len(rows)}\n"
            
            if matched_count > 0:
                total_amount = sum(float(o.get('amount', 0) or 0) for o in updated_orders)
                summary += f"\n💰 Total Amount Reconciled: ${total_amount:,.2f}\n"
            
            if not_found_count > 0:
                summary += f"\n⚠️ Orders not found (matched by Name + Date + Amount):\n"
                for rec in not_found_records[:10]:
                    summary += f"   • {rec.get('patient_name', 'N/A')} - {rec.get('service_date', 'N/A')} - ${rec.get('amount_paid', '0')}\n"
                if not_found_count > 10:
                    summary += f"   ... and {not_found_count - 10} more\n"
            
            QMessageBox.information(self, "Payment Import", summary)
            
            # Refresh the reconciliation report if we updated any orders
            if matched_count > 0:
                self.statusBar().showMessage(f"✅ {matched_count} orders marked as paid", 5000)
                # Refresh the reports view
                if hasattr(self, 'refresh_reports_overview'):
                    self.refresh_reports_overview()
                # Auto-generate reconciliation report to show updated status
                self.generate_reconciliation_report()
                
        except Exception as e:
            import traceback
            QMessageBox.critical(
                self,
                "Import Error",
                f"Error importing payment file:\n{str(e)}\n\n{traceback.format_exc()}"
            )

    def load_prescribers(self):
        """Load prescribers into the prescriber table."""
        try:
            from dmelogic.db.prescribers import fetch_all_prescribers
            
            # Fetch prescribers using the new DB layer
            prescribers = fetch_all_prescribers(folder_path=self.folder_path)
            
            # Clear existing table
            self.prescriber_table.setRowCount(0)
            
            # Add prescriber data to table
            for row_idx, prescriber in enumerate(prescribers):
                self.prescriber_table.insertRow(row_idx)
                
                # Extract fields from Row object
                id_val = prescriber["id"]
                last_name = prescriber["last_name"]
                first_name = prescriber["first_name"]
                
                try:
                    title = prescriber["title"] or ""
                except (KeyError, IndexError):
                    title = ""
                
                try:
                    practice_name = prescriber["practice_name"] or ""
                except (KeyError, IndexError):
                    practice_name = ""
                
                try:
                    specialty = prescriber["specialty"] or ""
                except (KeyError, IndexError):
                    specialty = ""
                
                try:
                    npi = prescriber["npi_number"] or ""
                except (KeyError, IndexError):
                    try:
                        npi = prescriber["npi"] or ""
                    except (KeyError, IndexError):
                        npi = ""
                
                try:
                    phone = prescriber["phone"] or ""
                except (KeyError, IndexError):
                    phone = ""
                
                try:
                    fax = prescriber["fax"] or ""
                except (KeyError, IndexError):
                    fax = ""
                
                try:
                    addr1 = prescriber["address_line1"] or ""
                except (KeyError, IndexError):
                    addr1 = ""
                
                try:
                    addr2 = prescriber["address_line2"] or ""
                except (KeyError, IndexError):
                    addr2 = ""
                
                try:
                    city = prescriber["city"] or ""
                except (KeyError, IndexError):
                    city = ""
                
                try:
                    state = prescriber["state"] or ""
                except (KeyError, IndexError):
                    state = ""
                
                try:
                    zip_code = prescriber["zip_code"] or ""
                except (KeyError, IndexError):
                    zip_code = ""
                
                # Build full address
                address_parts = [p for p in [addr1, addr2, city, state, zip_code] if p]
                full_address = ", ".join(address_parts) if address_parts else ""
                
                # Set table items with explicit light text color for dark theme
                id_item = QTableWidgetItem(str(id_val))
                id_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 0, id_item)
                
                last_item = QTableWidgetItem(last_name.upper() if last_name else "")
                last_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 1, last_item)
                
                first_item = QTableWidgetItem(first_name.upper() if first_name else "")
                first_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 2, first_item)
                
                title_item = QTableWidgetItem(title if title else "")
                title_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 3, title_item)
                
                practice_item = QTableWidgetItem(practice_name if practice_name else "")
                practice_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 4, practice_item)
                
                specialty_item = QTableWidgetItem(specialty if specialty else "")
                specialty_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 5, specialty_item)
                
                npi_item = QTableWidgetItem(npi if npi else "")
                npi_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 6, npi_item)
                
                phone_item = QTableWidgetItem(phone if phone else "")
                phone_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 7, phone_item)
                
                fax_item = QTableWidgetItem(fax if fax else "")
                fax_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 8, fax_item)
                
                address_item = QTableWidgetItem(full_address)
                address_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 9, address_item)
                    
            print(f"✅ Loaded {len(prescribers)} prescribers")
            
        except Exception as e:
            print(f"Error loading prescribers: {e}")
            QMessageBox.critical(self, "Error", f"Failed to load prescribers: {e}")

