    def refresh_fee_schedule(self):
        """Load/reload the fee schedule from Excel and populate the table + column list."""
        try:
            # Prefer previously selected file if available
            sel = None
            try:
                if isinstance(self.settings, dict):
                    sel = self.settings.get('fee_schedule_path')
            except Exception:
                sel = None
            if sel and os.path.exists(sel):
                self.fee_schedule_path = sel
            else:
                self.fee_schedule_path = self._find_fee_schedule_file()
            if not self.fee_schedule_path:
                self.fee_status.setText("No .xlsx file found in assets/.")
                self.fee_table.setRowCount(0)
                self.fee_table.setColumnCount(0)
                return
            try:
                import openpyxl
            except Exception:
                self.fee_status.setText("Missing dependency: openpyxl. Please install it to load .xlsx.")
                self.fee_table.setRowCount(0)
                self.fee_table.setColumnCount(0)
                return

            wb = openpyxl.load_workbook(self.fee_schedule_path, data_only=True, read_only=True)
            ws = wb[wb.sheetnames[0]]

            rows_iter = ws.iter_rows(values_only=True)
            headers = []
            for row in rows_iter:
                if row is None:
                    continue
                headers = [str(c) if c is not None else "" for c in row]
                break
            data_rows = []
            for row in rows_iter:
                if row is None:
                    continue
                data_rows.append(["" if c is None else str(c) for c in row])
            wb.close()

            self.fee_schedule_headers = headers
            self.fee_schedule_rows = data_rows

            effective_cols = max(len(headers), max((len(r) for r in data_rows), default=0))

            self.fee_column_combo.clear()
            self.fee_column_combo.addItem("All Columns", "__all__")
            for i in range(effective_cols):
                label = self.fee_fixed_headers[i] if i < len(self.fee_fixed_headers) else f"Column {i+1}"
                self.fee_column_combo.addItem(label, i)

            display_headers = [self.fee_fixed_headers[i] if i < len(self.fee_fixed_headers) else (headers[i] if i < len(headers) else f"Column {i+1}") for i in range(effective_cols)]
            self._render_fee_table(display_headers, data_rows)
            base = os.path.basename(self.fee_schedule_path)
            self.fee_status.setText(f"Loaded {base} — {len(data_rows)} rows")
            
            try:
                if isinstance(self.settings, dict):
                    self.settings['fee_schedule_path'] = self.fee_schedule_path
                    self.save_settings()
            except Exception:
                pass
        except Exception as e:
            self.fee_status.setText(f"Error loading fee schedule: {e}")

    def _find_fee_schedule_file(self):
        """Find the fee schedule Excel file in common locations."""
        import glob
        try:
            fee_path = None
            if isinstance(getattr(self, 'settings', {}), dict):
                fee_path = self.settings.get('fee_schedule_path')
            if fee_path and os.path.exists(fee_path):
                return fee_path
        except Exception:
            pass

        try:
            base_dir = os.path.dirname(os.path.abspath(__file__))
        except Exception:
            base_dir = os.getcwd()
        candidates = []
        try:
            db_folder = self.settings.get('db_folder') if isinstance(self.settings, dict) else None
        except Exception:
            db_folder = None
        search_dirs = []
        if db_folder:
            search_dirs.append(db_folder)
            search_dirs.append(os.path.join(db_folder, 'reference'))
        assets = os.path.join(base_dir, "assets")
        search_dirs.append(assets)
        search_dirs.append(base_dir)

        patterns = ["MEDICAID_FEE_SCHED_*.xlsx", "DME_Fee_Schedule*.xlsx", "*.xlsx"]
        for d in search_dirs:
            try:
                for pat in patterns:
                    found = glob.glob(os.path.join(d, pat))
                    for p in found:
                        try:
                            candidates.append((p, os.path.getmtime(p)))
                        except Exception:
                            candidates.append((p, 0))
            except Exception:
                pass
        if not candidates:
            return None
        candidates.sort(key=lambda t: t[1], reverse=True)
        return candidates[0][0]

    def _render_fee_table(self, headers, rows):
        """Render the fee schedule table with given headers and rows."""
        col_count = max(len(headers), max((len(r) for r in rows), default=0))
        self.fee_table.setRowCount(0)
        self.fee_table.setColumnCount(col_count)
        display_headers = []
        for i in range(col_count):
            if i < len(self.fee_fixed_headers):
                display_headers.append(self.fee_fixed_headers[i])
            elif i < len(headers):
                display_headers.append(headers[i] or f"Column {i+1}")
            else:
                display_headers.append(f"Column {i+1}")
        self.fee_table.setHorizontalHeaderLabels(display_headers)

        for r_idx, row in enumerate(rows):
            self.fee_table.insertRow(r_idx)
            padded = list(row) + [""] * (col_count - len(row))
            for c_idx, value in enumerate(padded):
                self.fee_table.setItem(r_idx, c_idx, QTableWidgetItem(str(value)))

        header = self.fee_table.horizontalHeader()
        for i in range(col_count):
            header.setSectionResizeMode(i, QHeaderView.ResizeMode.ResizeToContents)
        if col_count > 1:
            header.setSectionResizeMode(1, QHeaderView.ResizeMode.Stretch)

