    def search_fee_schedule(self):
        """Filter fee schedule rows by the query and selected column."""
        q = self.fee_search_input.text().strip().lower()
        if not self.fee_schedule_rows:
            return
        sel = self.fee_column_combo.currentData()
        filtered = []
        if not q:
            filtered = self.fee_schedule_rows
        else:
            if sel == "__all__":
                for row in self.fee_schedule_rows:
                    joined = " ".join([str(v).lower() for v in row])
                    if q in joined:
                        filtered.append(row)
            else:
                col = int(sel)
                for row in self.fee_schedule_rows:
                    if col < len(row) and q in str(row[col]).lower():
                        filtered.append(row)
        effective_cols = max(len(self.fee_schedule_headers), max((len(r) for r in self.fee_schedule_rows), default=0))
        display_headers = [self.fee_fixed_headers[i] if i < len(self.fee_fixed_headers) else (self.fee_schedule_headers[i] if i < len(self.fee_schedule_headers) else f"Column {i+1}") for i in range(effective_cols)]
        self._render_fee_table(display_headers, filtered)
        self.fee_status.setText(f"Matches: {len(filtered)} of {len(self.fee_schedule_rows)}")

    def search_prescribers(self):
        """Search prescribers table based on search input with partial name matching."""
        search_text = self.prescriber_search.text().strip()
        search_digits = ''.join(ch for ch in search_text if ch.isdigit())
        digits_param = search_digits or search_text
        
        if not search_text:
            # If search is empty, reload all prescribers
            self.load_prescribers()
            return
        
        try:
            conn = sqlite3.connect(self.prescriber_database_file)
            cursor = conn.cursor()
            
            # Remove commas and split search text into parts for partial name matching
            search_text_cleaned = search_text.replace(',', ' ')
            search_parts = [p for p in search_text_cleaned.split() if p]
            
            # Build SQL query with partial name matching
            # For each search part, check if it appears in first name OR last name
            name_conditions = []
            params = []
            
            for part in search_parts:
                name_conditions.append("(UPPER(last_name) LIKE '%' || UPPER(?) || '%' OR UPPER(first_name) LIKE '%' || UPPER(?) || '%')")
                params.extend([part, part])
            
            # Combine name conditions with AND (all parts must match)
            name_clause = " AND ".join(name_conditions) if name_conditions else "1=1"
            
            # Also check other fields with the full search text (exact substring match)
            other_fields_clause = """
                OR npi_number LIKE '%' || ? || '%'
                OR UPPER(practice_name) LIKE '%' || UPPER(?) || '%'
                OR UPPER(title) LIKE '%' || UPPER(?) || '%'
                OR UPPER(specialty) LIKE '%' || UPPER(?) || '%'
                OR phone LIKE '%' || ? || '%'
                OR fax LIKE '%' || ? || '%'
                OR REPLACE(REPLACE(REPLACE(phone, '-', ''), '(', ''), ')', '') LIKE '%' || ? || '%'
                OR REPLACE(REPLACE(REPLACE(fax, '-', ''), '(', ''), ')', '') LIKE '%' || ? || '%'
            """
            params.extend([
                search_text, search_text, search_text, search_text,
                search_text, search_text, digits_param, digits_param
            ])
            
            query = f"""
                SELECT id, last_name, first_name, title, practice_name, specialty, npi_number, phone, fax,
                       address_line1, address_line2, city, state, zip_code
                FROM prescribers 
                WHERE ({name_clause})
                   {other_fields_clause}
                ORDER BY last_name, first_name
            """
            
            cursor.execute(query, params)
            
            prescribers = cursor.fetchall()
            conn.close()
            
            # Clear existing table
            self.prescriber_table.setRowCount(0)
            
            # Add search results to table
            for row_idx, prescriber in enumerate(prescribers):
                self.prescriber_table.insertRow(row_idx)
                
                # Map database columns to table columns:
                # [0]=ID, [1]=Last, [2]=First, [3]=Title, [4]=Practice, [5]=Specialty, [6]=NPI, [7]=Phone, [8]=Fax, [9]=Address
                id_val, last_name, first_name, title, practice_name, specialty, npi, phone, fax, addr1, addr2, city, state, zip_code = prescriber
                
                # Build full address
                address_parts = [p for p in [addr1, addr2, city, state, zip_code] if p]
                full_address = ", ".join(address_parts) if address_parts else ""
                
                # Set table items
                self.prescriber_table.setItem(row_idx, 0, QTableWidgetItem(str(id_val)))
                self.prescriber_table.setItem(row_idx, 1, QTableWidgetItem(last_name.upper() if last_name else ""))
                self.prescriber_table.setItem(row_idx, 2, QTableWidgetItem(first_name.upper() if first_name else ""))
                self.prescriber_table.setItem(row_idx, 3, QTableWidgetItem(title if title else ""))
                self.prescriber_table.setItem(row_idx, 4, QTableWidgetItem(practice_name if practice_name else ""))
                self.prescriber_table.setItem(row_idx, 5, QTableWidgetItem(specialty if specialty else ""))
                self.prescriber_table.setItem(row_idx, 6, QTableWidgetItem(npi if npi else ""))
                self.prescriber_table.setItem(row_idx, 7, QTableWidgetItem(phone if phone else ""))
                self.prescriber_table.setItem(row_idx, 8, QTableWidgetItem(fax if fax else ""))
                self.prescriber_table.setItem(row_idx, 9, QTableWidgetItem(full_address))
            
            print(f"✅ Found {len(prescribers)} matching prescribers")
            
        except Exception as e:
            print(f"Error searching prescribers: {e}")
            QMessageBox.critical(self, "Error", f"Failed to search prescribers: {e}")

    def show_low_stock_report(self):
        """Show items with low stock levels."""
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT hcpcs_code, description, stock_quantity, reorder_level
                FROM inventory 
                WHERE stock_quantity <= reorder_level AND reorder_level > 0
                ORDER BY stock_quantity ASC
            """)
            low_stock_items = cursor.fetchall()
            conn.close()
            
            if not low_stock_items:
                QMessageBox.information(self, "Low Stock Report", "No items are currently at or below reorder level.")
                return
            
            # Create dialog to show low stock items
            dialog = QDialog(self)
            dialog.setWindowTitle("⚠️ Low Stock Report")
            dialog.resize(600, 400)
            
            layout = QVBoxLayout(dialog)
            
            header = QLabel(f"Found {len(low_stock_items)} items at or below reorder level:")
            header.setStyleSheet("font-weight: bold; font-size: 14px; color: #e74c3c;")
            layout.addWidget(header)
            
            table = QTableWidget()
            table.setColumnCount(4)
            table.setHorizontalHeaderLabels(["HCPCS Code", "Description", "Current Stock", "Reorder Level"])
            table.setRowCount(len(low_stock_items))
            
            for row, item in enumerate(low_stock_items):
                for col, value in enumerate(item):
                    table.setItem(row, col, QTableWidgetItem(str(value)))
            
            # Color code low stock rows
            for row in range(len(low_stock_items)):
                for col in range(4):
                    item = table.item(row, col)
                    if item:
                        item.setBackground(QColor(255, 235, 235))  # Light red background
            
            layout.addWidget(table)
            
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(dialog.accept)
            layout.addWidget(close_btn)
            
            dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate low stock report: {e}")

