    def _prompt_hold_options(self, current_status_enum):
        """Collect hold-until date, resume status, and note from the user."""
        print("[DEBUG] _prompt_hold_options called")
        from PyQt6.QtWidgets import (
            QComboBox,
            QDateEdit,
            QDialog,
            QDialogButtonBox,
            QFormLayout,
            QLabel,
            QTextEdit,
        )
        from PyQt6.QtCore import QDate
        from dmelogic.db.models import OrderStatus
        from dmelogic.db.order_workflow import get_allowed_next_statuses

        dialog = QDialog(self)
        dialog.setWindowTitle("Schedule Hold Release")
        dialog.setMinimumWidth(350)
        form = QFormLayout(dialog)

        hold_date = QDateEdit(QDate.currentDate().addDays(7))
        hold_date.setCalendarPopup(True)
        form.addRow("Release on:", hold_date)

        resume_combo = QComboBox()
        allowed_after_hold = sorted(
            get_allowed_next_statuses(OrderStatus.ON_HOLD),
            key=lambda s: list(OrderStatus).index(s),
        )
        for status in allowed_after_hold:
            resume_combo.addItem(status.value, status.value)
        if current_status_enum in allowed_after_hold:
            resume_combo.setCurrentText(current_status_enum.value)
        form.addRow("Resume to:", resume_combo)

        note_edit = QTextEdit()
        note_edit.setPlaceholderText("Reason / reminder for this hold")
        note_edit.setMaximumHeight(80)
        form.addRow(QLabel("Hold note:"))
        form.addRow(note_edit)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        form.addRow(buttons)

        print("[DEBUG] About to show hold dialog with exec()")
        result = dialog.exec()
        print(f"[DEBUG] Dialog result: {result}, Accepted={QDialog.DialogCode.Accepted}")
        
        if result == QDialog.DialogCode.Accepted:
            return_val = (
                hold_date.date().toString("yyyy-MM-dd"),
                resume_combo.currentData(),
                note_edit.toPlainText().strip(),
            )
            print(f"[DEBUG] Returning hold options: {return_val}")
            return return_val
        print("[DEBUG] Dialog not accepted, returning None")
        return None

    def _edit_hold_settings(self, order_id, order_number, folder_path):
        """Edit hold settings for an order that's already On Hold."""
        from PyQt6.QtWidgets import (
            QComboBox,
            QDateEdit,
            QDialog,
            QDialogButtonBox,
            QFormLayout,
            QLabel,
            QMessageBox,
            QTextEdit,
        )
        from PyQt6.QtCore import QDate
        from dmelogic.db.models import OrderStatus
        from dmelogic.db.order_workflow import get_allowed_next_statuses
        from dmelogic.db.orders import set_order_hold
        import sqlite3

        # Fetch current hold settings
        db_path = self.orders_db_path
        conn = sqlite3.connect(db_path)
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        cur.execute("""
            SELECT hold_until_date, hold_resume_status, hold_note
            FROM orders WHERE id = ?
        """, (order_id,))
        row = cur.fetchone()
        conn.close()

        current_hold_date = row["hold_until_date"] if row else None
        current_resume = row["hold_resume_status"] if row else None
        current_note = row["hold_note"] if row else None

        dialog = QDialog(self)
        dialog.setWindowTitle(f"Edit Hold Settings - {order_number}")
        dialog.setMinimumWidth(350)
        form = QFormLayout(dialog)

        # Current info label
        if current_hold_date:
            info_label = QLabel(f"<b>Currently scheduled to release:</b> {current_hold_date}")
        else:
            info_label = QLabel("<b>No release date set</b>")
        info_label.setStyleSheet("padding: 5px; background: #fff3cd; border-radius: 4px;")
        form.addRow(info_label)

        # Date picker
        if current_hold_date:
            try:
                qdate = QDate.fromString(current_hold_date, "yyyy-MM-dd")
                if not qdate.isValid():
                    qdate = QDate.currentDate().addDays(7)
            except Exception:
                qdate = QDate.currentDate().addDays(7)
        else:
            qdate = QDate.currentDate().addDays(7)

        hold_date = QDateEdit(qdate)
        hold_date.setCalendarPopup(True)
        form.addRow("Release on:", hold_date)

        # Resume status
        resume_combo = QComboBox()
        allowed_after_hold = sorted(
            get_allowed_next_statuses(OrderStatus.ON_HOLD),
            key=lambda s: list(OrderStatus).index(s),
        )
        for status in allowed_after_hold:
            resume_combo.addItem(status.value, status.value)
        if current_resume and current_resume in [s.value for s in allowed_after_hold]:
            resume_combo.setCurrentText(current_resume)
        form.addRow("Resume to:", resume_combo)

        # Note
        note_edit = QTextEdit()
        note_edit.setPlaceholderText("Reason / reminder for this hold")
        note_edit.setMaximumHeight(80)
        if current_note:
            note_edit.setPlainText(current_note)
        form.addRow(QLabel("Hold note:"))
        form.addRow(note_edit)

        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Save | QDialogButtonBox.StandardButton.Cancel)
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        form.addRow(buttons)

        if dialog.exec() == QDialog.DialogCode.Accepted:
            new_hold_date = hold_date.date().toString("yyyy-MM-dd")
            new_resume = resume_combo.currentData()
            new_note = note_edit.toPlainText().strip()

            try:
                set_order_hold(
                    order_id=order_id,
                    hold_until_date=new_hold_date,
                    resume_status=new_resume,
                    note=new_note,
                    folder_path=folder_path,
                )
                QMessageBox.information(
                    self,
                    "Hold Updated",
                    f"Order {order_number} hold settings updated.\n\n"
                    f"Will release on: {new_hold_date}\n"
                    f"Resume to: {new_resume}",
                )
                try:
                    self.load_orders()
                except Exception:
                    pass
            except Exception as e:
                QMessageBox.warning(
                    self,
                    "Error",
                    f"Could not update hold settings:\n{e}",
                )

    def _update_order_status_impl(self):
        """
        Update the status of the selected order using the validated workflow engine.

        - Reads current status from orders.db via the DB layer.
        - Shows only allowed next statuses (plus current) based on OrderStatus enum.
        - Uses order_workflow.update_order_status_validated for business-rule checks.
        - For 'On Hold', captures release date + resume status and stores them.
        """
        from PyQt6.QtWidgets import QInputDialog, QMessageBox
        from dmelogic.db import fetch_order_with_items
        from dmelogic.db.order_workflow import (
            get_allowed_next_statuses,
            update_order_status_validated,
        )
        from dmelogic.db.models import OrderStatus
        from dmelogic.db.orders import set_order_hold

        # 1) Get selected order
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order first.")
            return

        order_number_item = self.orders_table.item(current_row, 0)
        if not order_number_item:
            QMessageBox.warning(self, "Invalid Row", "Couldn't read the order number.")
            return

        order_number = order_number_item.text()
        try:
            order_id_val = self.get_order_id_from_display(order_number)
        except Exception:
            order_id_val = None

        if not order_id_val:
            QMessageBox.warning(self, "Invalid Order", "Couldn't determine the order ID.")
            return

        order_id = int(order_id_val)

        # 2) Fetch current order (rich domain model)
        folder_path = getattr(self, "folder_path", None)
        order = fetch_order_with_items(order_id, folder_path=folder_path)
        if not order:
            QMessageBox.critical(
                self,
                "Order Not Found",
                f"Order ID {order_id} could not be found in the database.",
            )
            return

        # Get current status from domain model (already an enum)
        current_status_enum = order.order_status

        # 3) Compute allowed next statuses
        allowed_next = get_allowed_next_statuses(current_status_enum)
        # Present current + allowed next as choices
        choices_enums = [current_status_enum] + sorted(
            allowed_next,
            key=lambda s: list(OrderStatus).index(s),
        )
        choices_labels = [s.value for s in choices_enums]

        # If there are no transitions (terminal state), inform and bail
        if len(choices_labels) == 1 and choices_enums[0] == current_status_enum and not allowed_next:
            QMessageBox.information(
                self,
                "Order Status",
                f"Order {order_number} is in terminal state: {current_status_enum.value}\n"
                "No further status changes are allowed.",
            )
            return

        # 4) Ask user for new status
        new_status_str, ok = QInputDialog.getItem(
            self,
            "Update Order Status",
            f"Select new status for {order_number} "
            f"(current: {current_status_enum.value}):",
            choices_labels,
            choices_labels.index(current_status_enum.value),
            False,
        )

        if not ok or not new_status_str:
            return  # user cancelled

        # If they picked the same status...
        if new_status_str == current_status_enum.value:
            # Special case: if already On Hold, allow editing hold settings
            if current_status_enum == OrderStatus.ON_HOLD:
                self._edit_hold_settings(order_id, order_number, folder_path)
            return

        hold_options = None
        if new_status_str == OrderStatus.ON_HOLD.value:
            print(f"[DEBUG] About to show hold options dialog for changing to On Hold")
            hold_options = self._prompt_hold_options(current_status_enum)
            print(f"[DEBUG] Hold options returned: {hold_options}")
            if not hold_options:
                print(f"[DEBUG] User cancelled or dialog returned None - aborting")
                return

        # 5) Validate & update via workflow engine
        success, error_msg = update_order_status_validated(
            order_id=order_id,
            current_status=current_status_enum.value,
            new_status=new_status_str,
            folder_path=folder_path,
        )

        if not success:
            QMessageBox.warning(
                self,
                "Invalid Status Change",
                error_msg or "Status update failed due to validation rules.",
            )
            return

        if new_status_str == OrderStatus.ON_HOLD.value and hold_options:
            hold_until_date, resume_status, hold_note = hold_options
            resume_status = resume_status or current_status_enum.value
            try:
                set_order_hold(
                    order_id=order_id,
                    hold_until_date=hold_until_date,
                    resume_status=resume_status,
                    note=hold_note,
                    folder_path=folder_path,
                )
            except Exception as e:
                QMessageBox.warning(
                    self,
                    "Hold Saved with Warning",
                    f"Status updated, but hold metadata could not be saved:\n{e}",
                )

        # 6) Refresh UI and reselect row
        try:
            self.load_orders()
            if current_row < self.orders_table.rowCount():
                self.orders_table.selectRow(current_row)
        except Exception:
            pass

        QMessageBox.information(
            self,
            "Status Updated",
            f"Order {order_number} status updated to: {new_status_str}",
        )

    def show_delivery_report(self):
        """Show a report of orders filtered by delivery status."""
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Get delivered orders
            cursor.execute("""
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name,
                       order_status, delivery_date, tracking_number
                FROM orders
                WHERE delivery_date IS NOT NULL
                ORDER BY delivery_date DESC
            """)
            delivered = cursor.fetchall()
            
            # Get pending deliveries
            cursor.execute("""
                SELECT id, rx_date, order_date, patient_last_name, patient_first_name,
                       order_status, tracking_number
                FROM orders
                WHERE delivery_date IS NULL AND order_status NOT IN ('Cancelled', 'Completed')
                ORDER BY order_date ASC
            """)
            pending = cursor.fetchall()
            conn.close()

            # Create report dialog
            dialog = QDialog(self)
            dialog.setWindowTitle("📊 Delivery Report")
            dialog.resize(900, 600)
            layout = QVBoxLayout(dialog)

            # Summary stats
            stats_label = QLabel(f"<b>Total Delivered:</b> {len(delivered)} | <b>Pending Delivery:</b> {len(pending)}")
            stats_label.setStyleSheet("font-size: 14px; padding: 10px; background: #f0f0f0; border-radius: 5px;")
            layout.addWidget(stats_label)

            # Tab widget for delivered vs pending
            tabs = QTabWidget()
            
            # Delivered tab
            delivered_table = QTableWidget()
            delivered_table.setColumnCount(7)
            delivered_table.setHorizontalHeaderLabels(["Order #", "Patient", "Order Date", "Delivery Date", "Status", "Tracking", "RX Date"])
            delivered_table.setRowCount(len(delivered))
            
            for i, order in enumerate(delivered):
                order_id, rx_date, order_date, last_name, first_name, status, delivery_date, tracking = order
                delivered_table.setItem(i, 0, QTableWidgetItem(self.format_order_number(order_id)))
                delivered_table.setItem(i, 1, QTableWidgetItem(f"{last_name}, {first_name}"))
                delivered_table.setItem(i, 2, QTableWidgetItem(order_date or ""))
                delivered_table.setItem(i, 3, QTableWidgetItem(delivery_date or ""))
                delivered_table.setItem(i, 4, QTableWidgetItem(status or ""))
                delivered_table.setItem(i, 5, QTableWidgetItem(tracking or ""))
                delivered_table.setItem(i, 6, QTableWidgetItem(rx_date or ""))
            
            delivered_table.resizeColumnsToContents()
            tabs.addTab(delivered_table, f"Delivered ({len(delivered)})")
            
            # Pending tab
            pending_table = QTableWidget()
            pending_table.setColumnCount(6)
            pending_table.setHorizontalHeaderLabels(["Order #", "Patient", "Order Date", "Status", "Tracking", "RX Date"])
            pending_table.setRowCount(len(pending))
            
            for i, order in enumerate(pending):
                order_id, rx_date, order_date, last_name, first_name, status, tracking = order
                pending_table.setItem(i, 0, QTableWidgetItem(self.format_order_number(order_id)))
                pending_table.setItem(i, 1, QTableWidgetItem(f"{last_name}, {first_name}"))
                pending_table.setItem(i, 2, QTableWidgetItem(order_date or ""))
                pending_table.setItem(i, 3, QTableWidgetItem(status or ""))
                pending_table.setItem(i, 4, QTableWidgetItem(tracking or ""))
                pending_table.setItem(i, 5, QTableWidgetItem(rx_date or ""))
            
            pending_table.resizeColumnsToContents()
            tabs.addTab(pending_table, f"Pending Delivery ({len(pending)})")
            
            layout.addWidget(tabs)
            
            # Close button
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(dialog.accept)
            layout.addWidget(close_btn)
            
            dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate delivery report: {e}")
            print(f"Delivery report error: {e}")

