    def load_tasks_table(self):
        """Load tasks from database applying simple filters."""
        try:
            assignee = self.tasks_assignee_filter.currentText() if hasattr(self, 'tasks_assignee_filter') else 'All Assignees'
            status = self.tasks_status_filter.currentText() if hasattr(self, 'tasks_status_filter') else 'All Statuses'
            priority = self.tasks_priority_filter.currentText() if hasattr(self, 'tasks_priority_filter') else 'All Priorities'
            clauses = []
            params = []
            if assignee and assignee != 'All Assignees':
                if assignee == 'Me':
                    clauses.append("assigned_to_user = ?"); params.append('Me')
                else:
                    clauses.append("assigned_to_user = ?"); params.append(assignee)
            if status and status != 'All Statuses':
                clauses.append("status = ?"); params.append(status)
            if priority and priority != 'All Priorities':
                clauses.append("priority = ?"); params.append(priority)
            where = ("WHERE " + " AND ".join(clauses)) if clauses else ""
            q = f"""
                SELECT id, title, status, priority, due_date, assigned_to_user, notes, completed_date, patient_name
                FROM tasks
                {where}
                ORDER BY COALESCE(due_date,'9999-12-31') ASC, priority DESC, created_date DESC
                LIMIT 500
            """
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute(q, params)
            rows = cur.fetchall()
            conn.close()
            self.tasks_table.setRowCount(0)
            for r in rows:
                tid, title, status_v, priority_v, due, assigned, notes, completed, patient = r
                row = self.tasks_table.rowCount(); self.tasks_table.insertRow(row)
                completed_flag = '✔' if status_v == 'Completed' or completed else ''
                color = '#95a5a6' if completed_flag else ('#e74c3c' if due and due < datetime.now().strftime('%Y-%m-%d') and status_v != 'Completed' else ('#f39c12' if due == datetime.now().strftime('%Y-%m-%d') else 'white'))
                values = [str(tid), completed_flag, priority_v, due or '', title, patient or '', assigned or '', status_v]
                for col, val in enumerate(values):
                    item = QTableWidgetItem(val)
                    if col in (3,4):
                        item.setForeground(QColor(color))
                    self.tasks_table.setItem(row, col, item)
            self.tasks_status_label.setText(f"Loaded {len(rows)} tasks")
        except Exception as e:
            self.tasks_status_label.setText(f"Error loading tasks: {e}")

    def open_task_dialog(self, existing: dict | None = None):
        dlg = TaskDialog(self, existing)
        if dlg.exec() == QDialog.DialogCode.Accepted:
            data = dlg.get_data()
            self.save_task(data)
            self.load_tasks_table()

    def edit_selected_task(self, *_):
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        tid_item = self.tasks_table.item(row, 0)
        if not tid_item:
            return
        tid = tid_item.text()
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("SELECT id, title, status, priority, due_date, assigned_to_user, notes FROM tasks WHERE id = ?", (tid,))
            r = cur.fetchone(); conn.close()
            if not r:
                return
            existing = {
                'id': r[0], 'title': r[1], 'status': r[2], 'priority': r[3], 'due_date': r[4], 'assigned_to_user': r[5], 'notes': r[6]
            }
            self.open_task_dialog(existing)
        except Exception as e:
            QMessageBox.critical(self, "Tasks", f"Failed to load task: {e}")

    def save_task(self, data: dict):
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            if data.get('id'):
                cur.execute("""
                    UPDATE tasks SET title=?, status=?, priority=?, due_date=?, assigned_to_user=?, notes=?,
                        completed_date = CASE WHEN ?='Completed' THEN COALESCE(completed_date, CURRENT_TIMESTAMP)
                                             WHEN ?!='Completed' THEN NULL ELSE completed_date END
                    WHERE id=?
                """, (data['title'], data['status'], data['priority'], data['due_date'], data['assigned_to_user'], data['notes'], data['status'], data['status'], data['id']))
            else:
                cur.execute("""
                    INSERT INTO tasks (title,status,priority,due_date,assigned_to_user,notes)
                    VALUES (?,?,?,?,?,?)
                """, (data['title'], data['status'], data['priority'], data['due_date'], data['assigned_to_user'], data['notes']))
            conn.commit(); conn.close()
        except Exception as e:
            QMessageBox.critical(self, "Tasks", f"Failed to save task: {e}")

    def show_tasks_context_menu(self, position):
        """Show context menu for tasks table."""
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        
        menu = QMenu()
        edit_action = menu.addAction("✏️ Edit Task")
        complete_action = menu.addAction("✅ Mark as Completed")
        menu.addSeparator()
        delete_action = menu.addAction("🗑️ Delete Task")
        
        action = menu.exec(self.tasks_table.viewport().mapToGlobal(position))
        
        if action == edit_action:
            self.edit_selected_task()
        elif action == complete_action:
            self.mark_task_completed()
        elif action == delete_action:
            self.delete_selected_task()

    def mark_task_completed(self):
        """Mark the selected task as completed."""
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        tid_item = self.tasks_table.item(row, 0)
        if not tid_item:
            return
        tid = tid_item.text()
        try:
            conn = sqlite3.connect(self.orders_database_file)
            cur = conn.cursor()
            cur.execute("""
                UPDATE tasks 
                SET status = 'Completed', 
                    completed_date = CURRENT_TIMESTAMP 
                WHERE id = ?
            """, (tid,))
            conn.commit()
            conn.close()
            self.load_tasks_table()
            self.tasks_status_label.setText(f"Task #{tid} marked as completed")
        except Exception as e:
            QMessageBox.critical(self, "Tasks", f"Failed to complete task: {e}")

    def delete_selected_task(self):
        """Delete the selected task with confirmation."""
        row = self.tasks_table.currentRow()
        if row < 0:
            return
        tid_item = self.tasks_table.item(row, 0)
        if not tid_item:
            return
        tid = tid_item.text()
        title_item = self.tasks_table.item(row, 4)
        title = title_item.text() if title_item else "this task"
        
        reply = QMessageBox.question(
            self, 
            "Delete Task", 
            f"Are you sure you want to delete task #{tid}?\n\n{title}",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No
        )
        
        if reply == QMessageBox.StandardButton.Yes:
            try:
                conn = sqlite3.connect(self.orders_database_file)
                cur = conn.cursor()
                cur.execute("DELETE FROM tasks WHERE id = ?", (tid,))
                conn.commit()
                conn.close()
                self.load_tasks_table()
                self.tasks_status_label.setText(f"Task #{tid} deleted")
            except Exception as e:
                QMessageBox.critical(self, "Tasks", f"Failed to delete task: {e}")

    def process_refill_from_history(self):
        """Create a refill for the selected order in the Patient Order History table."""
        try:
            from dmelogic.refill_service import process_refill, RefillError

            # Use the currently selected row
            row = self.get_selected_history_row()
            if row < 0:
                QMessageBox.warning(self, "No Selection", "Please select an order in the Order History table.")
                return
            
            # Find the first row of this order (the one with order_id stored)
            # Search backwards from current row to find the row with order_id data
            order_id_item = None
            src_order_id = None
            for search_row in range(row, -1, -1):
                item = self.patient_order_history_table.item(search_row, 0)
                if item:
                    data = item.data(Qt.ItemDataRole.UserRole)
                    if data:
                        order_id_item = item
                        src_order_id = data
                        break
            
            if not order_id_item or not src_order_id:
                QMessageBox.warning(self, "Selection Error", "Couldn't find the order for the selected row.")
                return

            # Check if refills are available before confirming
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Count items with refills > 0
            cursor.execute(
                """
                SELECT hcpcs_code, COALESCE(refills,'0')
                FROM order_items 
                WHERE order_id = ?
                ORDER BY id
                """,
                (src_order_id,),
            )
            items = cursor.fetchall()
            items_with_refills = []
            for hcpcs, ref_val in items:
                try:
                    n = int(float(str(ref_val).strip())) if str(ref_val).strip() != '' else 0
                except Exception:
                    n = 0
                if n > 0:
                    items_with_refills.append((hcpcs or "Unknown", n))
            
            conn.close()
            
            if not items_with_refills:
                QMessageBox.warning(
                    self,
                    "No Refills Available",
                    "None of the items in this order have refills remaining.\n\nCannot create a refill order."
                )
                return
            
            # Build message showing which items will be included
            item_list = "\n".join([f"  • {hcpcs}: {n} refill(s)" for hcpcs, n in items_with_refills])
            total_items = len(items)
            included_items = len(items_with_refills)
            
            message = f"Create a refill order from the selected history entry?\n\n"
            if included_items < total_items:
                message += f"⚠️ Only {included_items} of {total_items} items will be included (items with refills remaining):\n\n"
            else:
                message += f"Items to refill ({included_items}):\n\n"
            message += item_list

            confirm = QMessageBox.question(
                self,
                "Process Refill",
                message,
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.Yes,
            )
            if confirm != QMessageBox.StandardButton.Yes:
                return

            folder_path = getattr(self, "folder_path", None)
            try:
                new_order = process_refill(int(src_order_id), folder_path=folder_path)
            except RefillError as e:
                QMessageBox.critical(self, "Refill Error", f"Cannot process refill:\n\n{e}")
                return
            except Exception as e:
                QMessageBox.critical(self, "Refill Error", f"Failed to process refill:\n\n{e}")
                return

            new_order_id = new_order.id
            display_no = self.format_order_number(new_order_id) if hasattr(self, "format_order_number") else str(new_order_id)

            # Refresh both orders and patient view
            self.load_orders()
            self.on_patient_selected()

            # Offer to open the new refill for edits
            reply = QMessageBox.question(
                self,
                "Refill Created",
                f"Refill order {display_no} created successfully. Open it now for review?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.Yes,
            )
            if reply == QMessageBox.StandardButton.Yes:
                self.edit_order_by_id(new_order_id)

        except Exception as e:
            QMessageBox.critical(self, "Refill Error", f"Failed to process refill: {e}")
            print(f"Process refill (history) error: {e}")

    def delete_order_from_history(self):
        """Delete the selected order from the Patient Order History table with refill reversal safeguards."""
        try:
            # Use the currently selected row
            row = self.get_selected_history_row()
            if row < 0:
                QMessageBox.warning(self, "No Selection", "Please select an order in the Order History table to delete.")
                return

            # Find the first row of this order (the one with order_id stored)
            order_cell = None
            order_id_val = None
            order_display = ""

            for search_row in range(row, -1, -1):
                item = self.patient_order_history_table.item(search_row, 0)
                if item:
                    data = item.data(Qt.ItemDataRole.UserRole)
                    if data:
                        order_cell = item
                        order_id_val = data
                        order_display = item.text() or ""
                        break

            if not order_cell or not order_id_val:
                QMessageBox.warning(self, "Selection Error", "Couldn't find the order for the selected row.")
                return

            # Confirm deletion
            reply = QMessageBox.question(
                self,
                "Confirm Deletion",
                f"Are you sure you want to delete this order?\n\n"
                f"Order #: {order_display}\n\n"
                f"This action cannot be undone.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            )

            if reply != QMessageBox.StandardButton.Yes:
                return

            # Perform deletion with refill reversal like in delete_order()
            try:
                if not hasattr(self, 'orders_db_path'):
                    self.orders_db_path = self.orders_database_file

                conn = sqlite3.connect(self.orders_db_path)
                cursor = conn.cursor()

                # Log deleted order before removal
                try:
                    self.log_deleted_order(int(order_id_val))
                except Exception as e:
                    print(f"Deleted order logging failed: {e}")

                # Reverse refills on previous order in the chain if this is a refill
                cursor.execute(
                    "SELECT COALESCE(parent_order_id,0), COALESCE(refill_number,0) FROM orders WHERE id = ?",
                    (order_id_val,),
                )
                rowinfo = cursor.fetchone()

                if rowinfo:
                    parent_id, rno = int(rowinfo[0] or 0), int(rowinfo[1] or 0)

                    if rno > 0 and parent_id:
                        # Determine previous order id in the chain
                        if rno == 1:
                            prev_id = parent_id
                        else:
                            cursor.execute(
                                "SELECT id FROM orders WHERE parent_order_id = ? AND refill_number = ?",
                                (parent_id, rno - 1),
                            )
                            prev_row = cursor.fetchone()
                            prev_id = int(prev_row[0]) if prev_row else parent_id

                        # Increment refills on previous order items by 1
                        cursor.execute("SELECT id, COALESCE(refills,'') FROM order_items WHERE order_id = ?", (prev_id,))
                        prev_items = cursor.fetchall()

                        for (it_id, ref_val) in prev_items:
                            try:
                                n = int(float(str(ref_val).strip())) if str(ref_val).strip() != '' else 0
                            except Exception:
                                n = 0
                            cursor.execute("UPDATE order_items SET refills = ? WHERE id = ?", (str(n + 1), it_id))

                        # Unlock parent and clear refill_completed so it can be refilled again
                        cursor.execute("UPDATE orders SET refill_completed = 0, refill_completed_at = NULL, is_locked = 0 WHERE id = ?", (prev_id,))

                # Delete the order and its items
                cursor.execute("DELETE FROM order_items WHERE order_id = ?", (order_id_val,))
                cursor.execute("DELETE FROM orders WHERE id = ?", (order_id_val,))
                conn.commit()
                conn.close()

                # Refresh both views
                self.load_orders()
                self.on_patient_selected()

                QMessageBox.information(self, "Success", f"Order {order_display} has been deleted.")

            except Exception as e:
                try:
                    conn.close()
                except Exception:
                    pass
                QMessageBox.critical(self, "Error", f"Failed to delete order: {e}")
                print(f"Order deletion error: {e}")

        except Exception as e:
            QMessageBox.critical(self, "Error", f"Unexpected error: {e}")
            print(f"delete_order_from_history error: {e}")

    def get_selected_history_row(self) -> int:
        """Return the currently selected row index from Order History, or -1 if none."""
        try:
            cur = self.patient_order_history_table.currentRow()
            return int(cur) if cur is not None and int(cur) >= 0 else -1
        except Exception:
            return -1

    def _show_refill_history_popup(self, base_id, chain):
        """Show a full-width popup dialog with the complete refill chain history."""
        try:
            from datetime import datetime, timedelta
            chain_sorted = sorted(chain, key=lambda x: x[0], reverse=True)
            
            dlg = QDialog(self)
            dlg.setWindowTitle(f"Refill History — ORD-{str(base_id).zfill(3)}  ({len(chain_sorted)} fills)")
            dlg.setMinimumWidth(900)
            dlg.setMinimumHeight(300)
            # Start at 90% of parent window size for near-fullscreen feel
            try:
                pw = self.width()
                ph = self.height()
                dlg.resize(int(pw * 0.92), int(ph * 0.55))
            except Exception:
                dlg.resize(1200, 500)
            dlg.setSizeGripEnabled(True)
            
            layout = QVBoxLayout(dlg)
            layout.setContentsMargins(12, 12, 12, 12)
            layout.setSpacing(8)
            
            header = QLabel(f"Refill Chain — {len(chain_sorted)} orders  •  Double-click any row to open Order Editor")
            header.setStyleSheet("font-size: 13px; font-weight: bold; color: #0d6efd;")
            layout.addWidget(header)
            
            # Full column set matching the main orders table
            col_headers = [
                "Order #", "Patient", "DOB", "HCPCS", "Description",
                "Qty", "Refills", "Days", "Order Date",
                "Refill Due", "Del/PU Date", "Status", "Tracking #",
                "Notes", "Paid", "Paid Date"
            ]
            tbl = QTableWidget()
            tbl.setColumnCount(len(col_headers))
            tbl.setHorizontalHeaderLabels(col_headers)
            tbl.setEditTriggers(QTableWidget.EditTrigger.NoEditTriggers)
            tbl.setSelectionBehavior(QTableWidget.SelectionBehavior.SelectRows)
            tbl.setAlternatingRowColors(True)
            tbl.verticalHeader().setVisible(False)
            tbl.horizontalHeader().setStretchLastSection(True)
            
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            
            # Map row → order_id for double-click editing
            row_order_map = {}
            
            for refill_no, oid in chain_sorted:
                cur.execute(
                    """SELECT o.order_date, o.order_status, o.refill_number,
                              o.patient_last_name, o.patient_first_name, o.patient_dob,
                              o.delivery_date, o.pickup_date, o.tracking_number,
                              o.notes, o.paid, o.paid_date, o.is_pickup,
                              i.hcpcs_code, i.description, i.qty, i.refills, i.day_supply
                       FROM orders o
                       LEFT JOIN order_items i ON i.order_id = o.id
                       WHERE o.id = ?
                       ORDER BY i.id ASC""",
                    (oid,),
                )
                rows = cur.fetchall()
                if not rows:
                    continue
                
                for i, row_data in enumerate(rows):
                    (odate, ostatus, rno, lname, fname, dob,
                     del_date, pu_date, tracking, notes_val,
                     paid_val, paid_date_val, is_pu,
                     hcpcs, desc, qty, refills_val, days) = row_data
                    
                    r = tbl.rowCount()
                    tbl.insertRow(r)
                    row_order_map[r] = oid
                    
                    # Col 0: Order #
                    if i == 0:
                        try:
                            order_num = self.format_order_number(oid)
                        except Exception:
                            order_num = f"ORD-{str(base_id).zfill(3)}" + (f"-R{rno}" if rno else "")
                        tbl.setItem(r, 0, QTableWidgetItem(order_num))
                    else:
                        tbl.setItem(r, 0, QTableWidgetItem("  ↳"))
                    
                    # Col 1: Patient (first row only)
                    pname = f"{lname}, {fname}" if lname and fname else ""
                    tbl.setItem(r, 1, QTableWidgetItem(pname if i == 0 else ""))
                    
                    # Col 2: DOB
                    dob_disp = ""
                    if i == 0 and dob:
                        try:
                            dob_disp = self.format_date_display(dob)
                        except Exception:
                            dob_disp = dob or ""
                    tbl.setItem(r, 2, QTableWidgetItem(dob_disp))
                    
                    # Col 3: HCPCS
                    hcpcs_clean = (hcpcs or "").split("-")[0].strip() if hcpcs else ""
                    tbl.setItem(r, 3, QTableWidgetItem(hcpcs_clean))
                    
                    # Col 4: Description
                    tbl.setItem(r, 4, QTableWidgetItem(desc or ""))
                    
                    # Col 5: Qty
                    tbl.setItem(r, 5, QTableWidgetItem(str(qty) if qty else ""))
                    
                    # Col 6: Refills
                    tbl.setItem(r, 6, QTableWidgetItem(str(refills_val) if refills_val else "0"))
                    
                    # Col 7: Days
                    tbl.setItem(r, 7, QTableWidgetItem(str(days) if days else ""))
                    
                    # Col 8: Order Date (first row only)
                    od_disp = ""
                    if i == 0 and odate:
                        try:
                            od_disp = self.format_date_display(odate)
                        except Exception:
                            od_disp = odate or ""
                    tbl.setItem(r, 8, QTableWidgetItem(od_disp))
                    
                    # Col 9: Refill Due Date
                    due_text = ""
                    if i == 0 and days and odate:
                        try:
                            base_dt = None
                            for fmt in ("%Y-%m-%d", "%m/%d/%Y", "%Y/%m/%d"):
                                try:
                                    base_dt = datetime.strptime(str(odate).split(" ")[0], fmt)
                                    break
                                except Exception:
                                    continue
                            if base_dt:
                                due_dt = base_dt + timedelta(days=int(float(days)))
                                due_text = due_dt.strftime("%m/%d/%Y")
                        except Exception:
                            pass
                    tbl.setItem(r, 9, QTableWidgetItem(due_text))
                    
                    # Col 10: Del/PU Date (first row only)
                    dp_disp = ""
                    if i == 0:
                        dp_raw = pu_date or del_date or ""
                        if dp_raw:
                            try:
                                dp_disp = self.format_date_display(dp_raw)
                            except Exception:
                                dp_disp = dp_raw
                    tbl.setItem(r, 10, QTableWidgetItem(dp_disp))
                    
                    # Col 11: Status (first row only)
                    if i == 0:
                        st_item = QTableWidgetItem((ostatus or "Pending").upper())
                        st_item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                        tbl.setItem(r, 11, st_item)
                    else:
                        tbl.setItem(r, 11, QTableWidgetItem(""))
                    
                    # Col 12: Tracking # (first row only)
                    tbl.setItem(r, 12, QTableWidgetItem((tracking or "") if i == 0 else ""))
                    
                    # Col 13: Notes (first row only)
                    tbl.setItem(r, 13, QTableWidgetItem((notes_val or "") if i == 0 else ""))
                    
                    # Col 14: Paid (first row only)
                    if i == 0:
                        tbl.setItem(r, 14, QTableWidgetItem("Yes" if paid_val else "No"))
                    else:
                        tbl.setItem(r, 14, QTableWidgetItem(""))
                    
                    # Col 15: Paid Date (first row only)
                    pd_disp = ""
                    if i == 0 and paid_date_val:
                        try:
                            pd_disp = self.format_date_display(paid_date_val)
                        except Exception:
                            pd_disp = paid_date_val or ""
                    tbl.setItem(r, 15, QTableWidgetItem(pd_disp))
                    
                    # Highlight the latest refill row (bold + light blue bg)
                    if refill_no == chain_sorted[0][0]:
                        for c in range(len(col_headers)):
                            it = tbl.item(r, c)
                            if it:
                                it.setBackground(QColor(13, 110, 253, 30))
                                font = it.font()
                                font.setBold(True)
                                it.setFont(font)
            
            conn.close()
            
            tbl.resizeColumnsToContents()
            layout.addWidget(tbl)
            
            # Double-click to open Order Editor
            main_self = self
            def on_dbl_click(index):
                r = index.row()
                oid = row_order_map.get(r)
                if oid:
                    dlg.accept()
                    main_self.open_order_editor(oid)
            tbl.doubleClicked.connect(on_dbl_click)
            
            note = QLabel("Highlighted = current (latest) fill  •  Double-click any row to open its Order Editor")
            note.setStyleSheet("color: #6c757d; font-size: 11px; font-style: italic;")
            layout.addWidget(note)
            
            # Buttons
            btn_layout = QHBoxLayout()
            btn_layout.addStretch()
            
            edit_btn = QPushButton("Edit Selected Order")
            edit_btn.setFixedWidth(160)
            def edit_selected():
                sel = tbl.currentRow()
                oid = row_order_map.get(sel)
                if oid:
                    dlg.accept()
                    main_self.open_order_editor(oid)
                else:
                    QMessageBox.information(dlg, "No Selection", "Select a row first.")
            edit_btn.clicked.connect(edit_selected)
            btn_layout.addWidget(edit_btn)
            
            close_btn = QPushButton("Close")
            close_btn.setFixedWidth(100)
            close_btn.clicked.connect(dlg.accept)
            btn_layout.addWidget(close_btn)
            layout.addLayout(btn_layout)
            
            dlg.exec()
        except Exception as e:
            print(f"Refill history popup error: {e}")

    def handle_cell_click(self, row, col):
        """Handle inline interactions for specific columns.

        - 0:  Order # — show refill history popup
        - 14: Paid — single-click toggles between Yes/No (fast UX)
        - 10: Del/PU Date — open date picker
        - 15: Paid Date — open date picker
        """
        # Show refill history popup when clicking Order # column on a chain order
        if col == 0:
            try:
                item = self.orders_table.item(row, 0)
                if item:
                    data = item.data(Qt.ItemDataRole.UserRole)
                    if data:
                        order_id, idx = data
                        base_id = getattr(self, '_order_to_base', {}).get(order_id)
                        if base_id is not None:
                            chain = getattr(self, '_base_to_orders', {}).get(base_id, [])
                            if len(chain) > 1 and idx == 0:
                                self._show_refill_history_popup(base_id, chain)
                                return
            except Exception as e:
                print(f"Refill chain popup error: {e}")
        
        # Fast toggle for Paid column
        if col == 14:
            try:
                paid_item = self.orders_table.item(row, 14)
                current_text = (paid_item.text() if paid_item else "").strip().lower()
                new_text = "No" if current_text == "yes" else "Yes"
                # Setting text will trigger on_orders_item_changed to persist
                if paid_item is None:
                    paid_item = QTableWidgetItem(new_text)
                    paid_item.setTextAlignment(Qt.AlignmentFlag.AlignCenter)
                    self.orders_table.setItem(row, 14, paid_item)
                else:
                    paid_item.setText(new_text)
                # Visual nudge (optional refresh)
                self.orders_table.viewport().update()
            except Exception as e:
                print(f"Paid toggle click error: {e}")
            return

        # Gate for supported date columns
        if col not in [10, 15]:
            return
        
        # Get order ID
        order_number = self.orders_table.item(row, 0).text()
        order_id = int(self.get_order_id_from_display(order_number) or 0)
        if order_id == 0:
            return
        
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            if col == 10:  # Del/PU Date column: open date picker
                current_date = self.orders_table.item(row, 10).text() if self.orders_table.item(row, 10) else ""
                dialog = QDialog(self)
                dialog.setWindowTitle("Set Delivery/Pickup Date")
                v = QVBoxLayout(dialog)
                date_edit = QDateEdit()
                date_edit.setCalendarPopup(True)
                date_edit.setDisplayFormat("MM/dd/yyyy")
                if current_date:
                    d = QDate.fromString(current_date, "MM/dd/yyyy")
                    if not d.isValid():
                        d = QDate.fromString(current_date, "yyyy-MM-dd")
                    if d.isValid():
                        date_edit.setDate(d)
                    else:
                        date_edit.setDate(QDate.currentDate())
                else:
                    date_edit.setDate(QDate.currentDate())
                v.addWidget(QLabel("Select Delivery/Pickup Date:"))
                v.addWidget(date_edit)
                h = QHBoxLayout()
                save_btn = QPushButton("Save")
                clear_btn = QPushButton("Clear")
                cancel_btn = QPushButton("Cancel")
                h.addWidget(save_btn)
                h.addWidget(clear_btn)
                h.addWidget(cancel_btn)
                v.addLayout(h)

                def save_delivery():
                    nd_iso = date_edit.date().toString("yyyy-MM-dd")
                    nd_display = date_edit.date().toString("MM/dd/yyyy")
                    cursor.execute("UPDATE orders SET delivery_date = ? WHERE id = ?", (nd_iso, order_id))
                    conn.commit()
                    self.orders_table.setItem(row, 10, QTableWidgetItem(nd_display))
                    dialog.accept()
                def clear_delivery():
                    cursor.execute("UPDATE orders SET delivery_date = NULL WHERE id = ?", (order_id,))
                    conn.commit()
                    self.orders_table.setItem(row, 10, QTableWidgetItem(""))
                    dialog.accept()
                save_btn.clicked.connect(save_delivery)
                clear_btn.clicked.connect(clear_delivery)
                cancel_btn.clicked.connect(dialog.reject)
                dialog.exec()

            elif col == 15:  # Paid Date column
                # Open date picker
                current_date = self.orders_table.item(row, 15).text()
                date_dialog = QDialog(self)
                date_dialog.setWindowTitle("Set Paid Date")
                layout = QVBoxLayout(date_dialog)
                
                date_edit = QDateEdit()
                date_edit.setCalendarPopup(True)
                date_edit.setDisplayFormat("MM/dd/yyyy")
                if current_date:
                    d = QDate.fromString(current_date, "MM/dd/yyyy")
                    if not d.isValid():
                        d = QDate.fromString(current_date, "yyyy-MM-dd")
                    date_edit.setDate(d if d.isValid() else QDate.currentDate())
                else:
                    date_edit.setDate(QDate.currentDate())
                
                layout.addWidget(QLabel("Select Paid Date:"))
                layout.addWidget(date_edit)
                
                btn_layout = QHBoxLayout()
                save_btn = QPushButton("Save")
                clear_btn = QPushButton("Clear")
                cancel_btn = QPushButton("Cancel")
                btn_layout.addWidget(save_btn)
                btn_layout.addWidget(clear_btn)
                btn_layout.addWidget(cancel_btn)
                layout.addLayout(btn_layout)
                
                def save_date():
                    new_date_iso = date_edit.date().toString("yyyy-MM-dd")
                    new_date_display = date_edit.date().toString("MM/dd/yyyy")
                    cursor.execute("UPDATE orders SET paid_date = ? WHERE id = ?", (new_date_iso, order_id))
                    conn.commit()
                    
                    paid_date_item = QTableWidgetItem(new_date_display)
                    paid_date_item.setBackground(QColor("#d6eaf8"))
                    self.orders_table.setItem(row, 15, paid_date_item)
                    date_dialog.accept()
                
                def clear_date():
                    cursor.execute("UPDATE orders SET paid_date = NULL WHERE id = ?", (order_id,))
                    conn.commit()
                    
                    self.orders_table.setItem(row, 15, QTableWidgetItem(""))
                    date_dialog.accept()
                
                save_btn.clicked.connect(save_date)
                clear_btn.clicked.connect(clear_date)
                cancel_btn.clicked.connect(date_dialog.reject)
                
                date_dialog.exec()
            
            conn.close()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to update: {e}")


    def display_pdf(self, file_path):
        """Load and display a PDF document."""
        import fitz  # PyMuPDF
        try:
            # Close previous
            if hasattr(self, "doc") and self.doc:
                try:
                    self.doc.close()
                except Exception:
                    pass
                self.doc = None

            # Clean filename - remove star prefix if present
            clean_filename = file_path
            if clean_filename.startswith("★ "):
                clean_filename = clean_filename[2:]
            
            # Allow absolute paths (e.g., freshly generated reports)
            if os.path.isabs(clean_filename):
                filepath = clean_filename
                display_name = os.path.basename(clean_filename)
            else:
                filepath = os.path.join(self.folder_path, clean_filename)
                display_name = clean_filename

            # Open new
            self.current_pdf_path = filepath
            self.doc = fitz.open(filepath)
            self.current_file = display_name
            self.pdf_document = self.doc  # Alias for consistency

            # Set total page count
            self.total_pages = self.doc.page_count if hasattr(self.doc, "page_count") else len(self.doc)
            self.current_page_num = 0

            # Render first page – fit to viewer width
            self.zoom_level = 1.0
            self.render_page()
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(50, self.fit_width)

            # Update label
            self.update_page_navigation()
            
            self.statusBar().showMessage(f"Loaded: {display_name} ({self.total_pages} pages)")

        except Exception as e:
            self.statusBar().showMessage(f"Error opening PDF: {e}", 5000)
            self._reset_pdf_viewer_state("Error opening PDF. Select another file.")
            print("Error in display_pdf:", e)

    def _reset_pdf_viewer_state(self, message: str | None = None):
        """Clear viewer state so a bad PDF doesn't lock the tab."""
        try:
            if hasattr(self, "doc") and self.doc:
                try:
                    self.doc.close()
                except Exception:
                    pass
            self.doc = None
            self.current_pdf_path = None
            self.current_file = None
            self.current_page_num = 0
            self.total_pages = 0
            # Keep last zoom for convenience; default to 1.0 if missing
            self.zoom_level = getattr(self, "zoom_level", 1.0)

            if hasattr(self, "pdf_label"):
                self.pdf_label.setPixmap(QPixmap())
                if message:
                    self.pdf_label.setText(message)
                    self.pdf_label.setAlignment(Qt.AlignmentFlag.AlignCenter)
                self.pdf_label.adjustSize()

            if hasattr(self, "update_page_navigation"):
                try:
                    self.update_page_navigation()
                except Exception:
                    pass
        except Exception:
            pass

    def load_pdf(self, full_path: str):
        """Open and display a PDF from an absolute path (without relying on folder_path).

        Keeps the existing viewer behavior (zoom, rotation, page nav) and updates
        current_file/current_pdf_path so print/download actions work.
        """
        try:
            if not full_path or not os.path.exists(full_path):
                QMessageBox.warning(self, "Open PDF", "The generated PDF was not found.")
                return

            # Close existing document if any
            if hasattr(self, 'doc') and self.doc:
                try:
                    self.doc.close()
                except Exception:
                    pass

            self.doc = fitz.open(full_path)
            self.current_page_num = 0
            self.current_file = os.path.basename(full_path)
            self.current_pdf_path = full_path
            self.pdf_document = self.doc
            self.zoom_level = 1.0
            self.render_page()
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(50, self.fit_width)
            self.update_page_navigation()
            self.statusBar().showMessage(f"Loaded: {self.current_file} ({len(self.doc)} pages)")
        except Exception as e:
            self.pdf_label.setText(f"Error opening PDF: {e}")
            self.statusBar().showMessage(f"Error: {str(e)}")

    def _save_current_report_pdf(self, dest_dir: str | None = None, silent: bool = True) -> str | None:
        """Render the current report data (headers/rows/summary) to a PDF and return the file path.

        - If dest_dir is None, writes to the system temp directory.
        - When silent=False, shows user notifications on success/failure.
        Returns the absolute path on success, or None on error.
        """
        try:
            from reportlab.lib.pagesizes import letter, landscape
            from reportlab.lib.units import inch
            from reportlab.lib import colors
            from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            import re, datetime, tempfile

            # Choose output directory
            out_dir = dest_dir or tempfile.gettempdir()
            try:
                os.makedirs(out_dir, exist_ok=True)
            except Exception:
                pass

            title = getattr(self, 'current_report_title', 'Report') or 'Report'
            safe_title = re.sub(r"[^A-Za-z0-9_-]+", "_", title).strip("_") or "Report"
            ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            file_path = os.path.join(out_dir, f"{safe_title}_{ts}.pdf")

            doc = SimpleDocTemplate(
                file_path,
                pagesize=landscape(letter),
                leftMargin=0.5*inch,
                rightMargin=0.5*inch,
                topMargin=0.6*inch,
                bottomMargin=0.6*inch,
            )
            styles = getSampleStyleSheet()
            story = []

            # Title
            title_style = ParagraphStyle('title', parent=styles['Heading2'], alignment=1)
            story.append(Paragraph(title, title_style))
            story.append(Spacer(1, 6))

            headers = getattr(self, 'current_report_headers', None)
            rows = getattr(self, 'current_report_rows', None)
            summary_lines = getattr(self, 'current_report_summary_lines', None)

            if headers and rows is not None:
                data = [headers] + rows
                table = Table(data, repeatRows=1)
                table.setStyle(TableStyle([
                    ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
                    ('FONTSIZE', (0,0), (-1,0), 9),
                    ('BACKGROUND', (0,0), (-1,0), colors.lightgrey),
                    ('ALIGN', (0,0), (-1,-1), 'LEFT'),
                    ('FONTSIZE', (0,1), (-1,-1), 8),
                    ('GRID', (0,0), (-1,-1), 0.25, colors.grey),
                    ('VALIGN', (0,0), (-1,-1), 'TOP'),
                ]))
                story.append(table)
            else:
                # Fallback: export the text block
                text = self.reports_text.toPlainText().strip()
                if not text:
                    if not silent:
                        QMessageBox.information(self, "Export PDF", "No report content to export.")
                    return None
                for line in text.split("\n"):
                    story.append(Paragraph(line.replace('  ', '&nbsp;&nbsp;'), styles['Normal']))
                    story.append(Spacer(1, 4))

            # Append summary if available
            if summary_lines:
                story.append(Spacer(1, 12))
                story.append(Paragraph("Summary", styles['Heading4']))
                for l in summary_lines:
                    story.append(Paragraph(l.replace('  ', '&nbsp;&nbsp;'), styles['Normal']))
                    story.append(Spacer(1, 2))

            doc.build(story)
            return file_path
        except Exception as e:
            if not silent:
                QMessageBox.critical(self, "Export PDF", f"Failed to export PDF: {e}")
            return None

    def load_billing_data(self, *args, **kwargs):
        """Stub method for load_billing_data"""
        pass

    def load_data(self, filename):
        """Loads data from the database into the input fields."""
        if not filename:
            return
        
        # Clean filename - remove star prefix if present
        clean_filename = filename
        if clean_filename.startswith("★ "):
            clean_filename = clean_filename[2:]
        
        try:
            conn = sqlite3.connect(self.database_file)
            cursor = conn.cursor()
            
            # Check if phone column exists
            cursor.execute("PRAGMA table_info(documents)")
            columns = [col[1] for col in cursor.fetchall()]
            has_phone = 'phone' in columns
            
            if has_phone:
                cursor.execute("SELECT first_name, last_name, dob, phone, notes FROM documents WHERE filename=?", (clean_filename,))
            else:
                cursor.execute("SELECT first_name, last_name, dob, notes FROM documents WHERE filename=?", (clean_filename,))
            
            row = cursor.fetchone()
            if row:
                if has_phone:
                    if hasattr(self, 'first_name_input'): self.first_name_input.setText(row[0] or "")
                    if hasattr(self, 'last_name_input'): self.last_name_input.setText(row[1] or "")
                    if hasattr(self, 'dob_input'): self.dob_input.setText(row[2] or "")
                    if hasattr(self, 'phone_input'): self.phone_input.setText(row[3] or "")
                    if hasattr(self, 'notes_history'): self.notes_history.setText(row[4] or "")
                else:
                    if hasattr(self, 'first_name_input'): self.first_name_input.setText(row[0] or "")
                    if hasattr(self, 'last_name_input'): self.last_name_input.setText(row[1] or "")
                    if hasattr(self, 'dob_input'): self.dob_input.setText(row[2] or "")
                    if hasattr(self, 'phone_input'): self.phone_input.clear()
                    if hasattr(self, 'notes_history'): self.notes_history.setText(row[3] or "")
            else:
                # Clear fields if no data found
                if hasattr(self, 'first_name_input'): self.first_name_input.clear()
                if hasattr(self, 'last_name_input'): self.last_name_input.clear()
                if hasattr(self, 'dob_input'): self.dob_input.clear()
                if hasattr(self, 'phone_input'): self.phone_input.clear()
                if hasattr(self, 'notes_history'): self.notes_history.clear()
            conn.close()
        except Exception as e:
            print(f"Error loading data for {clean_filename}: {e}")

    def load_inventory_data(self):
        """Load inventory data from database into the table."""
        try:
            from dmelogic.db.inventory import fetch_all_inventory
            items = fetch_all_inventory(folder_path=getattr(self, "folder_path", None))
            
            self.inventory_table.setRowCount(len(items))
            for row, item in enumerate(items):
                for col, value in enumerate(item):
                    # Format currency columns
                    if col in [4, 5] and value is not None:  # Cost and Retail Price
                        display_value = f"${float(value):.2f}"
                    elif col in [10, 11]:  # Date columns
                        display_value = str(value) if value else "Never"
                    else:
                        display_value = str(value) if value is not None else ""
                    
                    self.inventory_table.setItem(row, col, QTableWidgetItem(display_value))
            
            # Update status (indexes 8 and 9 are stock and reorder level)
            low_stock_count = sum(
                1 for item in items
                if item[8] is not None and item[9] is not None and item[8] <= item[9]
            )
            status_text = f"Loaded {len(items)} inventory items"
            if low_stock_count > 0:
                status_text += f" | ⚠️ {low_stock_count} items low stock"
            
            # Update legacy status if it exists
            if hasattr(self, 'inventory_status'):
                self.inventory_status.setText(status_text)
            
            # Update modern inventory summary
            if hasattr(self, 'update_inventory_summary'):
                self.update_inventory_summary()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load inventory data: {e}")
            if hasattr(self, 'inventory_status'):
                self.inventory_status.setText("Error loading inventory data")

    def render_page(self):
        """Render the current page as an image and display."""
        try:
            if not getattr(self, "doc", None):
                return
            if not hasattr(self, "total_pages") or self.total_pages <= 0:
                self.total_pages = self.doc.page_count if hasattr(self.doc, "page_count") else len(self.doc)
            if self.current_page_num < 0 or self.current_page_num >= self.total_pages:
                return

            page = self.doc.load_page(self.current_page_num)
            mat = fitz.Matrix(self.zoom_level, self.zoom_level).prerotate(self.rotation_angle)
            pix = page.get_pixmap(matrix=mat)
            image = QImage(pix.samples, pix.width, pix.height, pix.stride, QImage.Format.Format_RGB888)
            pixmap = QPixmap.fromImage(image)
            
            self.pdf_label.setPixmap(pixmap)
            self.pdf_label.resize(pixmap.size())
            self.update_page_navigation()
        except Exception as e:
            try:
                self.statusBar().showMessage(f"Error rendering PDF: {e}", 5000)
            except Exception:
                pass
            self._reset_pdf_viewer_state("Error rendering PDF. Select another file.")

    def _handle_pdf_label_click(self, event):
        """Handle mouse clicks on PDF to detect link clicks."""
        if hasattr(self, 'current_page_links') and self.current_page_links:
            click_x = event.pos().x()
            click_y = event.pos().y()
            
            # Check if click is within any link rectangle
            for link in self.current_page_links:
                x0, y0, x1, y1 = link['rect']
                if x0 <= click_x <= x1 and y0 <= click_y <= y1:
                    # Open the link
                    import webbrowser
                    webbrowser.open(link['uri'])
                    print(f"Opening link: {link['uri']}")
                    return
        
        # Call original mouse press event if it exists
        QLabel.mousePressEvent(self.pdf_label, event)

