    def perform_icd10_tab_search(self):
        """Perform ICD-10 search from the dedicated tab"""
        search_term = self.icd_search_input.text().strip()
        
        if not search_term:
            self.icd_status_label.setText("Please enter a search term")
            self.icd_status_label.setStyleSheet("color: #dc3545;")
            return
        
        if urllib is None:
            self.icd_status_label.setText("Error: Network library not available")
            self.icd_status_label.setStyleSheet("color: #dc3545;")
            return
        
        self.icd_status_label.setText("Searching...")
        self.icd_status_label.setStyleSheet("color: #007bff;")
        self.icd_results_table.setRowCount(0)
        
        try:
            # Build API URL
            base_url = "https://clinicaltables.nlm.nih.gov/api/icd10cm/v3/search"
            params = {
                'sf': 'code,name',
                'terms': search_term,
                'maxList': 100
            }
            url = f"{base_url}?{urllib.parse.urlencode(params)}"
            
            # Make request
            with urllib.request.urlopen(url, timeout=10) as response:
                data = json.loads(response.read().decode('utf-8'))
            
            # Parse response
            if not data or not isinstance(data, list) or len(data) < 4:
                self.icd_status_label.setText("Invalid response from server")
                self.icd_status_label.setStyleSheet("color: #dc3545;")
                return
            
            count = data[0]
            codes = data[1] if data[1] and isinstance(data[1], list) else []
            descriptions = data[3] if data[3] and isinstance(data[3], list) else []
            
            if count == 0 or not codes:
                self.icd_status_label.setText(f"No results found for '{search_term}'")
                self.icd_status_label.setStyleSheet("color: #666;")
                return
            
            # Populate table
            self.icd_results_table.setRowCount(len(codes))
            for i in range(len(codes)):
                code = str(codes[i]) if i < len(codes) else ""
                desc = str(descriptions[i]) if i < len(descriptions) else ""
                
                code_item = QTableWidgetItem(code)
                desc_item = QTableWidgetItem(desc)
                self.icd_results_table.setItem(i, 0, code_item)
                self.icd_results_table.setItem(i, 1, desc_item)
            
            self.icd_status_label.setText(f"Found {count} result{'s' if count != 1 else ''}")
            self.icd_status_label.setStyleSheet("color: #28a745;")
            
        except urllib.error.URLError as e:
            self.icd_status_label.setText(f"Network error: {str(e)}")
            self.icd_status_label.setStyleSheet("color: #dc3545;")
        except Exception as e:
            self.icd_status_label.setText(f"Error: {str(e)}")
            self.icd_status_label.setStyleSheet("color: #dc3545;")
    
    def copy_selected_icd_code(self):
        """Copy the selected ICD-10 code to clipboard"""
        selected_rows = self.icd_results_table.selectedItems()
        if not selected_rows:
            QMessageBox.information(self, "Copy Code", "Please select a code first")
            return
        
        row = self.icd_results_table.currentRow()
        if row >= 0:
            code_item = self.icd_results_table.item(row, 0)
            if code_item:
                code = code_item.text()
                QApplication.clipboard().setText(code)
                self.icd_status_label.setText(f"Copied code: {code}")
                self.icd_status_label.setStyleSheet("color: #28a745;")
    
    def copy_selected_icd_full(self):
        """Copy the selected ICD-10 code and description to clipboard"""
        selected_rows = self.icd_results_table.selectedItems()
        if not selected_rows:
            QMessageBox.information(self, "Copy", "Please select a code first")
            return
        
        row = self.icd_results_table.currentRow()
        if row >= 0:
            code_item = self.icd_results_table.item(row, 0)
            desc_item = self.icd_results_table.item(row, 1)
            
            if code_item and desc_item:
                full_text = f"{code_item.text()} - {desc_item.text()}"
                QApplication.clipboard().setText(full_text)
                self.icd_status_label.setText(f"Copied: {code_item.text()}")
                self.icd_status_label.setStyleSheet("color: #28a745;")

    def generate_1500_for_selected(self):
        """
        Generate HCFA-1500 claim JSON for the selected order.
        
        This verifies the domain model architecture:
        Order → Hcfa1500Claim → JSON output
        
        No SQL queries - uses fetch_order_with_items() and hcfa1500_from_order().
        """
        from dmelogic.db import fetch_order_with_items
        from dmelogic.claims_1500 import hcfa1500_from_order
        import json
        from PyQt6.QtWidgets import QDialog, QVBoxLayout, QTextEdit, QHBoxLayout, QPushButton
        
        # 1) Get selected order ID
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order to generate HCFA-1500.")
            return
        
        order_id_item = self.orders_table.item(current_row, 0)
        if not order_id_item:
            QMessageBox.warning(self, "Error", "Could not read order ID from table.")
            return
        
        # Parse order number "ORD-001" or "ORD-001-R1" → extract numeric ID
        order_num_text = order_id_item.text()
        try:
            # Format: "ORD-###" or "ORD-###-R#"
            parts = order_num_text.replace("ORD-", "").split("-")
            order_id = int(parts[0])
        except (ValueError, IndexError):
            QMessageBox.warning(self, "Error", f"Could not parse order ID from: {order_num_text}")
            return
        
        folder_path = getattr(self, "folder_path", None)
        
        # 2) Fetch order using domain model
        order = fetch_order_with_items(order_id, folder_path=folder_path)
        if not order:
            QMessageBox.warning(self, "1500 Claim", f"Order {order_num_text} not found in database.")
            return
        
        # 3) Transform to HCFA-1500 claim
        try:
            claim = hcfa1500_from_order(order, folder_path=folder_path)
            payload = claim.to_dict()
        except Exception as e:
            QMessageBox.critical(
                self,
                "1500 Generation Error",
                f"Failed to generate HCFA-1500 claim:\n{e}"
            )
            return
        
        # 4) Display JSON in a dialog
        dialog = QDialog(self)
        dialog.setWindowTitle(f"HCFA-1500 Claim - {order_num_text}")
        dialog.resize(800, 600)
        layout = QVBoxLayout(dialog)
        
        # Header label
        from PyQt6.QtWidgets import QLabel
        header = QLabel(f"<b>HCFA-1500 Claim Data for Order {order_num_text}</b><br>"
                       f"Patient: {order.patient_full_name}<br>"
                       f"Status: {order.order_status.value}")
        layout.addWidget(header)
        
        # JSON display
        text_edit = QTextEdit()
        text_edit.setReadOnly(True)
        text_edit.setPlainText(json.dumps(payload, indent=2, default=str))
        layout.addWidget(text_edit)
        
        # Buttons
        button_layout = QHBoxLayout()
        button_layout.addStretch()
        
        copy_btn = QPushButton("📋 Copy to Clipboard")
        copy_btn.clicked.connect(lambda: self._copy_json_to_clipboard(payload))
        button_layout.addWidget(copy_btn)
        
        save_btn = QPushButton("💾 Save to File")
        save_btn.clicked.connect(lambda: self._save_1500_json(order_id, payload))
        button_layout.addWidget(save_btn)
        
        close_btn = QPushButton("Close")
        close_btn.clicked.connect(dialog.close)
        button_layout.addWidget(close_btn)
        
        layout.addLayout(button_layout)
        dialog.exec()
    
    def _copy_json_to_clipboard(self, payload: dict):
        """Copy JSON payload to clipboard."""
        import json
        from PyQt6.QtWidgets import QApplication
        text = json.dumps(payload, indent=2, default=str)
        QApplication.clipboard().setText(text)
        QMessageBox.information(self, "Copied", "HCFA-1500 claim data copied to clipboard.")
    
    def _save_1500_json(self, order_id: int, payload: dict):
        """Save JSON payload to file."""
        import json
        from PyQt6.QtWidgets import QFileDialog
        
        file_path, _ = QFileDialog.getSaveFileName(
            self,
            "Save HCFA-1500 JSON",
            f"order_{order_id}_hcfa1500.json",
            "JSON Files (*.json)"
        )
        
        if file_path:
            try:
                with open(file_path, 'w', encoding='utf-8') as f:
                    json.dump(payload, f, indent=2, default=str)
                QMessageBox.information(
                    self,
                    "Saved",
                    f"HCFA-1500 claim data saved to:\n{file_path}"
                )
            except Exception as e:
                QMessageBox.critical(
                    self,
                    "Save Failed",
                    f"Failed to save JSON file:\n{e}"
                )

