    def print_1500_for_selected_order(self):
        """
        Generate and print CMS-1500 claim form as PDF.
        
        Architecture:
        Order → Hcfa1500Claim → PDF → Open with viewer
        
        Uses the complete domain model transformation chain:
        1. Fetch Order via fetch_order_with_items()
        2. Transform to Hcfa1500Claim via hcfa1500_from_order()
        3. Render PDF via render_hcfa1500_pdf()
        4. Open PDF with system default viewer
        """
        from dmelogic.db import fetch_order_with_items
        from dmelogic.claims_1500 import hcfa1500_from_order
        from dmelogic.printing.hcfa1500_pdf import render_hcfa1500_pdf
        from pathlib import Path
        import os
        from datetime import datetime
        
        # 1) Get selected order ID
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order to print.")
            return
        
        order_id_item = self.orders_table.item(current_row, 0)
        if not order_id_item:
            QMessageBox.warning(self, "Error", "Could not read order ID from table.")
            return
        
        # Parse order number "ORD-001" or "ORD-001-R1" → extract numeric ID
        order_num_text = order_id_item.text()
        try:
            # Format: "ORD-###" or "ORD-###-R#"
            parts = order_num_text.replace("ORD-", "").split("-")
            order_id = int(parts[0])
        except (ValueError, IndexError):
            QMessageBox.warning(self, "Error", f"Could not parse order ID from: {order_num_text}")
            return
        
        folder_path = getattr(self, "folder_path", None)
        
        # 2) Fetch order using domain model
        order = fetch_order_with_items(order_id, folder_path=folder_path)
        if not order:
            QMessageBox.warning(self, "Print HCFA-1500", f"Order {order_num_text} not found in database.")
            return
        
        # 3) Transform to HCFA-1500 claim
        try:
            claim = hcfa1500_from_order(order, folder_path=folder_path)
        except Exception as e:
            QMessageBox.critical(
                self,
                "Transform Failed",
                f"Failed to generate HCFA-1500 claim data:\n{e}"
            )
            return
        
        # 4) Generate PDF
        # Create output directory if needed
        output_dir = Path(folder_path) / "exports" / "claims"
        output_dir.mkdir(parents=True, exist_ok=True)
        
        # Generate filename with timestamp
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        pdf_filename = f"HCFA1500_Order{order_id}_{timestamp}.pdf"
        pdf_path = output_dir / pdf_filename
        
        try:
            render_hcfa1500_pdf(claim, pdf_path, preprinted_form=True)
        except Exception as e:
            QMessageBox.critical(
                self,
                "PDF Generation Failed",
                f"Failed to generate PDF:\n{e}"
            )
            return
        
        # 5) Open PDF with system default viewer
        try:
            if os.name == 'nt':  # Windows
                os.startfile(str(pdf_path))
            elif os.name == 'posix':  # macOS, Linux
                import subprocess
                subprocess.run(['open' if os.uname().sysname == 'Darwin' else 'xdg-open', str(pdf_path)])
            
            QMessageBox.information(
                self,
                "PDF Generated",
                f"CMS-1500 claim form generated:\n{pdf_path}\n\nOpening in PDF viewer..."
            )
        except Exception as e:
            # If opening fails, still show success message with path
            QMessageBox.information(
                self,
                "PDF Generated",
                f"CMS-1500 claim form generated:\n{pdf_path}\n\n(Could not open automatically: {e})"
            )

    def export_order_to_state_portal(self):
        """
        Export selected order to state portal using domain model.
        
        This is the first consumer of the domain model architecture:
        Order → StatePortalOrderView → CSV/JSON output
        
        No SQL queries in this method - all data fetched via fetch_order_with_items().
        """
        from dmelogic.db import fetch_order_with_items
        from dmelogic.db.state_portal_view import StatePortalOrderView
        import json
        from PyQt6.QtWidgets import QFileDialog
        
        # 1) Get selected order ID
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "No Selection", "Please select an order to export.")
            return
        
        order_id_item = self.orders_table.item(current_row, 0)
        if not order_id_item:
            QMessageBox.warning(self, "Error", "Could not read order ID from table.")
            return
        
        # Parse order number "ORD-001" or "ORD-001-R1" → extract numeric ID
        order_num_text = order_id_item.text()
        try:
            # Format: "ORD-###" or "ORD-###-R#"
            parts = order_num_text.replace("ORD-", "").split("-")
            order_id = int(parts[0])
        except (ValueError, IndexError):
            QMessageBox.warning(self, "Error", f"Could not parse order ID from: {order_num_text}")
            return
        
        folder_path = getattr(self, "folder_path", None)
        
        # 2) Fetch order using domain model
        order = fetch_order_with_items(order_id, folder_path=folder_path)
        if not order:
            QMessageBox.warning(self, "Portal Export", f"Order {order_num_text} not found in database.")
            return
        
        # 3) Transform to portal view
        portal_view = StatePortalOrderView.from_order(order, folder_path=folder_path)
        
        # 4) Ask user for export format
        from PyQt6.QtWidgets import QInputDialog
        format_choice, ok = QInputDialog.getItem(
            self,
            "Export Format",
            "Select export format:",
            ["JSON", "CSV"],
            0,
            False
        )
        
        if not ok:
            return  # User cancelled
        
        # 5) Generate output and save
        if format_choice == "JSON":
            # Export as JSON
            payload = portal_view.to_portal_json()
            file_path, _ = QFileDialog.getSaveFileName(
                self,
                "Save Portal Export (JSON)",
                f"order_{order_id}_portal.json",
                "JSON Files (*.json)"
            )
            
            if file_path:
                try:
                    with open(file_path, 'w', encoding='utf-8') as f:
                        json.dump(payload, f, indent=2, ensure_ascii=False)
                    QMessageBox.information(
                        self,
                        "Export Successful",
                        f"Order {order_num_text} exported to:\n{file_path}"
                    )
                except Exception as e:
                    QMessageBox.critical(
                        self,
                        "Export Failed",
                        f"Failed to write JSON file:\n{e}"
                    )
        
        else:  # CSV
            # Export as CSV
            csv_row = portal_view.to_csv_row()
            file_path, _ = QFileDialog.getSaveFileName(
                self,
                "Save Portal Export (CSV)",
                f"order_{order_id}_portal.csv",
                "CSV Files (*.csv)"
            )
            
            if file_path:
                try:
                    import csv
                    with open(file_path, 'w', newline='', encoding='utf-8') as f:
                        writer = csv.writer(f)
                        # Write header
                        writer.writerow(csv_row.keys())
                        # Write data
                        writer.writerow(csv_row.values())
                    QMessageBox.information(
                        self,
                        "Export Successful",
                        f"Order {order_num_text} exported to:\n{file_path}"
                    )
                except Exception as e:
                    QMessageBox.critical(
                        self,
                        "Export Failed",
                        f"Failed to write CSV file:\n{e}"
                    )
    
    def open_epaces_helper(self):
        """Open the ePACES billing helper dialog for the selected order."""
        print("[EPACES] open_epaces_helper called!")
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            QMessageBox.warning(self, "ePACES", "Please select an order first.")
            return
        
        # Get order ID from selected row
        order_number = self.orders_table.item(current_row, 0).text()
        order_id = int(self.get_order_id_from_display(order_number) or 0)
        if order_id == 0:
            QMessageBox.warning(self, "ePACES", "Could not determine order ID.")
            return
        
        try:
            from dmelogic.db import fetch_order_with_items
            from dmelogic.ui.epaces_helper import EpacesHelperDialog
            
            # Load order object
            order = fetch_order_with_items(order_id, self.folder_path)
            if not order:
                QMessageBox.warning(self, "ePACES", "Order not found.")
                return
            
            dialog = EpacesHelperDialog(
                order=order,
                folder_path=self.folder_path,
                parent=self
            )

            # ── Check if this order has an RX on File ──
            try:
                from reserved_rx_manager import get_reserved_rx_data
                db_path = getattr(self, 'orders_db_path', None) or os.path.join(self.folder_path, "orders.db")
                print(f"[RX check] order_id={order_id}, db_path={db_path}")
                rx_data = get_reserved_rx_data(db_path, str(order_id))
                print(f"[RX check] rx_data={rx_data}")
                if rx_data and int(rx_data.get("rx_on_file", 0)):
                    md_name = rx_data.get("reserved_rx_md", "") or "Unknown"
                    rx_date = rx_data.get("reserved_rx_date", "") or "N/A"
                    rx_doc  = rx_data.get("reserved_rx_path", "") or ""
                    doc_display = os.path.basename(rx_doc) if rx_doc else "—"

                    alert = QMessageBox(dialog)
                    alert.setIcon(QMessageBox.Icon.Information)
                    alert.setWindowTitle("RX Already on File")
                    alert.setText(
                        f"<b>This patient already has an RX on file.</b><br>"
                        f"<b>Do NOT contact the prescriber again.</b>"
                    )
                    alert.setInformativeText(
                        f"<table style='font-size:12px;'>"
                        f"<tr><td><b>Prescriber:</b></td><td>&nbsp;{md_name}</td></tr>"
                        f"<tr><td><b>Date Received:</b></td><td>&nbsp;{rx_date}</td></tr>"
                        f"<tr><td><b>Document:</b></td><td>&nbsp;{doc_display}</td></tr>"
                        f"</table>"
                    )
                    alert.setStandardButtons(QMessageBox.StandardButton.Ok)
                    alert.exec()
            except Exception as e:
                print(f"[RX on File check] ERROR: {e}")
                import traceback
                traceback.print_exc()

            dialog.exec()
        except Exception as e:
            QMessageBox.critical(
                self,
                "ePACES Error",
                f"Failed to open ePACES helper:\n{e}"
            )

    def batch_mark_delivered(self):
        """Mark multiple selected orders as delivered with today's date."""
        selected_rows = self.orders_table.selectionModel().selectedRows()
        if not selected_rows:
            QMessageBox.warning(self, "No Selection", "Please select one or more orders first.\n\nTip: Hold Ctrl and click to select multiple orders.")
            return
        
        # Get unique order IDs from selected rows
        order_ids = set()
        order_numbers = []
        for index in selected_rows:
            row = index.row()
            order_number_item = self.orders_table.item(row, 0)
            if order_number_item:
                order_number = order_number_item.text()
                order_id = self.get_order_id_from_display(order_number)
                if order_id:
                    order_ids.add(int(order_id))
                    if order_number not in order_numbers:
                        order_numbers.append(order_number)
        
        if not order_ids:
            QMessageBox.warning(self, "Invalid Selection", "Couldn't determine order IDs.")
            return
        
        # Confirm
        count = len(order_ids)
        confirm = QMessageBox.question(
            self,
            "Batch Mark Delivered",
            f"Mark {count} order(s) as delivered with today's date?\n\nOrders: {', '.join(order_numbers[:5])}{'...' if len(order_numbers) > 5 else ''}",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
            QMessageBox.StandardButton.No,
        )
        if confirm != QMessageBox.StandardButton.Yes:
            return
        
        try:
            from datetime import datetime
            today = datetime.now().strftime("%Y-%m-%d")
            
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Update all selected orders
            for order_id in order_ids:
                cursor.execute(
                    "UPDATE orders SET delivery_date = ?, order_status = 'Shipped' WHERE id = ?",
                    (today, order_id)
                )
            
            conn.commit()
            conn.close()
            
            # Refresh table
            self.load_orders()
            QMessageBox.information(self, "Success", f"Marked {count} order(s) as delivered.")
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to batch mark delivered: {e}")
            print(f"Batch delivered error: {e}")

