    def edit_order_LEGACY(self):
        """LEGACY: Edit selected order by opening it in the order dialog."""
        current_row = self.orders_table.currentRow()
        if current_row < 0:
            return
        
        # Get order number and extract ID
        order_number = self.orders_table.item(current_row, 0).text()
        order_id = int(self.get_order_id_from_display(order_number) or 0)
        if order_id == 0:
            QMessageBox.warning(self, "Invalid Order", "Couldn't determine the order ID.")
            return
        
        try:
            # Load order data from database
            conn = sqlite3.connect(self.orders_db_path)
            cursor = conn.cursor()
            
            # Get main order data (align with NewOrderDialog.populate_existing_order expectations)
            cursor.execute(
                """
                SELECT rx_date, order_date, patient_last_name, patient_first_name,
                       prescriber_name, prescriber_npi, order_status,
                       delivery_date, tracking_number, notes, is_pickup,
                       icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                       attached_rx_files, attached_signed_ticket_files, COALESCE(billed, 0), COALESCE(paid, 0), paid_date, doctor_directions,
                       rx_origin, clinic, prescriber_fax
                FROM orders 
                WHERE id = ?
                """,
                (order_id,),
            )
            order_data = cursor.fetchone()
            
            if not order_data:
                QMessageBox.warning(self, "Error", "Order not found in database.")
                conn.close()
                return
            
            # Check if there are notes (index 9 in the order_data tuple)
            notes = order_data[9]
            if notes and notes.strip():
                # Show modal warning dialog with notes that must be closed before proceeding
                from PyQt6.QtWidgets import QDialog, QVBoxLayout, QLabel, QPushButton, QTextEdit
                
                notes_dialog = QDialog(self)
                notes_dialog.setWindowTitle("⚠️ Order Notes")
                notes_dialog.setModal(True)  # Force modal behavior
                notes_dialog.setMinimumSize(500, 300)
                
                layout = QVBoxLayout(notes_dialog)
                
                # Warning header
                warning_label = QLabel("📝 <b>IMPORTANT: This order has notes</b>")
                warning_label.setStyleSheet("""
                    QLabel {
                        background-color: #ff9800;
                        color: white;
                        padding: 12px;
                        font-size: 14px;
                        border-radius: 4px;
                    }
                """)
                layout.addWidget(warning_label)
                
                # Notes display
                notes_display = QTextEdit()
                notes_display.setPlainText(notes)
                notes_display.setReadOnly(True)
                notes_display.setStyleSheet("""
                    QTextEdit {
                        background-color: #fff3cd;
                        border: 2px solid #ff9800;
                        padding: 10px;
                        font-size: 12px;
                    }
                """)
                layout.addWidget(notes_display)
                
                # OK button to dismiss
                ok_btn = QPushButton("I Have Read The Notes - Continue")
                ok_btn.setStyleSheet("""
                    QPushButton {
                        background-color: #ff9800;
                        color: white;
                        font-weight: bold;
                        padding: 10px 20px;
                        border-radius: 4px;
                        font-size: 13px;
                    }
                    QPushButton:hover {
                        background-color: #f57c00;
                    }
                """)
                ok_btn.clicked.connect(notes_dialog.accept)
                layout.addWidget(ok_btn)
                
                # Force user to acknowledge notes before continuing
                notes_dialog.exec()
            
            # Get order items in explicit order matching populate_existing_order
            cursor.execute(
                """
                SELECT COALESCE(rx_no,''), COALESCE(hcpcs_code,''), COALESCE(description,''),
                       COALESCE(item_number,''), COALESCE(refills,''), COALESCE(day_supply,''),
                       COALESCE(qty,''), COALESCE(cost_ea,''), COALESCE(total,''), COALESCE(pa_number,''), COALESCE(directions,'')
                FROM order_items WHERE order_id = ? ORDER BY id ASC
                """,
                (order_id,),
            )
            order_items = cursor.fetchall()
            conn.close()
            
            # Create dialog with existing data
            dialog = NewOrderDialog(self, order_data, order_items, order_id)
            
            # Set window title with patient name
            patient_last = order_data[2] if order_data and len(order_data) > 2 else ""
            patient_first = order_data[3] if order_data and len(order_data) > 3 else ""
            patient_name = f"{patient_first} {patient_last}" if patient_first or patient_last else "Unknown Patient"
            dialog.setWindowTitle(f"Edit Order {order_number} - {patient_name}")

            # Register as modeless child
            if hasattr(self, "register_child_window"):
                self.register_child_window(dialog)

            # When user saves & accepts, refresh the Orders table
            try:
                def _on_accepted(order_num=order_number):
                    try:
                        self.load_orders()
                    except Exception:
                        pass
                    print(f"✅ Order {order_num} updated successfully")

                dialog.accepted.connect(_on_accepted)
            except Exception:
                pass

            dialog.show()
            dialog.raise_()
            dialog.activateWindow()
                
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load order: {e}")
            print(f"Order edit error: {e}")

    def process_refill(self):
        """Create a new order that is a refill of the selected order.

        Rules:
        - New row in orders with parent_order_id pointing to the original root order
        - refill_number increments (1, 2, ...) based on existing refills of the root
        - Copy patient, prescriber, ICD-10, attached RX files
        - Set order_date=today; keep rx_date same as original; status='Pending'; delivery_date=NULL; tracking=NULL; is_pickup=0
        - Duplicate order_items rows
        """
        try:
            from dmelogic.refill_service import process_refill, RefillError

            row = self.orders_table.currentRow()
            if row < 0:
                QMessageBox.warning(self, "No Selection", "Please select an order to process a refill.")
                return

            order_display = self.orders_table.item(row, 0).text() if self.orders_table.item(row, 0) else ""
            seed_order_id = self.get_order_id_from_display(order_display)
            if not seed_order_id:
                QMessageBox.warning(self, "Invalid Order", "Couldn't determine the selected order ID.")
                return

            # Force user to pick which specific order from history to refill
            chosen_order_id = self.select_order_to_refill(seed_order_id)
            if not chosen_order_id:
                return  # user cancelled

            folder_path = getattr(self, "folder_path", None)
            try:
                new_order = process_refill(int(chosen_order_id), folder_path=folder_path)
            except RefillError as e:
                QMessageBox.critical(self, "Refill Error", f"Cannot process refill:\n\n{e}")
                return
            except Exception as e:
                QMessageBox.critical(self, "Refill Error", f"Failed to process refill:\n\n{e}")
                return

            new_order_id = new_order.id
            display_no = self.format_order_number(new_order_id) if hasattr(self, "format_order_number") else str(new_order_id)

            # Refresh table, select new row, prompt to edit
            self.load_orders()
            try:
                for r in range(self.orders_table.rowCount()):
                    d = self.orders_table.item(r, 0).text() if self.orders_table.item(r, 0) else ""
                    if self.get_order_id_from_display(d) == new_order_id:
                        self.orders_table.selectRow(r)
                        break
            except Exception:
                pass

            # Offer to open the new refill for edits
            reply = QMessageBox.question(
                self,
                "Refill Created",
                f"Refill order {display_no} created successfully. Open it now for review?",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.Yes,
            )
            if reply == QMessageBox.StandardButton.Yes:
                try:
                    self.edit_order()
                except Exception:
                    self.edit_order_by_id(new_order_id)

        except Exception as e:
            QMessageBox.critical(self, "Refill Error", f"Failed to process refill: {e}")
            print(f"Process refill error: {e}")

    def reverse_refill_order(self):
        """Reverse the selected refill order: restores parent refills, unlocks parent, deletes refill."""
        try:
            from dmelogic.refill_service import reverse_refill, RefillError
            from dmelogic.db import fetch_order_with_items

            row = self.orders_table.currentRow()
            if row < 0:
                QMessageBox.warning(self, "No Selection", "Select a refill order to reverse.")
                return

            order_display = self.orders_table.item(row, 0).text() if self.orders_table.item(row, 0) else ""
            order_id = self.get_order_id_from_display(order_display)
            if not order_id:
                QMessageBox.warning(self, "Invalid Order", "Couldn't determine the selected order ID.")
                return

            # Load order to verify it is a refill
            order = fetch_order_with_items(order_id, folder_path=self.folder_path)
            if not order:
                QMessageBox.warning(self, "Not Found", "Order could not be loaded.")
                return
            if not order.parent_order_id:
                QMessageBox.information(self, "Not a Refill", "Only refill orders can be reversed.")
                return

            parent_fmt = self.format_order_number(order.parent_order_id) if hasattr(self, "format_order_number") else str(order.parent_order_id)
            refill_fmt = self.format_order_number(order_id) if hasattr(self, "format_order_number") else str(order_id)

            confirm = QMessageBox.question(
                self,
                "Reverse Refill",
                f"Reverse {refill_fmt} and restore refills to parent {parent_fmt}?\n\n"
                "This will delete the refill order and unlock the parent.",
                QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                QMessageBox.StandardButton.No,
            )
            if confirm != QMessageBox.StandardButton.Yes:
                return

            try:
                parent = reverse_refill(order_id, folder_path=self.folder_path)
            except RefillError as e:
                QMessageBox.critical(self, "Refill Error", f"Cannot reverse refill:\n\n{e}")
                return
            except Exception as e:
                QMessageBox.critical(self, "Error", f"Failed to reverse refill:\n\n{e}")
                return

            parent_display = self.format_order_number(parent.id) if hasattr(self, "format_order_number") else str(parent.id)

            self.load_orders()
            QMessageBox.information(
                self,
                "Refill Reversed",
                f"Refill {refill_fmt} has been reversed. Parent {parent_display} unlocked."
            )

        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to reverse refill: {e}")
            print(f"Reverse refill error: {e}")

    def select_order_to_refill(self, seed_order_id: int) -> int | None:
        """Show a simple selection dialog listing this patient's orders and return the chosen order id.

        Returns None if user cancels.
        """
        try:
            conn = sqlite3.connect(self.orders_db_path)
            cur = conn.cursor()
            # Get patient identity from seed order
            cur.execute(
                "SELECT patient_last_name, patient_first_name, COALESCE(patient_dob,'') FROM orders WHERE id = ?",
                (seed_order_id,),
            )
            row = cur.fetchone()
            if not row:
                conn.close()
                return None
            last_name, first_name, dob = row
            # Fetch all orders for the same patient (exclude already-refilled orders)
            cur.execute(
                """
                SELECT id, rx_date, order_status, COALESCE(refill_number,0)
                FROM orders
                WHERE UPPER(patient_last_name)=UPPER(?) AND UPPER(patient_first_name)=UPPER(?) AND COALESCE(patient_dob,'')=COALESCE(?, '')
                  AND COALESCE(refill_completed, 0) = 0
                ORDER BY rx_date ASC, id ASC
                """,
                (last_name, first_name, dob),
            )
            orders = cur.fetchall()

            # Fallback: if no orders found (stale refill_completed flags), show ALL orders
            if not orders:
                cur.execute(
                    """
                    SELECT id, rx_date, order_status, COALESCE(refill_number,0)
                    FROM orders
                    WHERE UPPER(patient_last_name)=UPPER(?) AND UPPER(patient_first_name)=UPPER(?) AND COALESCE(patient_dob,'')=COALESCE(?, '')
                    ORDER BY rx_date ASC, id ASC
                    """,
                    (last_name, first_name, dob),
                )
                orders = cur.fetchall()
                # Auto-fix: clear stale refill_completed and is_locked flags
                for (oid, *_rest) in orders:
                    cur.execute(
                        "SELECT COUNT(*) FROM orders WHERE parent_order_id = ?",
                        (oid,),
                    )
                    child_count = cur.fetchone()[0]
                    if child_count == 0:
                        cur.execute(
                            "UPDATE orders SET refill_completed = 0, refill_completed_at = NULL, is_locked = 0 WHERE id = ? AND (COALESCE(refill_completed, 0) = 1 OR COALESCE(is_locked, 0) = 1)",
                            (oid,),
                        )
                conn.commit()

            conn.close()

            # Build dialog
            dlg = QDialog(self)
            dlg.setWindowTitle("Select Order to Refill")
            dlg.resize(600, 300)
            vbox = QVBoxLayout(dlg)
            label = QLabel(f"Select which order for {first_name} {last_name} to refill:")
            vbox.addWidget(label)
            table = QTableWidget()
            table.setColumnCount(4)
            table.setHorizontalHeaderLabels(["Order #", "RX Date", "Status", "Refill #"])
            table.setRowCount(len(orders))
            for r, (oid, rx_date, status, rno) in enumerate(orders):
                try:
                    num = self.format_order_number(oid)
                except Exception:
                    num = f"ORD-{str(oid).zfill(3)}" + (f"-R{rno}" if (rno or 0) > 0 else "")
                table.setItem(r, 0, QTableWidgetItem(num))
                table.setItem(r, 1, QTableWidgetItem(self.format_date_display(rx_date)))
                table.setItem(r, 2, QTableWidgetItem(status or "Pending"))
                table.setItem(r, 3, QTableWidgetItem(str(int(rno or 0))))
                # store id
                table.item(r, 0).setData(Qt.ItemDataRole.UserRole, oid)
                if oid == seed_order_id:
                    table.selectRow(r)
            table.resizeColumnsToContents()
            vbox.addWidget(table)
            # Buttons
            hbox = QHBoxLayout()
            hbox.addStretch()
            ok_btn = QPushButton("OK")
            cancel_btn = QPushButton("Cancel")
            hbox.addWidget(ok_btn)
            hbox.addWidget(cancel_btn)
            vbox.addLayout(hbox)

            chosen_id = {"val": None}
            def on_ok():
                sel = table.selectedItems()
                if not sel:
                    QMessageBox.warning(dlg, "No Selection", "Please select an order to refill.")
                    return
                r = sel[0].row()
                itm = table.item(r, 0)
                if itm:
                    chosen_id["val"] = itm.data(Qt.ItemDataRole.UserRole)
                dlg.accept()
            ok_btn.clicked.connect(on_ok)
            cancel_btn.clicked.connect(dlg.reject)

            if dlg.exec() == QDialog.DialogCode.Accepted:
                return int(chosen_id["val"]) if chosen_id["val"] else None
            return None
        except Exception as e:
            print(f"Select order to refill error: {e}")
            return None

    def create_refill_order(self, src_order_id: int) -> int:
        """Duplicate an order as a refill. Returns new order id."""
        conn = sqlite3.connect(self.orders_db_path)
        cur = conn.cursor()

        # Load source order header
        cur.execute(
            """
            SELECT id,
                   COALESCE(parent_order_id, NULL) AS parent_id,
                   COALESCE(refill_number, 0) AS refill_no,
                   rx_date, order_date,
                   patient_last_name, patient_first_name, patient_dob,
                   patient_address, patient_phone, patient_id, patient_name, patient_secondary_contact,
                   prescriber_name, prescriber_npi,
                   order_status, delivery_date, tracking_number, notes, is_pickup,
                   icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                   attached_rx_files, attached_signed_ticket_files,
                   billed, paid, paid_date, doctor_directions
            FROM orders WHERE id = ?
            """,
            (src_order_id,),
        )
        src = cur.fetchone()
        if not src:
            conn.close()
            raise ValueError("Source order not found")

        (
            _id,
            parent_id,
            _refill_no,
            rx_date,
            _order_date,
            last_name,
            first_name,
            patient_dob,
            patient_address,
            patient_phone,
            patient_db_id,
            patient_full_name,
            patient_secondary_contact,
            prescriber_name,
            prescriber_npi,
            _status,
            _delivery_date,
            _tracking,
            _notes,
            _is_pickup,
            icd1, icd2, icd3, icd4, icd5,
            attached_rx,
            attached_signed,
            billed,
            paid,
            paid_date,
            doctor_directions
        ) = src

        # Determine root order and next refill number
        root_id = parent_id if parent_id else src_order_id
        cur.execute("SELECT COALESCE(MAX(refill_number), 0) FROM orders WHERE parent_order_id = ?", (root_id,))
        max_refill = cur.fetchone()[0] or 0
        next_refill = int(max_refill) + 1

        # Check if ANY items have refills remaining
        cur.execute(
            """
            SELECT id, COALESCE(refills,'') 
            FROM order_items 
            WHERE order_id = ? 
            ORDER BY id
            """,
            (src_order_id,),
        )
        src_items = cur.fetchall()
        
        # Count how many items have refills > 0
        items_with_refills = []
        for (item_id, ref_val) in src_items:
            try:
                n = int(float(ref_val.strip())) if str(ref_val).strip() != '' else 0
            except Exception:
                n = 0
            if n > 0:
                items_with_refills.append((item_id, n))
        
        if not items_with_refills:
            conn.close()
            raise ValueError("No items have refills remaining on the selected order.")

        # Decrement refills on source order items that have refills > 0
        items_to_copy = []
        for (item_id, current_refills) in items_with_refills:
            new_refills = max(0, current_refills - 1)
            cur.execute("UPDATE order_items SET refills = ? WHERE id = ?", (str(new_refills), item_id))
            items_to_copy.append((item_id, new_refills))

        # Insert new order header
        today_str = QDate.currentDate().toString("yyyy-MM-dd")
        cur.execute(
            """
            INSERT INTO orders (
                rx_date, order_date,
                patient_last_name, patient_first_name, patient_dob,
                patient_address, patient_phone, patient_id, patient_name, patient_secondary_contact,
                prescriber_name, prescriber_npi,
                order_status, delivery_date, tracking_number, notes, is_pickup,
                icd_code_1, icd_code_2, icd_code_3, icd_code_4, icd_code_5,
                attached_rx_files, attached_signed_ticket_files, created_date,
                parent_order_id, refill_number,
                billed, paid, paid_date, doctor_directions
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NULL, NULL, NULL, 0, ?, ?, ?, ?, ?, ?, ?, datetime('now'), ?, ?, ?, ?, ?, ?)
            """,
            (
                rx_date,
                today_str,
                last_name,
                first_name,
                patient_dob,
                patient_address,
                patient_phone,
                patient_db_id,
                patient_full_name,
                patient_secondary_contact,
                prescriber_name,
                prescriber_npi,
                'Unbilled',
                icd1, icd2, icd3, icd4, icd5,
                attached_rx,
                attached_signed,
                root_id, next_refill,
                0,  # billed - refills start as not billed
                0,  # paid - refills start as not paid
                None,  # paid_date - refills have no paid date
                doctor_directions
            ),
        )
        new_order_id = cur.lastrowid

        # Copy ONLY items that had refills remaining
        for (item_id, child_refills) in items_to_copy:
            cur.execute(
                "SELECT rx_no, hcpcs_code, description, day_supply, qty, cost_ea, total, pa_number FROM order_items WHERE id = ?",
                (item_id,),
            )
            item_data = cur.fetchone()
            if not item_data:
                continue
            
            rx_no, hcpcs_code, description, day_supply, qty, cost_ea, total, pa_number = item_data
            
            cur.execute(
                """
                INSERT INTO order_items (
                    order_id, rx_no, hcpcs_code, description,
                    refills, day_supply, qty, cost_ea, total, pa_number
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    new_order_id,
                    rx_no,
                    hcpcs_code,
                    description,
                    str(child_refills),
                    day_supply,
                    qty,
                    cost_ea,
                    total,
                    pa_number,
                ),
            )

        conn.commit()
        conn.close()
        return new_order_id

    # ========== PRESCRIBER MANAGEMENT METHODS ==========
    def load_prescribers(self):
        """Load prescribers into the prescriber table."""
        try:
            conn = sqlite3.connect(self.prescriber_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT id, last_name, first_name, specialty, npi_number, phone, fax,
                       address_line1, address_line2, city, state, zip_code
                FROM prescribers 
                ORDER BY last_name, first_name
            """)
            prescribers = cursor.fetchall()
            conn.close()
            
            # Clear existing table
            self.prescriber_table.setRowCount(0)
            
            # Add prescriber data to table
            for row_idx, prescriber in enumerate(prescribers):
                self.prescriber_table.insertRow(row_idx)
                
                # Map database columns to table columns:
                # [0]=ID, [1]=Last Name, [2]=First Name, [3]=Specialty, [4]=NPI, [5]=Phone, [6]=Fax, [7]=Address
                id_val, last_name, first_name, specialty, npi, phone, fax, addr1, addr2, city, state, zip_code = prescriber
                
                # Build full address
                address_parts = [p for p in [addr1, addr2, city, state, zip_code] if p]
                full_address = ", ".join(address_parts) if address_parts else ""
                
                # Set table items with explicit light text color for dark theme
                id_item = QTableWidgetItem(str(id_val))
                id_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 0, id_item)
                
                last_item = QTableWidgetItem(last_name.upper() if last_name else "")
                last_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 1, last_item)
                
                first_item = QTableWidgetItem(first_name.upper() if first_name else "")
                first_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 2, first_item)
                
                specialty_item = QTableWidgetItem(specialty if specialty else "")
                specialty_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 3, specialty_item)
                
                npi_item = QTableWidgetItem(npi if npi else "")
                npi_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 4, npi_item)
                
                phone_item = QTableWidgetItem(phone if phone else "")
                phone_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 5, phone_item)
                
                fax_item = QTableWidgetItem(fax if fax else "")
                fax_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 6, fax_item)
                
                address_item = QTableWidgetItem(full_address)
                address_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 7, address_item)
                    
            print(f"✅ Loaded {len(prescribers)} prescribers")
            
        except Exception as e:
            print(f"Error loading prescribers: {e}")
            QMessageBox.critical(self, "Error", f"Failed to load prescribers: {e}")

    def search_prescribers(self, text):
        """Search prescribers based on name, NPI, title, or practice name."""
        if len(text) < 2:  # Only search if 2+ characters
            self.load_prescribers()
            return
            
        try:
            conn = sqlite3.connect(self.prescriber_database_file)
            cursor = conn.cursor()
            
            # Search in multiple fields (convert search term to uppercase)
            search_term = f"%{text.upper()}%"
            search_digits = ''.join(ch for ch in text if ch.isdigit()) or text
            cursor.execute("""
                SELECT id, last_name, first_name, title, practice_name, specialty, npi_number, phone, fax,
                       address_line1, address_line2, city, state, zip_code
                FROM prescribers 
                  WHERE UPPER(last_name) LIKE ? OR UPPER(first_name) LIKE ? OR npi_number LIKE ? 
                     OR UPPER(practice_name) LIKE ? OR UPPER(title) LIKE ? OR UPPER(specialty) LIKE ?
                     OR phone LIKE ? OR fax LIKE ?
                     OR REPLACE(REPLACE(REPLACE(phone, '-', ''), '(', ''), ')', '') LIKE ?
                     OR REPLACE(REPLACE(REPLACE(fax, '-', ''), '(', ''), ')', '') LIKE ?
                ORDER BY last_name, first_name
                 """, (search_term, search_term, search_term, search_term, search_term, search_term,
                     f"%{text}%", f"%{text}%", f"%{search_digits}%", f"%{search_digits}%"))
            
            prescribers = cursor.fetchall()
            conn.close()
            
            # Clear existing table
            self.prescriber_table.setRowCount(0)
            
            # Add matching prescribers to table
            for row_idx, prescriber in enumerate(prescribers):
                self.prescriber_table.insertRow(row_idx)
                
                # Map database columns to table columns
                id_val, last_name, first_name, title, practice_name, specialty, npi, phone, fax, addr1, addr2, city, state, zip_code = prescriber
                
                # Build full address
                address_parts = [p for p in [addr1, addr2, city, state, zip_code] if p]
                full_address = ", ".join(address_parts) if address_parts else ""
                
                # Set table items with explicit light text color for dark theme
                id_item = QTableWidgetItem(str(id_val))
                id_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 0, id_item)
                
                last_item = QTableWidgetItem(last_name.upper() if last_name else "")
                last_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 1, last_item)
                
                first_item = QTableWidgetItem(first_name.upper() if first_name else "")
                first_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 2, first_item)
                
                title_item = QTableWidgetItem(title if title else "")
                title_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 3, title_item)
                
                practice_item = QTableWidgetItem(practice_name if practice_name else "")
                practice_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 4, practice_item)
                
                specialty_item = QTableWidgetItem(specialty if specialty else "")
                specialty_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 5, specialty_item)
                
                npi_item = QTableWidgetItem(npi if npi else "")
                npi_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 6, npi_item)
                
                phone_item = QTableWidgetItem(phone if phone else "")
                phone_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 7, phone_item)
                
                fax_item = QTableWidgetItem(fax if fax else "")
                fax_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 8, fax_item)
                
                address_item = QTableWidgetItem(full_address)
                address_item.setForeground(QColor("#000000"))
                self.prescriber_table.setItem(row_idx, 9, address_item)
                    
            print(f"🔍 Found {len(prescribers)} prescribers matching '{text}'")
            
        except Exception as e:
            print(f"Error searching prescribers: {e}")

    def add_prescriber(self):
        """Open dialog to add a new prescriber."""
        dialog = PrescriberDialog(self)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            prescriber_data = dialog.get_prescriber_data()
            
            try:
                conn = sqlite3.connect(self.prescriber_database_file)
                cursor = conn.cursor()
                
                cursor.execute("""
                    INSERT INTO prescribers (
                        first_name, last_name, title, npi_number, license_number,
                        specialty, phone, fax, email, practice_name,
                        address_line1, address_line2, city, state, zip_code,
                        dea_number, tax_id, status, notes
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """, (
                    prescriber_data['first_name'].upper(), prescriber_data['last_name'].upper(),
                    prescriber_data['title'].upper(), prescriber_data['npi_number'],
                    prescriber_data['license_number'], prescriber_data['specialty'],
                    prescriber_data['phone'], prescriber_data['fax'],
                    prescriber_data['email'], prescriber_data['practice_name'],
                    prescriber_data['address_line1'], prescriber_data['address_line2'],
                    prescriber_data['city'], prescriber_data['state'],
                    prescriber_data['zip_code'], prescriber_data['dea_number'],
                    prescriber_data['tax_id'], prescriber_data['status'],
                    prescriber_data['notes']
                ))
                
                conn.commit()
                conn.close()
                
                # Refresh the prescriber list
                self.load_prescribers()
                print(f"✅ Added prescriber: {prescriber_data['last_name']}, {prescriber_data['first_name']}")
                
                # Also refresh any open NewOrderDialog
                self.refresh_order_dialogs()
                
                QMessageBox.information(self, "Success", "Prescriber added successfully!")
                
            except sqlite3.IntegrityError as e:
                if "npi_number" in str(e):
                    QMessageBox.warning(self, "Error", "NPI number already exists!")
                else:
                    QMessageBox.critical(self, "Error", f"Database error: {e}")
            except Exception as e:
                print(f"Error adding prescriber: {e}")
                QMessageBox.critical(self, "Error", f"Failed to add prescriber: {e}")

