    def search_inventory(self, text):
        """Search inventory items by HCPCS code, description, or category."""
        search_term = (text or "").strip().lower()

        # If the user clears the box or types fewer than 2 characters, just reload all data
        if len(search_term) < 2:
            self.load_inventory_data()
            return

        try:
            from dmelogic.db.inventory import fetch_all_inventory

            rows = fetch_all_inventory(folder_path=getattr(self, "folder_path", None))

            # Filter in-memory to avoid DB path mismatches and keep column coverage consistent
            filtered = []
            for r in rows:
                row_dict = dict(r) if not isinstance(r, dict) else r
                haystack = " ".join(
                    [
                        str(row_dict.get("item_id", "")),
                        str(row_dict.get("item_number", "")),
                        str(row_dict.get("hcpcs_code", "")),
                        str(row_dict.get("description", "")),
                        str(row_dict.get("category", "")),
                        str(row_dict.get("brand", "")),
                        str(row_dict.get("supplier", "")),
                    ]
                ).lower()
                if search_term in haystack:
                    filtered.append(row_dict)

            # Display results with the same columns as the main grid
            columns = [
                "item_id",
                "hcpcs_code",
                "description",
                "category",
                "cost",
                "retail_price",
                "brand",
                "supplier",
                "stock_quantity",
                "reorder_level",
                "last_used_date",
                "last_restocked_date",
            ]

            self.inventory_table.setRowCount(len(filtered))
            for row_idx, row_dict in enumerate(filtered):
                for col_idx, key in enumerate(columns):
                    value = row_dict.get(key)
                    if col_idx in [4, 5] and value not in (None, ""):
                        display_value = f"${float(value):.2f}"
                    elif col_idx in [10, 11]:
                        display_value = str(value) if value else "Never"
                    else:
                        display_value = str(value) if value is not None else ""
                    self.inventory_table.setItem(row_idx, col_idx, QTableWidgetItem(display_value))

            status_text = f"Found {len(filtered)} item{'s' if len(filtered) != 1 else ''} matching '{text}'"
            if hasattr(self, "inventory_status"):
                self.inventory_status.setText(status_text)

        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to search inventory: {e}")
    
    def load_inventory_data(self):
        """Load inventory data from database into the table."""
        try:
            from dmelogic.db.inventory import fetch_all_inventory
            items = fetch_all_inventory(folder_path=getattr(self, "folder_path", None))
            # Note: This is a duplicate method - main implementation is above
            
            self.inventory_table.setRowCount(len(items))
            for row, item in enumerate(items):
                for col, value in enumerate(item):
                    # Format currency columns
                    if col in [4, 5] and value is not None:  # Cost and Retail Price
                        display_value = f"${float(value):.2f}"
                    elif col in [10, 11]:  # Date columns
                        display_value = str(value) if value else "Never"
                    else:
                        display_value = str(value) if value is not None else ""
                    
                    self.inventory_table.setItem(row, col, QTableWidgetItem(display_value))
            
            # Update status (indexes 8 and 9 are stock and reorder level)
            low_stock_count = sum(
                1 for item in items
                if item[8] is not None and item[9] is not None and item[8] <= item[9]
            )
            status_text = f"Loaded {len(items)} inventory items"
            if low_stock_count > 0:
                status_text += f" | ⚠️ {low_stock_count} items low stock"
            self.inventory_status.setText(status_text)
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to load inventory data: {e}")
            self.inventory_status.setText("Error loading inventory data")
    
    def show_low_stock_report(self):
        """Show items with low stock levels."""
        try:
            conn = sqlite3.connect(self.inventory_database_file)
            cursor = conn.cursor()
            cursor.execute("""
                SELECT hcpcs_code, description, stock_quantity, reorder_level
                FROM inventory 
                WHERE stock_quantity <= reorder_level AND reorder_level > 0
                ORDER BY stock_quantity ASC
            """)
            low_stock_items = cursor.fetchall()
            conn.close()
            
            if not low_stock_items:
                QMessageBox.information(self, "Low Stock Report", "No items are currently at or below reorder level.")
                return
            
            # Create dialog to show low stock items
            dialog = QDialog(self)
            dialog.setWindowTitle("⚠️ Low Stock Report")
            dialog.resize(600, 400)
            
            layout = QVBoxLayout(dialog)
            
            header = QLabel(f"Found {len(low_stock_items)} items at or below reorder level:")
            header.setStyleSheet("font-weight: bold; font-size: 14px; color: #e74c3c;")
            layout.addWidget(header)
            
            table = QTableWidget()
            table.setColumnCount(4)
            table.setHorizontalHeaderLabels(["HCPCS Code", "Description", "Current Stock", "Reorder Level"])
            table.setRowCount(len(low_stock_items))
            
            for row, item in enumerate(low_stock_items):
                for col, value in enumerate(item):
                    table.setItem(row, col, QTableWidgetItem(str(value)))
            
            # Color code low stock rows
            for row in range(len(low_stock_items)):
                for col in range(4):
                    item = table.item(row, col)
                    if item:
                        item.setBackground(QColor(255, 235, 235))  # Light red background
            
            layout.addWidget(table)
            
            close_btn = QPushButton("Close")
            close_btn.clicked.connect(dialog.accept)
            layout.addWidget(close_btn)
            
            dialog.exec()
            
        except Exception as e:
            QMessageBox.critical(self, "Error", f"Failed to generate low stock report: {e}")
    
