    def open_reports_dashboard_standalone(self):
        """Launch the standalone Reports & Analytics dashboard (Tkinter) in a separate process.

        We use a subprocess to avoid mixing Qt and Tk event loops in the same process.
        """
        try:
            script_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "reports_dashboard.py")
            if not os.path.exists(script_path):
                QMessageBox.warning(self, "Reports & Analytics", "reports_dashboard.py was not found in the application folder.")
                return
            python = sys.executable or "python"
            subprocess.Popen([python, script_path])
        except Exception as e:
            QMessageBox.critical(self, "Reports & Analytics", f"Failed to launch dashboard:\n{e}")

    

