    def export_report_pdf(self):
        """Export the current report to PDF.

        If structured data (headers/rows) is present, render a real table and append summary.
        Otherwise, export the text preview.
        """
        try:
            from reportlab.lib.pagesizes import letter, landscape
            from reportlab.lib.units import inch
            from reportlab.lib import colors
            from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            import os, re, datetime

            # Save to user's Downloads folder with a timestamped filename
            downloads = os.path.join(os.path.expanduser("~"), "Downloads")
            try:
                os.makedirs(downloads, exist_ok=True)
            except Exception:
                # Fallback to current folder if Downloads is not available
                downloads = self.folder_path

            title = getattr(self, 'current_report_title', 'Report')
            safe_title = re.sub(r"[^A-Za-z0-9_-]+", "_", title).strip("_") or "Report"
            ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            file_path = os.path.join(downloads, f"{safe_title}_{ts}.pdf")

            doc = SimpleDocTemplate(file_path, pagesize=landscape(letter), leftMargin=0.5*inch, rightMargin=0.5*inch, topMargin=0.6*inch, bottomMargin=0.6*inch)
            styles = getSampleStyleSheet()
            story = []

            # Title
            title = getattr(self, 'current_report_title', 'Report')
            title_style = ParagraphStyle('title', parent=styles['Heading2'], alignment=1)
            story.append(Paragraph(title, title_style))
            story.append(Spacer(1, 6))

            headers = getattr(self, 'current_report_headers', None)
            rows = getattr(self, 'current_report_rows', None)
            summary_lines = getattr(self, 'current_report_summary_lines', None)

            if headers and rows is not None:
                data = [headers] + rows
                table = Table(data, repeatRows=1)
                table.setStyle(TableStyle([
                    ('FONTNAME', (0,0), (-1,0), 'Helvetica-Bold'),
                    ('FONTSIZE', (0,0), (-1,0), 9),
                    ('BACKGROUND', (0,0), (-1,0), colors.lightgrey),
                    ('ALIGN', (0,0), (-1,-1), 'LEFT'),
                    ('FONTSIZE', (0,1), (-1,-1), 8),
                    ('GRID', (0,0), (-1,-1), 0.25, colors.grey),
                    ('VALIGN', (0,0), (-1,-1), 'TOP'),
                ]))
                story.append(table)
            else:
                # Fallback: export the text block
                text = self.reports_text.toPlainText().strip()
                if not text:
                    QMessageBox.information(self, "Export PDF", "No report content to export.")
                    return
                for line in text.split("\n"):
                    story.append(Paragraph(line.replace('  ', '&nbsp;&nbsp;'), styles['Normal']))
                    story.append(Spacer(1, 4))

            # Append summary if available
            if summary_lines:
                story.append(Spacer(1, 12))
                story.append(Paragraph("Summary", styles['Heading4']))
                for l in summary_lines:
                    story.append(Paragraph(l.replace('  ', '&nbsp;&nbsp;'), styles['Normal']))
                    story.append(Spacer(1, 2))

            doc.build(story)

            try:
                os.startfile(file_path)
            except Exception:
                pass
            QMessageBox.information(self, "Export PDF", f"Saved to: {file_path}")
        except Exception as e:
            QMessageBox.critical(self, "Export PDF", f"Failed to export PDF: {e}")
    
    def export_report_excel(self):
        """Export current report as a CSV file that opens in Excel.

        If a structured table (headers+rows) is available (e.g., Order Report), export exactly that.
        Otherwise, fall back to parsing the text preview heuristically.
        """
        try:
            import csv, os, re, datetime
            # Save to user's Downloads folder with a timestamped filename
            downloads = os.path.join(os.path.expanduser("~"), "Downloads")
            try:
                os.makedirs(downloads, exist_ok=True)
            except Exception:
                downloads = self.folder_path
            title = getattr(self, 'current_report_title', 'Report')
            safe_title = re.sub(r"[^A-Za-z0-9_-]+", "_", title).strip("_") or "Report"
            ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            file_path = os.path.join(downloads, f"{safe_title}_{ts}.csv")

            # Prefer structured export if available
            if getattr(self, 'current_report_headers', None) and getattr(self, 'current_report_rows', None):
                with open(file_path, 'w', newline='', encoding='utf-8') as f:
                    writer = csv.writer(f)
                    writer.writerow(self.current_report_headers)
                    for row in self.current_report_rows:
                        writer.writerow(row)
                    # If we have a summary, append it after a couple of blank lines
                    if getattr(self, 'current_report_summary_lines', None):
                        writer.writerow([])
                        writer.writerow([])
                        for line in self.current_report_summary_lines:
                            writer.writerow([line])
                try:
                    os.startfile(file_path)
                except Exception:
                    pass
                QMessageBox.information(self, "Export CSV", f"Saved to: {file_path}")
                return

            # Fallback: export text
            text = self.reports_text.toPlainText().strip()
            if not text:
                QMessageBox.information(self, "Export CSV", "No report content to export.")
                return
            with open(file_path, 'w', newline='', encoding='utf-8') as f:
                writer = csv.writer(f)
                for line in text.split("\n"):
                    if line.strip().startswith("•") or line.strip().startswith("-"):
                        cleaned = line.strip().lstrip("•-").strip()
                        if ":" in cleaned:
                            parts = [p.strip() for p in cleaned.split(":", 1)]
                            writer.writerow(parts)
                        else:
                            writer.writerow([cleaned])
                    elif " | " in line:
                        writer.writerow([p.strip() for p in line.split("|")])
                    elif ":" in line:
                        parts = [p.strip() for p in line.split(":", 1)]
                        writer.writerow(parts)
                    else:
                        writer.writerow([line])
            try:
                os.startfile(file_path)
            except Exception:
                pass
            QMessageBox.information(self, "Export CSV", f"Saved to: {file_path}")
        except Exception as e:
            QMessageBox.critical(self, "Export CSV", f"Failed to export CSV: {e}")

    def choose_db_folder(self):
        """Prompt for a database folder and connect known DBs from there."""
        try:
            base = self.settings.get('db_folder') if isinstance(getattr(self, 'settings', {}), dict) else self.folder_path
        except Exception:
            base = self.folder_path
        dir_path = QFileDialog.getExistingDirectory(self, "Select Database Folder", base or self.folder_path)
        if not dir_path:
            return

        found = {}
        def check(name):
            p = os.path.join(dir_path, name)
            return p if os.path.exists(p) else None

        # Probe each db
        patients = check('patients.db')
        orders = check('orders.db')
        inventory = check('inventory.db')
        billing = check('billing.db')
        prescribers = check('prescribers.db')
        insurance = check('insurance_names.db') or check('insurance.db')
        document_db = check('document_data.db')

        # Apply if found
        if patients: self.patient_database_file = patients
        if orders:
            self.orders_database_file = orders
            self.orders_db_path = orders
        if inventory: self.inventory_database_file = inventory
        if billing: self.billing_database_file = billing
        if prescribers: self.prescriber_database_file = prescribers
        if insurance: self.insurance_database_file = insurance
        if document_db: self.database_file = document_db

        # Persist selection
        try:
            if isinstance(self.settings, dict):
                self.settings['db_folder'] = dir_path
                self.save_settings()
        except Exception:
            pass

        # Feedback
        lines = ["Database connections updated:"]
        for label, path in [
            ("Patients", getattr(self, 'patient_database_file', None)),
            ("Orders", getattr(self, 'orders_database_file', None)),
            ("Inventory", getattr(self, 'inventory_database_file', None)),
            ("Billing", getattr(self, 'billing_database_file', None)),
            ("Prescribers", getattr(self, 'prescriber_database_file', None)),
            ("Insurance", getattr(self, 'insurance_database_file', None)),
            ("Documents Index", getattr(self, 'database_file', None)),
        ]:
            exists = os.path.exists(path) if path else False
            size = os.path.getsize(path) if exists else 0
            lines.append(f"• {label}: {'OK' if exists else 'Missing'} — {path if path else ''} ({size} bytes)")
        QMessageBox.information(self, "Databases", "\n".join(lines))

        # Optionally refresh current report visuals (no-op if none loaded yet)
        if hasattr(self, 'update_reports_visuals'):
            self.update_reports_visuals()

    def move_databases_to_folder(self):
        """Let the user pick a target folder and move all known DB files into it.

        - Copies data safely (creates the folder if missing)
        - If a target file exists, it is backed up with a timestamp before being overwritten
        - Updates in-memory paths and saves settings['db_folder']
        """
        try:
            base = None
            try:
                if isinstance(self.settings, dict):
                    base = self.settings.get('db_folder') or self.folder_path
            except Exception:
                base = self.folder_path
            target_dir = QFileDialog.getExistingDirectory(self, "Select Target Folder for Databases", base or self.folder_path)
            if not target_dir:
                return

            os.makedirs(target_dir, exist_ok=True)

            # Collect current db paths
            items = [
                ("Patients", getattr(self, 'patient_database_file', None), 'patients.db'),
                ("Orders", getattr(self, 'orders_database_file', None), 'orders.db'),
                ("Inventory", getattr(self, 'inventory_database_file', None), 'inventory.db'),
                ("Billing", getattr(self, 'billing_database_file', None), 'billing.db'),
                ("Prescribers", getattr(self, 'prescriber_database_file', None), 'prescribers.db'),
                ("Insurance", getattr(self, 'insurance_database_file', None), 'insurance_names.db'),
            ]

            # Ask/include document index based on preference
            try:
                pref = None
                try:
                    if isinstance(self.settings, dict):
                        pref = self.settings.get('doc_index_move_pref', 'ask')  # 'ask' | 'always' | 'never'
                except Exception:
                    pref = 'ask'

                include_doc_index = False
                if pref == 'always':
                    include_doc_index = True
                elif pref == 'never':
                    include_doc_index = False
                else:
                    # Ask the user this time
                    reply = QMessageBox.question(
                        self,
                        "Move Document Index?",
                        (
                            "Also move the folder document index database (document_data.db) to the target?\n\n"
                            "Recommended: Keep it per-folder if you use multiple fax folders."
                        ),
                        QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                        QMessageBox.StandardButton.No,
                    )
                    include_doc_index = reply == QMessageBox.StandardButton.Yes

                    # Optional: remember this choice
                    remember = QMessageBox.question(
                        self,
                        "Remember Choice?",
                        "Remember this choice for future moves?",
                        QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No,
                        QMessageBox.StandardButton.No,
                    )
                    if remember == QMessageBox.StandardButton.Yes and isinstance(self.settings, dict):
                        self.settings['doc_index_move_pref'] = 'always' if include_doc_index else 'never'
                        try:
                            self.save_settings()
                        except Exception:
                            pass

                if include_doc_index:
                    items.append(("Documents Index", getattr(self, 'database_file', None), 'document_data.db'))
            except Exception:
                pass

            from datetime import datetime
            ts = datetime.now().strftime('%Y%m%d_%H%M%S')
            report_lines = [f"Moving databases to: {target_dir}"]
            moved_any = False

            for label, src, fname in items:
                try:
                    if not src or not os.path.exists(src):
                        report_lines.append(f"• {label}: Source missing — skipping")
                        continue
                    dest = os.path.join(target_dir, fname)
                    # Backup existing dest if present
                    if os.path.exists(dest):
                        backup = dest + f".bak_{ts}"
                        shutil.copy2(dest, backup)
                    # Move (handle cross-device by shutil.move)
                    if os.path.abspath(src) != os.path.abspath(dest):
                        shutil.move(src, dest)
                        moved_any = True
                    # Update in-memory pointers
                    if label == "Patients":
                        self.patient_database_file = dest
                    elif label == "Orders":
                        self.orders_database_file = dest
                        self.orders_db_path = dest
                    elif label == "Inventory":
                        self.inventory_database_file = dest
                    elif label == "Billing":
                        self.billing_database_file = dest
                    elif label == "Prescribers":
                        self.prescriber_database_file = dest
                    elif label == "Insurance":
                        self.insurance_database_file = dest
                    elif label == "Documents Index":
                        self.database_file = dest
                    report_lines.append(f"• {label}: moved → {dest}")
                except Exception as e:
                    report_lines.append(f"• {label}: FAILED — {e}")

            # Persist selection
            try:
                if isinstance(self.settings, dict):
                    self.settings['db_folder'] = target_dir
                    self.save_settings()
            except Exception:
                pass

            # Feedback
            QMessageBox.information(self, "Move Databases", "\n".join(report_lines))

            # Refresh visuals if open
            if moved_any and hasattr(self, 'update_reports_visuals'):
                self.update_reports_visuals()
        except Exception as e:
            QMessageBox.critical(self, "Move Databases", f"Failed to move databases: {e}")

    def update_reports_visuals(self, report_type: str = ""):
        """Populate the embedded Reports dashboard widgets (KPI cards, chart, table).

        Inputs:
        - report_type: one of "orders", "reconciliation", "inventory", "billing", "patients" (best-effort parsing if unknown)

        Data sources:
        - Preferred: self.current_report_headers, self.current_report_rows, self.current_report_summary_lines
        - Fallback: parse key numbers out of self.reports_text (plain text)
        """
        try:
            # Table population
            headers = getattr(self, 'current_report_headers', None)
            rows = getattr(self, 'current_report_rows', None)
            if hasattr(self, 'reports_table') and self.reports_table is not None:
                if headers and rows is not None:
                    self.reports_table.clear()
                    self.reports_table.setColumnCount(len(headers))
                    self.reports_table.setHorizontalHeaderLabels(headers)
                    self.reports_table.setRowCount(len(rows))
                    for r, row in enumerate(rows):
                        for c, val in enumerate(row):
                            self.reports_table.setItem(r, c, QTableWidgetItem(str(val)))
                    self.reports_table.resizeColumnsToContents()
                else:
                    # If no structured rows, clear table
                    self.reports_table.clear()
                    self.reports_table.setRowCount(0)
                    self.reports_table.setColumnCount(0)

            # KPI defaults
            def set_kpis(labels_vals):
                # Ensure exactly 4 KPI slots
                display = list(labels_vals)[:4]
                while len(display) < 4:
                    display.append(("", "-"))
                for i, (label, val) in enumerate(display):
                    # Update card title and big value
                    if i < len(self.kpi_titles):
                        self.kpi_titles[i].setText(str(label))
                    if i < len(self.kpi_values):
                        self.kpi_values[i].setText(str(val))

            # Chart helper
            def draw_bar(labels, values, title=""):
                if getattr(self, 'reports_ax', None) is None or getattr(self, 'reports_canvas', None) is None:
                    return
                ax = self.reports_ax
                ax.clear()
                ax.bar(labels, values, color="#2e7d32")
                ax.set_title(title)
                ax.set_ylabel("")
                ax.set_xlabel("")
                ax.grid(axis='y', linestyle=':', alpha=0.5)
                for i, v in enumerate(values):
                    try:
                        ax.text(i, v, f"{v}", ha='center', va='bottom', fontsize=8)
                    except Exception:
                        pass
                self.reports_canvas.draw_idle()

            text_block = self.reports_text.toPlainText() if hasattr(self, 'reports_text') and self.reports_text is not None else ""
            summary_lines = getattr(self, 'current_report_summary_lines', None)

            import re

            if report_type == "orders":
                # KPIs: Orders in range, by top statuses
                total = len(rows) if rows is not None else 0
                # Status is last column if available
                status_counts = {}
                if rows is not None and len(rows) > 0:
                    for r in rows:
                        s = str(r[-1]) if r else ""
                        status_counts[s] = status_counts.get(s, 0) + 1
                # Prepare KPIs
                top = sorted(status_counts.items(), key=lambda kv: kv[1], reverse=True)[:3]
                kpis = [("Orders in range", total)] + [(lbl or "", cnt) for lbl, cnt in top]
                set_kpis(kpis)
                # Chart
                if status_counts:
                    labels = [k or "" for k, _ in status_counts.items()]
                    values = [v for _, v in status_counts.items()]
                    draw_bar(labels, values, title="Orders by Status")
                else:
                    draw_bar(["Orders"], [total], title="Orders in Range")

            elif report_type == "reconciliation":
                # Parse summary for billed/unbilled & paid/unpaid counts and revenue
                billed_cnt = unpaid_cnt = paid_cnt = unbilled_cnt = 0
                billed_rev = unbilled_rev = paid_rev = unpaid_rev = 0.0
                total_orders = len(rows) if rows is not None else 0
                if summary_lines:
                    for line in summary_lines:
                        m = re.search(r"Billed Orders: (\d+)", line)
                        if m: billed_cnt = int(m.group(1))
                        m = re.search(r"Unbilled Orders: (\d+)", line)
                        if m: unbilled_cnt = int(m.group(1))
                        m = re.search(r"Paid Orders: (\d+)", line)
                        if m: paid_cnt = int(m.group(1))
                        m = re.search(r"Unpaid Orders: (\d+)", line)
                        if m: unpaid_cnt = int(m.group(1))
                        m = re.search(r"Billed Revenue: \$(.+)", line)
                        if m:
                            billed_rev = float(m.group(1).replace(',', ''))
                        m = re.search(r"Unbilled Revenue: \$(.+)", line)
                        if m:
                            unbilled_rev = float(m.group(1).replace(',', ''))
                        m = re.search(r"Paid Revenue: \$(.+)", line)
                        if m:
                            paid_rev = float(m.group(1).replace(',', ''))
                        m = re.search(r"Unpaid Revenue: \$(.+)", line)
                        if m:
                            unpaid_rev = float(m.group(1).replace(',', ''))
                set_kpis([
                    ("Total Orders", total_orders),
                    ("Billed", billed_cnt),
                    ("Paid", paid_cnt),
                    ("Unpaid", unpaid_cnt),
                ])
                draw_bar(["Billed", "Unbilled", "Paid", "Unpaid"], [billed_cnt, unbilled_cnt, paid_cnt, unpaid_cnt], title="Orders Status")

            elif report_type == "inventory":
                # From text: Unique SKUs, Total units on hand, Items at/below reorder, Most Critical Stock lines
                total_items = re.search(r"Unique SKUs: (\d+)", text_block)
                total_stock = re.search(r"Total units on hand: (\d+)", text_block)
                low_items = re.search(r"Items at/below reorder: (\d+)", text_block)
                total_items = int(total_items.group(1)) if total_items else 0
                total_stock = int(total_stock.group(1)) if total_stock else 0
                low_items = int(low_items.group(1)) if low_items else 0
                set_kpis([
                    ("Unique SKUs", total_items),
                    ("Units on Hand", total_stock),
                    ("At/Below Reorder", low_items),
                    ("Items Listed", self.reports_table.rowCount() if hasattr(self, 'reports_table') else 0),
                ])
                draw_bar(["SKUs", "Units", "Reorder"], [total_items, total_stock, low_items], title="Inventory Snapshot")

            elif report_type == "billing":
                claims = re.search(r"Total claims: (\d+)", text_block)
                billed = re.search(r"Total billed: \$(.+)", text_block)
                paid = re.search(r"Total paid: \$(.+)", text_block)
                outstanding = re.search(r"Outstanding: \$(.+)", text_block)
                claims = int(claims.group(1)) if claims else 0
                billed_amt = float(billed.group(1).replace(',', '')) if billed else 0.0
                paid_amt = float(paid.group(1).replace(',', '')) if paid else 0.0
                out_amt = float(outstanding.group(1).replace(',', '')) if outstanding else max(0.0, billed_amt - paid_amt)
                set_kpis([
                    ("Claims", claims),
                    ("Billed $", f"${billed_amt:,.0f}"),
                    ("Paid $", f"${paid_amt:,.0f}"),
                    ("Outstanding $", f"${out_amt:,.0f}"),
                ])
                draw_bar(["Billed", "Paid", "Outstanding"], [billed_amt, paid_amt, out_amt], title="Billing")

            elif report_type == "patients":
                total_patients = re.search(r"Total patients: (\d+)", text_block)
                new_in_range = re.search(r"New patients in range: (\d+)", text_block)
                total_patients = int(total_patients.group(1)) if total_patients else 0
                new_in_range = int(new_in_range.group(1)) if new_in_range else 0
                set_kpis([
                    ("Total Patients", total_patients),
                    ("New in Range", new_in_range),
                    ("", "-"),
                    ("", "-"),
                ])
                draw_bar(["Total", "New"], [total_patients, new_in_range], title="Patients")
            else:
                # Unknown type: try to show a simple count if rows exist
                count = len(rows) if rows is not None else 0
                set_kpis([("Rows", count), ("", "-"), ("", "-"), ("", "-")])
                draw_bar(["Rows"], [count], title="Report")
        except Exception as e:
            # Non-fatal; keep UI usable
            try:
                print(f"update_reports_visuals failed: {e}")
            except Exception:
                pass

    def load_file_list(self):
        """Scans the folder and populates the file list with PDFs only."""
        self.file_list_widget.clear()
        # Clear any search highlighting when file list is refreshed
        if hasattr(self, 'search_results_table') or hasattr(self, 'search_results_list'):
            self.clear_file_highlighting()
        
        # Clear filename cache when folder changes
        if hasattr(self, 'filename_cache'):
            self.filename_cache.clear()
        
        try:
            pdf_files = []
            for filename in os.listdir(self.folder_path):
                if filename.lower().endswith(".pdf"):
                    pdf_files.append(filename)
            
            # Sort based on current sort mode
            sort_mode = getattr(self, '_file_sort_mode', 'date')
            if sort_mode == 'name':
                pdf_files.sort(key=str.lower)
            else:
                pdf_files.sort(key=lambda f: os.path.getctime(os.path.join(self.folder_path, f)), reverse=True)
            
            # Build link cache to show indicators
            link_cache = self._build_file_link_cache()
            
            for filename in pdf_files:
                item = QListWidgetItem(filename)
                item.setData(Qt.ItemDataRole.UserRole, filename)
                icon = self._file_link_icon(filename, link_cache)
                if icon:
                    item.setIcon(icon)
                self.file_list_widget.addItem(item)
            
            # Refresh filter dropdowns with new file data
            if hasattr(self, 'fax_filter_combo'):
                self.populate_fax_filter()
                
            # Update status
            count = len(pdf_files)
            self.statusBar().showMessage(f"Found {count} PDF file{'s' if count != 1 else ''} in {os.path.basename(self.folder_path)}")
            if hasattr(self, 'left_status_label'):
                self.left_status_label.setText(f"Ready • {count} files indexed")
            
        except FileNotFoundError:
            self.pdf_label.setText(f"Error: Folder not found.\n{self.folder_path}")
            self.statusBar().showMessage("Folder not found")
        except PermissionError:
            self.pdf_label.setText(f"Error: No permission to access folder.\n{self.folder_path}")
            self.statusBar().showMessage("Permission denied")

    def on_file_selected(self, current_item, previous_item):
        """Handles file selection changes, including autosaving."""
        try:
            # Auto-save data for the previously selected file
            if previous_item is not None:
                prev_filename = self._get_file_item_name(previous_item)
                try:
                    self.save_data(prev_filename)
                    print(f"Auto-saved when switching from: {prev_filename}")
                except Exception:
                    pass

            # DON'T clear - load data from database to keep tags attached to files
            # Load data FIRST before displaying PDF
            if current_item is not None:
                self.current_file = self._get_file_item_name(current_item)
                try:
                    self.load_data(self.current_file)  # Load tags first
                except Exception:
                    pass
                try:
                    self.display_pdf(self.current_file)  # Then display PDF
                except Exception as e:
                    try:
                        self.statusBar().showMessage(f"Error loading {self.current_file}: {e}", 5000)
                    except Exception:
                        pass
                    self._reset_pdf_viewer_state("Error loading file. Select another document.")
                    return
                
            # Reapply highlighting to maintain persistent highlighting
            self.reapply_highlighting()
        except Exception as e:
            try:
                name = self._get_file_item_name(current_item) if current_item else "(none)"
                self.statusBar().showMessage(f"Error opening {name}: {e}", 5000)
            except Exception:
                pass
            self._reset_pdf_viewer_state("Error loading file. Select another document.")

    def prev_page(self):
        """Go to previous page."""
        if self.doc and self.current_page_num > 0:
            self.current_page_num -= 1
            self.render_page()

    def next_page(self):
        """Go to next page."""
        if self.doc and self.current_page_num < len(self.doc) - 1:
            self.current_page_num += 1
            self.render_page()

    def fit_width(self):
        """Fit the document width to the scroll area width."""
        if self.doc:
            # Get scroll area width (minus scrollbar space)
            available_width = self.scroll_area.viewport().width() - 20
            
            # Get page dimensions
            page = self.doc.load_page(self.current_page_num)
            page_rect = page.rect
            
            # Calculate zoom level to fit width
            self.zoom_level = available_width / page_rect.width
            self.render_page()

    def load_data(self, filename):
        """Loads data from the database into the input fields."""
        # Clean filename - remove star prefix if present
        clean_filename = filename
        if clean_filename.startswith("★ "):
            clean_filename = clean_filename[2:]
            
        conn = sqlite3.connect(self.database_file)
        cursor = conn.cursor()
        
        # Check if phone column exists
        cursor.execute("PRAGMA table_info(documents)")
        columns = [col[1] for col in cursor.fetchall()]
        has_phone = 'phone' in columns
        
        if has_phone:
            cursor.execute("SELECT first_name, last_name, dob, phone, notes FROM documents WHERE filename=?", (clean_filename,))
        else:
            cursor.execute("SELECT first_name, last_name, dob, notes FROM documents WHERE filename=?", (clean_filename,))
        
        row = cursor.fetchone()
        if row:
            if has_phone:
                if hasattr(self, 'first_name_input'): self.first_name_input.setText(row[0] or "")
                if hasattr(self, 'last_name_input'): self.last_name_input.setText(row[1] or "")
                if hasattr(self, 'dob_input'): self.dob_input.setText(row[2] or "")
                if hasattr(self, 'phone_input'): self.phone_input.setText(row[3] or "")
                if hasattr(self, 'notes_history'): self.notes_history.setText(row[4] or "")
            else:
                if hasattr(self, 'first_name_input'): self.first_name_input.setText(row[0] or "")
                if hasattr(self, 'last_name_input'): self.last_name_input.setText(row[1] or "")
                if hasattr(self, 'dob_input'): self.dob_input.setText(row[2] or "")
                if hasattr(self, 'phone_input'): self.phone_input.clear()
                if hasattr(self, 'notes_history'): self.notes_history.setText(row[3] or "")
        conn.close()

    def save_data(self, filename):
        """Saves the current data from the fields into the database."""
        if not filename:
            return
            
        # Clean filename - remove star prefix if present
        clean_filename = filename
        if clean_filename.startswith("★ "):
            clean_filename = clean_filename[2:]
            
        try:
            conn = sqlite3.connect(self.database_file)
            cursor = conn.cursor()
            
            # Check if phone column exists, add it if not
            cursor.execute("PRAGMA table_info(documents)")
            columns = [col[1] for col in cursor.fetchall()]
            if 'phone' not in columns:
                cursor.execute("ALTER TABLE documents ADD COLUMN phone TEXT DEFAULT ''")
            
            phone = self.phone_input.text() if hasattr(self, 'phone_input') else ''
            
            cursor.execute("""
            INSERT OR REPLACE INTO documents (filename, first_name, last_name, dob, phone, notes)
            VALUES (?, ?, ?, ?, ?, ?)
            """, (clean_filename, 
                  self.first_name_input.text().strip() if hasattr(self, 'first_name_input') else '',
                  self.last_name_input.text().strip() if hasattr(self, 'last_name_input') else '',
                  self.dob_input.text().strip() if hasattr(self, 'dob_input') else '',
                  phone,
                  self.notes_history.toPlainText() if hasattr(self, 'notes_history') else ''))
            conn.commit()
            conn.close()
            print(f"Auto-saved data for: {filename}")  # Debug message
        except Exception as e:
            print(f"Error saving data for {filename}: {e}")
            QMessageBox.warning(self, "Save Error", f"Could not save data for {filename}:\n{e}")

    def add_note(self):
        """Adds a new timestamped note to the notes history."""
        if not hasattr(self, 'new_note_input') or not hasattr(self, 'notes_history'):
            return
        new_note_text = self.new_note_input.text().strip()
        if new_note_text:
            # Standardize timestamp display format
            timestamp = datetime.now().strftime("%m/%d/%Y %H:%M:%S")
            full_note = f"[{timestamp}] {new_note_text}"
            
            current_history = self.notes_history.toPlainText()
            if current_history:
                self.notes_history.setText(current_history + "\n" + full_note)
            else:
                self.notes_history.setText(full_note)
            self.new_note_input.clear()
            
            # Auto-save immediately after adding note
            if self.current_file:
                self.save_data(self.current_file)
                self.statusBar().showMessage(f"Note added and saved for {self.current_file}")
    
    def closeEvent(self, event):
        """Handle main window close - clean up resources."""
        try:
            # Stop message notifier
            if hasattr(self, '_message_notifier') and self._message_notifier:
                self._message_notifier.stop()
            
            # Stop OCR watcher
            if hasattr(self, 'ocr_stop_event') and self.ocr_stop_event:
                self.ocr_stop_event.set()
            
            # Stop auto-refresh timer
            if hasattr(self, 'auto_refresh_timer'):
                self.auto_refresh_timer.stop()
            
            # Save settings
            if hasattr(self, 'settings'):
                self.save_settings(self.settings)
                
        except Exception as e:
            print(f"Error in closeEvent: {e}")
        
        super().closeEvent(event)

