try:
    if not hasattr(PDFViewer, "update_order_status"):
        def _patched_update_order_status(self):
            return self._update_order_status_impl()
        PDFViewer.update_order_status = _patched_update_order_status

    if not hasattr(PDFViewer, "check_scheduled_holds"):
        def _patched_check_scheduled_holds(self):
            try:
                from PyQt6.QtWidgets import QMessageBox
                from dmelogic.db.orders import get_due_hold_orders, clear_order_hold
                from dmelogic.db.order_workflow import update_order_status_validated
            except Exception as e:
                print(f"check_scheduled_holds import error: {e}")
                return

            folder_path = getattr(self, "folder_path", None)
            try:
                due_orders = get_due_hold_orders(folder_path=folder_path)
            except Exception as e:
                print(f"check_scheduled_holds query error: {e}")
                return

            if not due_orders:
                return

            released = []
            failures = []
            for order in due_orders:
                resume_status = order.get("hold_resume_status") or "Pending"
                success, error_msg = update_order_status_validated(
                    order_id=order["id"],
                    current_status="On Hold",
                    new_status=resume_status,
                    folder_path=folder_path,
                )

                order_label = self.format_order_number(order["id"]) if hasattr(self, "format_order_number") else f"ORD-{order['id']:03d}"
                patient_label = f"{order.get('patient_last_name', '')}, {order.get('patient_first_name', '')}".strip(", ") or "Unknown patient"

                if success:
                    try:
                        clear_order_hold(order["id"], folder_path=folder_path, mark_reminder_sent=True)
                    except Exception:
                        pass
                    released.append(f"{order_label} → {resume_status} ({patient_label})")
                else:
                    failures.append(f"{order_label}: {error_msg or 'Could not change status'}")

            if released:
                QMessageBox.information(
                    self,
                    "Hold Releases",
                    "\n".join(released),
                )
                try:
                    self.load_orders()
                except Exception:
                    pass

            if failures:
                QMessageBox.warning(
                    self,
                    "Hold Release Issues",
                    "\n".join(failures) + "\n\nUpdate these orders manually.",
                )

        PDFViewer.check_scheduled_holds = _patched_check_scheduled_holds
except Exception as _patch_err:
    print(f"PDFViewer patch failed: {_patch_err}")

